CREATE OR REPLACE FUNCTION "public"."activate_subscription"("p_auth_user_id" "uuid", "p_plan_code" "text", "p_billing_cycle" "text" DEFAULT 'monthly'::"text", "p_razorpay_payment_id" "text" DEFAULT NULL::"text", "p_razorpay_order_id" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_student_id UUID;
  v_plan_id UUID;
  v_period_end TIMESTAMPTZ;
BEGIN
  -- Get student ID
  SELECT id INTO v_student_id FROM students WHERE auth_user_id = p_auth_user_id LIMIT 1;
  IF v_student_id IS NULL THEN
    RAISE EXCEPTION 'Student not found for auth_user_id %', p_auth_user_id;
  END IF;

  -- Get plan ID
  SELECT id INTO v_plan_id FROM subscription_plans WHERE plan_code = p_plan_code LIMIT 1;
  IF v_plan_id IS NULL THEN
    RAISE EXCEPTION 'Plan not found: %', p_plan_code;
  END IF;

  -- Calculate period end
  v_period_end := CASE 
    WHEN p_billing_cycle = 'yearly' THEN NOW() + INTERVAL '1 year'
    ELSE NOW() + INTERVAL '1 month'
  END;

  -- Upsert subscription record
  INSERT INTO student_subscriptions (
    student_id, plan_id, plan_code, status, billing_cycle,
    current_period_start, current_period_end,
    razorpay_payment_id, auto_renew
  ) VALUES (
    v_student_id, v_plan_id, p_plan_code, 'active', p_billing_cycle,
    NOW(), v_period_end,
    p_razorpay_payment_id, true
  )
  ON CONFLICT (student_id) DO UPDATE SET
    plan_id = v_plan_id,
    plan_code = p_plan_code,
    status = 'active',
    billing_cycle = p_billing_cycle,
    current_period_start = NOW(),
    current_period_end = v_period_end,
    razorpay_payment_id = COALESCE(p_razorpay_payment_id, student_subscriptions.razorpay_payment_id),
    auto_renew = true,
    cancelled_at = NULL,
    cancel_reason = NULL,
    updated_at = NOW();

  -- Also update the students table subscription_plan field
  UPDATE students SET subscription_plan = p_plan_code WHERE id = v_student_id;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."activate_subscription"("p_auth_user_id" "uuid", "p_plan_code" "text", "p_billing_cycle" "text" DEFAULT 'monthly'::"text", "p_razorpay_payment_id" "text" DEFAULT NULL::"text", "p_razorpay_order_id" "text" DEFAULT NULL::"text", "p_razorpay_subscription_id" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_student_id UUID; v_plan_id UUID;
  v_period_end TIMESTAMPTZ; v_next_billing TIMESTAMPTZ;
BEGIN
  SELECT id INTO v_student_id FROM students WHERE auth_user_id = p_auth_user_id LIMIT 1;
  IF v_student_id IS NULL THEN RAISE EXCEPTION 'Student not found for auth_user_id %', p_auth_user_id; END IF;

  SELECT id INTO v_plan_id FROM subscription_plans WHERE plan_code = p_plan_code LIMIT 1;
  IF v_plan_id IS NULL THEN RAISE EXCEPTION 'Plan not found: %', p_plan_code; END IF;

  v_period_end := CASE WHEN p_billing_cycle = 'yearly' THEN NOW() + INTERVAL '1 year' ELSE NOW() + INTERVAL '1 month' END;
  v_next_billing := CASE
    WHEN p_razorpay_subscription_id IS NOT NULL AND p_billing_cycle = 'monthly' THEN NOW() + INTERVAL '1 month'
    ELSE NULL
  END;

  INSERT INTO student_subscriptions (
    student_id, plan_id, plan_code, status, billing_cycle,
    current_period_start, current_period_end, next_billing_at,
    razorpay_payment_id, razorpay_subscription_id,
    auto_renew, renewal_attempts, grace_period_end, ended_at
  ) VALUES (
    v_student_id, v_plan_id, p_plan_code, 'active', p_billing_cycle,
    NOW(), v_period_end, v_next_billing,
    p_razorpay_payment_id, p_razorpay_subscription_id,
    CASE WHEN p_razorpay_subscription_id IS NOT NULL THEN true ELSE false END,
    0, NULL, NULL
  )
  ON CONFLICT (student_id) DO UPDATE SET
    plan_id = v_plan_id, plan_code = p_plan_code, status = 'active',
    billing_cycle = p_billing_cycle,
    current_period_start = NOW(), current_period_end = v_period_end,
    next_billing_at = v_next_billing,
    razorpay_payment_id = COALESCE(p_razorpay_payment_id, student_subscriptions.razorpay_payment_id),
    razorpay_subscription_id = COALESCE(p_razorpay_subscription_id, student_subscriptions.razorpay_subscription_id),
    auto_renew = CASE WHEN p_razorpay_subscription_id IS NOT NULL THEN true ELSE false END,
    renewal_attempts = 0, grace_period_end = NULL, ended_at = NULL,
    cancelled_at = NULL, cancel_reason = NULL, updated_at = NOW();

  UPDATE students SET subscription_plan = p_plan_code WHERE id = v_student_id;
END; $$;


CREATE OR REPLACE FUNCTION "public"."activate_subscription_locked"("p_auth_user_id" "uuid", "p_plan_code" "text", "p_billing_cycle" "text" DEFAULT 'monthly'::"text", "p_razorpay_payment_id" "text" DEFAULT NULL::"text", "p_razorpay_order_id" "text" DEFAULT NULL::"text", "p_razorpay_subscription_id" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_student_id uuid;
BEGIN
  SELECT id INTO v_student_id FROM students WHERE auth_user_id = p_auth_user_id LIMIT 1;
  IF v_student_id IS NULL THEN
    RAISE EXCEPTION 'Student not found for auth_user_id %', p_auth_user_id;
  END IF;

  PERFORM pg_advisory_xact_lock(hashtextextended('subscription:' || v_student_id::text, 0));

  PERFORM activate_subscription(
    p_auth_user_id,
    p_plan_code,
    p_billing_cycle,
    p_razorpay_payment_id,
    p_razorpay_order_id,
    p_razorpay_subscription_id
  );
END;
$$;


CREATE OR REPLACE FUNCTION "public"."add_xp"("p_student_id" "uuid", "p_xp" integer, "p_source" "text" DEFAULT 'foxy_chat'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_subject text;
BEGIN
  -- Get the student's current preferred subject (or default to 'general')
  SELECT COALESCE(preferred_subject, 'math') INTO v_subject
  FROM students WHERE id = p_student_id;

  -- If source contains a subject hint, use it
  IF p_source LIKE '%math%' THEN v_subject := 'math';
  ELSIF p_source LIKE '%science%' THEN v_subject := 'science';
  ELSIF p_source LIKE '%english%' THEN v_subject := 'english';
  ELSIF p_source LIKE '%hindi%' THEN v_subject := 'hindi';
  ELSIF p_source LIKE '%physics%' THEN v_subject := 'physics';
  ELSIF p_source LIKE '%chemistry%' THEN v_subject := 'chemistry';
  ELSIF p_source LIKE '%biology%' THEN v_subject := 'biology';
  END IF;

  -- Upsert subject-specific XP in learning profile
  INSERT INTO student_learning_profiles (student_id, subject, xp, level)
  VALUES (p_student_id, v_subject, p_xp, 1)
  ON CONFLICT (student_id, subject) DO UPDATE
  SET xp = student_learning_profiles.xp + p_xp,
      level = GREATEST(1, (student_learning_profiles.xp + p_xp) / 500 + 1),
      last_session_at = now();

  -- Update global XP total in students table
  UPDATE students
  SET xp_total = COALESCE(xp_total, 0) + p_xp,
      last_active = now()
  WHERE id = p_student_id;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."admin_create_mapping"("p_admin_auth_id" "uuid", "p_guardian_id" "uuid", "p_student_id" "uuid", "p_notes" "text" DEFAULT 'Created by admin'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_link_id UUID;
  v_existing TEXT;
BEGIN
  -- Verify admin
  SELECT id INTO v_admin_id FROM admin_users
  WHERE auth_user_id = p_admin_auth_id AND is_active = true
  AND role IN ('super_admin', 'admin');
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized — admin only');
  END IF;
  
  -- Check existing active link
  SELECT status INTO v_existing FROM guardian_student_links
  WHERE guardian_id = p_guardian_id AND student_id = p_student_id
  AND status IN ('approved', 'pending');
  
  IF FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Active or pending link already exists (status: ' || v_existing || ')');
  END IF;
  
  INSERT INTO guardian_student_links (
    guardian_id, student_id, permission_level, status,
    is_verified, initiated_by, approved_by, approved_at
  ) VALUES (
    p_guardian_id, p_student_id, 'full', 'approved',
    true, p_admin_auth_id, p_admin_auth_id, now()
  )
  RETURNING id INTO v_link_id;
  
  INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
  VALUES (v_admin_id, 'admin_create_mapping', 'guardian_student_link', v_link_id::text,
    jsonb_build_object('guardian_id', p_guardian_id, 'student_id', p_student_id, 'notes', p_notes));
  
  RETURN jsonb_build_object('success', true, 'link_id', v_link_id, 'status', 'approved');
END;
$$;


CREATE OR REPLACE FUNCTION "public"."admin_override_mapping"("p_admin_auth_id" "uuid", "p_link_id" "uuid", "p_action" "text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_current_status TEXT;
BEGIN
  -- Verify admin
  SELECT id INTO v_admin_id FROM admin_users
  WHERE auth_user_id = p_admin_auth_id AND is_active = true
  AND role IN ('super_admin', 'admin');
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized — admin only');
  END IF;
  
  IF p_action NOT IN ('approved', 'rejected', 'revoked') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Action must be approved, rejected, or revoked');
  END IF;
  
  -- Get current status
  SELECT status INTO v_current_status FROM guardian_student_links WHERE id = p_link_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Link not found');
  END IF;
  
  -- Update
  UPDATE guardian_student_links
  SET status = p_action,
      is_verified = (p_action = 'approved'),
      approved_by = CASE WHEN p_action = 'approved' THEN p_admin_auth_id ELSE approved_by END,
      approved_at = CASE WHEN p_action = 'approved' THEN now() ELSE approved_at END,
      rejected_reason = CASE WHEN p_action = 'rejected' THEN COALESCE(p_notes, 'Rejected by admin') ELSE rejected_reason END,
      revoked_at = CASE WHEN p_action = 'revoked' THEN now() ELSE revoked_at END,
      revoked_by = CASE WHEN p_action = 'revoked' THEN p_admin_auth_id ELSE revoked_by END,
      updated_at = now()
  WHERE id = p_link_id;
  
  -- Audit
  INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
  VALUES (v_admin_id, 'admin_override_' || p_action, 'guardian_student_link', p_link_id::text,
    jsonb_build_object('previous_status', v_current_status, 'new_status', p_action, 'notes', p_notes));
  
  RETURN jsonb_build_object('success', true, 'status', p_action);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."admin_repair_user_onboarding"("p_auth_user_id" "uuid", "p_force_role" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_role TEXT;
  v_profile_id UUID;
  v_has_student BOOLEAN;
  v_has_teacher BOOLEAN;
  v_has_guardian BOOLEAN;
BEGIN
  SELECT EXISTS(SELECT 1 FROM students WHERE auth_user_id = p_auth_user_id) INTO v_has_student;
  SELECT EXISTS(SELECT 1 FROM teachers WHERE auth_user_id = p_auth_user_id) INTO v_has_teacher;
  SELECT EXISTS(SELECT 1 FROM guardians WHERE auth_user_id = p_auth_user_id) INTO v_has_guardian;

  v_role := COALESCE(p_force_role,
    CASE
      WHEN v_has_teacher THEN 'teacher'
      WHEN v_has_guardian THEN 'parent'
      WHEN v_has_student THEN 'student'
      ELSE 'student'
    END
  );

  IF v_role = 'student' AND v_has_student THEN
    SELECT id INTO v_profile_id FROM students WHERE auth_user_id = p_auth_user_id LIMIT 1;
  ELSIF v_role = 'teacher' AND v_has_teacher THEN
    SELECT id INTO v_profile_id FROM teachers WHERE auth_user_id = p_auth_user_id LIMIT 1;
  ELSIF v_role = 'parent' AND v_has_guardian THEN
    SELECT id INTO v_profile_id FROM guardians WHERE auth_user_id = p_auth_user_id LIMIT 1;
  END IF;

  INSERT INTO onboarding_state (auth_user_id, intended_role, step, profile_id, completed_at)
  VALUES (p_auth_user_id, v_role, 'completed', v_profile_id, now())
  ON CONFLICT (auth_user_id) DO UPDATE SET
    step = 'completed',
    profile_id = COALESCE(v_profile_id, onboarding_state.profile_id),
    error_message = NULL, completed_at = now(), updated_at = now();

  PERFORM sync_user_roles_for_user(p_auth_user_id);

  INSERT INTO auth_audit_log (auth_user_id, event_type, metadata)
  VALUES (p_auth_user_id, 'bootstrap_success',
    jsonb_build_object('action', 'admin_repair', 'role', v_role, 'profile_id', v_profile_id,
      'had_student', v_has_student, 'had_teacher', v_has_teacher, 'had_guardian', v_has_guardian));

  RETURN jsonb_build_object('status', 'repaired', 'role', v_role, 'profile_id', v_profile_id,
    'had_student', v_has_student, 'had_teacher', v_has_teacher, 'had_guardian', v_has_guardian);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."admin_update_user_status"("p_admin_auth_id" "uuid", "p_target_auth_user_id" "uuid", "p_action" "text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_admin_id UUID;
  v_target_role TEXT;
  v_prev_status TEXT;
BEGIN
  SELECT id INTO v_admin_id FROM admin_users
  WHERE auth_user_id = p_admin_auth_id AND is_active = true
  AND role IN ('super_admin', 'admin');
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('success', false, 'error', 'Not authorized');
  END IF;
  
  IF p_action NOT IN ('deactivate', 'reactivate', 'suspend') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Invalid action');
  END IF;
  
  v_target_role := get_user_role(p_target_auth_user_id);
  
  -- Prevent modifying other admins
  IF v_target_role IN ('super_admin', 'admin') THEN
    RETURN jsonb_build_object('success', false, 'error', 'Cannot modify admin accounts');
  END IF;
  
  IF v_target_role = 'student' THEN
    SELECT account_status INTO v_prev_status FROM students WHERE auth_user_id = p_target_auth_user_id;
    UPDATE students SET
      account_status = CASE p_action
        WHEN 'deactivate' THEN 'deactivated'
        WHEN 'reactivate' THEN 'active'
        WHEN 'suspend' THEN 'suspended'
      END,
      is_active = (p_action = 'reactivate'),
      updated_at = now()
    WHERE auth_user_id = p_target_auth_user_id;
  ELSIF v_target_role = 'parent' THEN
    v_prev_status := 'active';
  END IF;
  
  INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details)
  VALUES (v_admin_id, 'user_' || p_action, v_target_role, p_target_auth_user_id::text,
    jsonb_build_object('previous_status', v_prev_status, 'action', p_action, 'notes', p_notes));
  
  RETURN jsonb_build_object('success', true, 'role', v_target_role, 'action', p_action);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."archive_dead_subject_enrollments"() RETURNS TABLE("student_id" "uuid", "archived_count" integer, "archived_codes" "text"[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  r              RECORD;
  v_dead         TEXT[];
  v_kept         TEXT[];
  v_new_pref     TEXT;
BEGIN
  FOR r IN
    SELECT
      s.id,
      s.selected_subjects,
      s.preferred_subject,
      ARRAY_AGG(DISTINCT sse.subject_code) FILTER (
        WHERE sub.is_content_ready = FALSE
      ) AS dead_codes
    FROM students s
    JOIN student_subject_enrollment sse ON sse.student_id = s.id
    JOIN subjects sub                   ON sub.code        = sse.subject_code
    GROUP BY s.id, s.selected_subjects, s.preferred_subject
    HAVING ARRAY_AGG(DISTINCT sse.subject_code) FILTER (
      WHERE sub.is_content_ready = FALSE
    ) IS NOT NULL
  LOOP
    v_dead := r.dead_codes;
    v_kept := COALESCE(r.selected_subjects, ARRAY[]::TEXT[]);
    v_kept := ARRAY(SELECT UNNEST(v_kept) EXCEPT SELECT UNNEST(v_dead));

    IF NOT EXISTS (
      SELECT 1 FROM legacy_subjects_archive
       WHERE legacy_subjects_archive.student_id = r.id
         AND invalid_subjects = v_dead
         AND archived_at::date = CURRENT_DATE
    ) THEN
      INSERT INTO legacy_subjects_archive (student_id, invalid_subjects, reason, archived_at)
      VALUES (r.id, v_dead, 'subject_no_content', now());
    END IF;

    DELETE FROM student_subject_enrollment
     WHERE student_subject_enrollment.student_id = r.id
       AND subject_code = ANY(v_dead);

    v_new_pref := CASE
      WHEN r.preferred_subject = ANY(v_dead) THEN (SELECT v_kept[1])
      ELSE r.preferred_subject
    END;

    UPDATE students
       SET selected_subjects = v_kept,
           preferred_subject = v_new_pref
     WHERE id = r.id;

    INSERT INTO admin_audit_log (admin_id, action, entity_type, entity_id, details, created_at)
    VALUES (NULL, 'subject.dead_enrollment.archived', 'student', r.id::text,
            jsonb_build_object('archived', v_dead, 'kept', v_kept,
                               'new_preferred_subject', v_new_pref,
                               'archived_at', now()),
            now());

    student_id     := r.id;
    archived_count := COALESCE(array_length(v_dead, 1), 0);
    archived_codes := v_dead;
    RETURN NEXT;
  END LOOP;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."archive_old_data"("p_days" integer DEFAULT 30) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_cutoff timestamptz; v_e int:=0; v_q int:=0; v_n int:=0; v_a int:=0;
BEGIN
  v_cutoff := now() - (p_days || ' days')::interval;
  WITH m AS (DELETE FROM engagement_events WHERE created_at < v_cutoff RETURNING id, student_id, event_type, event_data, session_id, created_at)
  INSERT INTO engagement_events_archive SELECT * FROM m; GET DIAGNOSTICS v_e = ROW_COUNT;
  WITH m AS (DELETE FROM quiz_responses WHERE created_at < v_cutoff RETURNING id, student_id, session_id, question_text, selected_answer, is_correct, response_time_ms, created_at)
  INSERT INTO quiz_responses_archive SELECT * FROM m; GET DIAGNOSTICS v_q = ROW_COUNT;
  WITH m AS (DELETE FROM notifications WHERE created_at < v_cutoff AND is_read = true RETURNING id, recipient_id, recipient_type, type, title, message, is_read, created_at)
  INSERT INTO notifications_archive SELECT * FROM m; GET DIAGNOSTICS v_n = ROW_COUNT;
  WITH m AS (DELETE FROM ai_interaction_logs WHERE created_at < v_cutoff RETURNING id, student_id, interaction_type, model_used, latency_ms, input_tokens, output_tokens, created_at)
  INSERT INTO ai_interaction_logs_archive SELECT * FROM m; GET DIAGNOSTICS v_a = ROW_COUNT;
  RETURN jsonb_build_object('cutoff',v_cutoff,'engagement',v_e,'quiz_responses',v_q,'notifications',v_n,'ai_logs',v_a,'total',v_e+v_q+v_n+v_a);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."archive_processed_events"("p_older_than" interval DEFAULT '30 days'::interval) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count integer;
BEGIN
  DELETE FROM public.domain_events
  WHERE status = 'processed'
    AND processed_at IS NOT NULL
    AND processed_at < now() - p_older_than;
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;
COMMENT ON FUNCTION "public"."archive_processed_events"("p_older_than" interval) IS 'Delete processed events older than the supplied interval (default 30 days). Service-role-only maintenance RPC.';




CREATE OR REPLACE FUNCTION "public"."atomic_downgrade_subscription"("p_student_id" "uuid", "p_cancelled_sub_id" "text", "p_new_status" "text") RETURNS TABLE("outcome" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_sub_id text;
BEGIN
  IF p_new_status NOT IN ('cancelled','expired','halted','completed') THEN
    RAISE EXCEPTION 'invalid status: %', p_new_status;
  END IF;

  SELECT razorpay_subscription_id INTO v_current_sub_id
  FROM student_subscriptions
  WHERE student_id = p_student_id
  FOR UPDATE;

  IF v_current_sub_id IS NOT NULL AND v_current_sub_id <> p_cancelled_sub_id THEN
    RETURN QUERY SELECT 'stale_cancel_ignored'::text;
    RETURN;
  END IF;

  UPDATE students
  SET subscription_plan = 'free', updated_at = NOW()
  WHERE id = p_student_id;

  UPDATE student_subscriptions
  SET plan_code = 'free',
      status = p_new_status,
      cancelled_at = NOW(),
      updated_at = NOW()
  WHERE student_id = p_student_id;

  RETURN QUERY SELECT 'downgraded'::text;
END;
$$;
COMMENT ON FUNCTION "public"."atomic_downgrade_subscription"("p_student_id" "uuid", "p_cancelled_sub_id" "text", "p_new_status" "text") IS 'Atomic downgrade with stale-cancel guard via row-level lock. Replaces the JS SELECT-then-UPDATE in webhook/route.ts:downgradeIfMatchingSub.';




CREATE OR REPLACE FUNCTION "public"."atomic_plan_change"("p_student_id" "uuid", "p_new_plan" "text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $_$
DECLARE
  v_canonical_plan text;
  v_plan_id        uuid;
  v_old_student_plan text;
  v_old_sub_plan     text;
  v_now            timestamptz := now();
BEGIN
  IF p_student_id IS NULL THEN
    RAISE EXCEPTION 'p_student_id is required' USING ERRCODE = '22023';
  END IF;
  IF p_new_plan IS NULL OR length(p_new_plan) = 0 THEN
    RAISE EXCEPTION 'p_new_plan is required' USING ERRCODE = '22023';
  END IF;

  v_canonical_plan := p_new_plan;
  v_canonical_plan := regexp_replace(v_canonical_plan, '_(monthly|yearly)$', '');
  IF v_canonical_plan = 'ultimate' THEN v_canonical_plan := 'unlimited'; END IF;
  IF v_canonical_plan = 'basic'    THEN v_canonical_plan := 'starter';   END IF;
  IF v_canonical_plan = 'premium'  THEN v_canonical_plan := 'pro';       END IF;

  IF v_canonical_plan <> 'free' THEN
    SELECT id INTO v_plan_id
      FROM subscription_plans
     WHERE plan_code = v_canonical_plan
     LIMIT 1;
    IF v_plan_id IS NULL THEN
      RAISE EXCEPTION 'Plan not found in subscription_plans: % (input %)', v_canonical_plan, p_new_plan
        USING ERRCODE = '22023';
    END IF;
  END IF;

  PERFORM pg_advisory_xact_lock(
    hashtextextended('subscription:' || p_student_id::text, 0)
  );

  SELECT subscription_plan INTO v_old_student_plan
    FROM students WHERE id = p_student_id FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Student not found: %', p_student_id USING ERRCODE = 'P0002';
  END IF;

  SELECT plan_code INTO v_old_sub_plan
    FROM student_subscriptions WHERE student_id = p_student_id FOR UPDATE;

  UPDATE students
     SET subscription_plan = p_new_plan, updated_at = v_now
   WHERE id = p_student_id;

  UPDATE student_subscriptions
     SET plan_code  = v_canonical_plan,
         plan_id    = COALESCE(v_plan_id, plan_id),
         updated_at = v_now
   WHERE student_id = p_student_id;

  BEGIN
    PERFORM public.enqueue_event(
      'subscription.plan_changed',
      'student',
      p_student_id,
      jsonb_build_object(
        'student_id', p_student_id,
        'old_student_plan', v_old_student_plan,
        'old_sub_plan_code', v_old_sub_plan,
        'new_plan', p_new_plan,
        'new_sub_plan_code', v_canonical_plan,
        'reason', p_reason,
        'changed_at', v_now,
        'source', 'atomic_plan_change_rpc'
      )
    );
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'atomic_plan_change: enqueue_event failed (% / %), continuing', SQLERRM, SQLSTATE;
  END;

  RETURN jsonb_build_object(
    'success', true,
    'student_id', p_student_id,
    'old_student_plan', v_old_student_plan,
    'old_sub_plan_code', v_old_sub_plan,
    'new_plan', p_new_plan,
    'new_sub_plan_code', v_canonical_plan,
    'reason', p_reason,
    'changed_at', v_now
  );
END;
$_$;
COMMENT ON FUNCTION "public"."atomic_plan_change"("p_student_id" "uuid", "p_new_plan" "text", "p_reason" "text") IS 'Atomic admin plan change. Updates students.subscription_plan AND student_subscriptions.plan_code in a single transaction guarded by pg_advisory_xact_lock(''subscription:''||student_id). Closes the P11 split-brain class bug re-introduced by the super-admin bulk-actions/plan-change route. service_role-only EXECUTE.';




CREATE OR REPLACE FUNCTION "public"."atomic_quiz_profile_update"("p_student_id" "uuid", "p_xp" integer, "p_correct" integer, "p_total" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  PERFORM atomic_quiz_profile_update(
    p_student_id,
    'unknown'::TEXT,  -- p_subject  → normalised to NULL inside 7-param version
    p_xp,
    p_total,
    p_correct,
    0,                -- p_time_seconds
    NULL::UUID        -- p_session_id → CASE B path (no dedup reference_id)
  );
END;
$$;
COMMENT ON FUNCTION "public"."atomic_quiz_profile_update"("p_student_id" "uuid", "p_xp" integer, "p_correct" integer, "p_total" integer) IS 'Backward-compatible 4-param overload. Delegates to the canonical 7-param version with p_subject=''unknown'', p_time_seconds=0, p_session_id=NULL. p_session_id=NULL triggers the award_xp() delegation path (no reference_id). SECURITY DEFINER: delegates to a SECURITY DEFINER function.';




CREATE OR REPLACE FUNCTION "public"."atomic_quiz_profile_update"("p_student_id" "uuid", "p_xp" integer, "p_correct" integer, "p_total" integer, "p_subject" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_subject TEXT;
  v_today DATE := CURRENT_DATE;
BEGIN
  -- Use explicit subject if provided; fall back to preferred_subject only as last resort
  IF p_subject IS NOT NULL AND p_subject != '' THEN
    v_subject := p_subject;
  ELSE
    SELECT COALESCE(preferred_subject, 'math') INTO v_subject
    FROM students WHERE id = p_student_id;
  END IF;

  -- Atomically update learning profile: INCREMENT not replace
  INSERT INTO student_learning_profiles (
    student_id, subject, xp, level, total_sessions,
    total_questions_asked, total_questions_answered_correctly,
    last_session_at, streak_days
  ) VALUES (
    p_student_id, v_subject, p_xp, GREATEST(1, p_xp / 500 + 1), 1,
    p_total, p_correct, NOW(), 1
  )
  ON CONFLICT (student_id, subject) DO UPDATE SET
    xp = student_learning_profiles.xp + EXCLUDED.xp,
    level = GREATEST(1, (student_learning_profiles.xp + EXCLUDED.xp) / 500 + 1),
    total_sessions = student_learning_profiles.total_sessions + 1,
    total_questions_asked = student_learning_profiles.total_questions_asked + EXCLUDED.total_questions_asked,
    total_questions_answered_correctly = student_learning_profiles.total_questions_answered_correctly + EXCLUDED.total_questions_answered_correctly,
    last_session_at = NOW(),
    streak_days = CASE
      WHEN DATE(student_learning_profiles.last_session_at) = v_today THEN student_learning_profiles.streak_days
      WHEN DATE(student_learning_profiles.last_session_at) = v_today - 1 THEN student_learning_profiles.streak_days + 1
      ELSE 1
    END,
    longest_streak = GREATEST(
      student_learning_profiles.longest_streak,
      CASE
        WHEN DATE(student_learning_profiles.last_session_at) = v_today - 1 THEN student_learning_profiles.streak_days + 1
        ELSE student_learning_profiles.streak_days
      END
    );

  -- Update global XP total
  UPDATE students
  SET xp_total = COALESCE(xp_total, 0) + p_xp,
      last_active = NOW()
  WHERE id = p_student_id;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."atomic_quiz_profile_update"("p_student_id" "uuid", "p_subject" "text", "p_xp" integer, "p_total" integer, "p_correct" integer, "p_time_seconds" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_time_minutes  INT := GREATEST(1, ROUND(p_time_seconds / 60.0));
  v_daily_cap     INT := 200;
  v_today_earned  INT;
  v_remaining     INT;
  v_effective_xp  INT;
  v_xp_capped     BOOLEAN := false;
  v_xp_excess     INT := 0;
  v_new_profile_xp BIGINT;
BEGIN
  SELECT COALESCE(SUM(xp_earned), 0)::INT
    INTO v_today_earned
    FROM quiz_sessions
   WHERE student_id = p_student_id
     AND completed_at IS NOT NULL
     AND completed_at >= CURRENT_DATE
     AND completed_at <  (CURRENT_DATE + INTERVAL '1 day');

  v_remaining    := GREATEST(0, v_daily_cap - v_today_earned);
  v_effective_xp := LEAST(GREATEST(0, COALESCE(p_xp, 0)), v_remaining);

  IF v_effective_xp < COALESCE(p_xp, 0) THEN
    v_xp_capped := true;
    v_xp_excess := COALESCE(p_xp, 0) - v_effective_xp;
  END IF;

  INSERT INTO student_learning_profiles (
    student_id, subject, xp, total_sessions,
    total_questions_asked, total_questions_answered_correctly,
    total_time_minutes, last_session_at, streak_days, level, current_level
  ) VALUES (
    p_student_id, p_subject, v_effective_xp, 1,
    p_total, p_correct,
    v_time_minutes, NOW(), 1, 1, 'beginner'
  )
  ON CONFLICT (student_id, subject) DO UPDATE SET
    xp = student_learning_profiles.xp + v_effective_xp,
    total_sessions = student_learning_profiles.total_sessions + 1,
    total_questions_asked = student_learning_profiles.total_questions_asked + p_total,
    total_questions_answered_correctly = student_learning_profiles.total_questions_answered_correctly + p_correct,
    total_time_minutes = student_learning_profiles.total_time_minutes + v_time_minutes,
    last_session_at = NOW(),
    level = GREATEST(1, FLOOR((student_learning_profiles.xp + v_effective_xp) / 500) + 1)
  RETURNING xp INTO v_new_profile_xp;

  UPDATE students SET
    xp_total = COALESCE(xp_total, 0) + v_effective_xp,
    last_active = NOW(),
    streak_days = CASE
      WHEN last_active::date = CURRENT_DATE THEN COALESCE(streak_days, 1)
      WHEN last_active::date = CURRENT_DATE - 1 THEN COALESCE(streak_days, 0) + 1
      ELSE 1
    END
  WHERE id = p_student_id;

  RETURN jsonb_build_object(
    'success',         true,
    'requested_xp',    COALESCE(p_xp, 0),
    'effective_xp',    v_effective_xp,
    'xp_capped',       v_xp_capped,
    'xp_cap_excess',   v_xp_excess,
    'today_earned',    v_today_earned,
    'daily_cap',       v_daily_cap,
    'remaining_today', GREATEST(0, v_remaining - v_effective_xp),
    'profile_xp',      v_new_profile_xp
  );
END;
$$;
COMMENT ON FUNCTION "public"."atomic_quiz_profile_update"("p_student_id" "uuid", "p_subject" "text", "p_xp" integer, "p_total" integer, "p_correct" integer, "p_time_seconds" integer) IS 'Atomic quiz profile + student XP update with the P2 daily XP cap (200) enforced. Daily cap source of truth: src/lib/xp-rules.ts XP_RULES.quiz_daily_cap. Returns JSONB.';




CREATE OR REPLACE FUNCTION "public"."atomic_quiz_profile_update"("p_student_id" "uuid", "p_subject" "text", "p_xp" integer, "p_total" integer, "p_correct" integer, "p_time_seconds" integer, "p_session_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_time_minutes    INT     := GREATEST(1, ROUND(p_time_seconds / 60.0));
  v_today_quiz_xp   INTEGER := 0;
  v_xp_to_award     INTEGER := 0;
  v_reference_id    TEXT    := NULL;
  v_rows_inserted   INTEGER := 0;
  v_subject_clean   TEXT;
BEGIN
  -- ── Normalise subject ──────────────────────────────────────────────────────
  v_subject_clean := CASE WHEN p_subject IS NULL OR p_subject = 'unknown'
                          THEN NULL ELSE p_subject END;

  -- ── Step 1: Compute today's already-awarded quiz XP (IST date boundary) ───
  -- P2: daily quiz XP cap = 200. Uses the ledger as the authoritative source.
  SELECT COALESCE(SUM(amount), 0)
    INTO v_today_quiz_xp
  FROM xp_transactions
  WHERE student_id    = p_student_id
    AND daily_category = 'quiz'
    AND created_at    >= (CURRENT_DATE AT TIME ZONE 'Asia/Kolkata');

  -- Cap the award so total daily quiz XP never exceeds 200.
  -- If p_xp is 0 (flagged submission) or cap already reached, v_xp_to_award = 0.
  v_xp_to_award := GREATEST(0, LEAST(p_xp, 200 - v_today_quiz_xp));

  -- ── Step 2: Build reference_id for CASE A idempotency ────────────────────
  IF p_session_id IS NOT NULL THEN
    v_reference_id := 'quiz_' || p_session_id::TEXT;
  END IF;

  -- ── Step 3: Write ledger row and update XP totals ────────────────────────
  IF v_xp_to_award > 0 THEN

    IF v_reference_id IS NOT NULL THEN
      -- CASE A: session_id known — use direct INSERT with ON CONFLICT for strict
      -- idempotency. The unique partial index on reference_id guarantees that a
      -- re-submitted session is silently ignored.
      INSERT INTO xp_transactions (
        student_id, amount, source, subject,
        daily_category, reference_id, metadata, created_at
      ) VALUES (
        p_student_id,
        v_xp_to_award,
        'quiz',
        v_subject_clean,
        'quiz',
        v_reference_id,
        jsonb_build_object(
          'session_id',   p_session_id,
          'total_q',      p_total,
          'correct_q',    p_correct,
          'time_seconds', p_time_seconds,
          'original_xp',  p_xp           -- amount before daily cap
        ),
        NOW()
      )
      ON CONFLICT (reference_id) DO NOTHING;

      GET DIAGNOSTICS v_rows_inserted = ROW_COUNT;

      -- Only increment students.xp_total when a new ledger row was actually
      -- inserted (i.e. this is not a re-submission).
      IF v_rows_inserted > 0 THEN
        UPDATE students SET
          xp_total    = COALESCE(xp_total, 0) + v_xp_to_award,
          last_active = NOW()
        WHERE id = p_student_id;

        -- Increment subject-specific XP in learning profiles if subject known.
        IF v_subject_clean IS NOT NULL THEN
          UPDATE student_learning_profiles SET
            xp = COALESCE(xp, 0) + v_xp_to_award
          WHERE student_id = p_student_id
            AND subject    = v_subject_clean;
        END IF;
      END IF;

    ELSE
      -- CASE B: no session_id (legacy 4-param callers) — delegate to award_xp.
      -- award_xp writes the ledger row and updates students.xp_total and
      -- student_learning_profiles.xp. We pass p_daily_cap = NULL because the
      -- cap has already been applied above (v_xp_to_award is already capped).
      PERFORM award_xp(
        p_student_id     := p_student_id,
        p_amount         := v_xp_to_award,
        p_source         := 'quiz',
        p_subject        := v_subject_clean,
        p_daily_category := 'quiz',
        p_daily_cap      := NULL,
        p_metadata       := jsonb_build_object(
                              'total_q',      p_total,
                              'correct_q',    p_correct,
                              'time_seconds', p_time_seconds,
                              'original_xp',  p_xp
                            )
      );
      -- award_xp sets last_active = now() on students, so the streak UPDATE
      -- below will read the correct last_active value.
    END IF;

  END IF;
  -- v_xp_to_award = 0: ledger and students.xp_total intentionally untouched.

  -- ── Step 4: Upsert student_learning_profiles for session counters ─────────
  -- XP column:
  --   On first INSERT — set to v_xp_to_award (the capped amount).
  --   On UPDATE — XP is NOT incremented here; Steps 3A/3B already handled it.
  -- Level recalculation reads the XP value already in the row plus what we
  -- just added, using EXCLUDED.xp to reference the first-insert value safely.
  INSERT INTO student_learning_profiles (
    student_id,
    subject,
    xp,
    total_sessions,
    total_questions_asked,
    total_questions_answered_correctly,
    total_time_minutes,
    last_session_at,
    streak_days,
    level,
    current_level
  ) VALUES (
    p_student_id,
    COALESCE(v_subject_clean, 'general'),
    v_xp_to_award,
    1,
    p_total,
    p_correct,
    v_time_minutes,
    NOW(),
    1,
    1,
    'beginner'
  )
  ON CONFLICT (student_id, subject) DO UPDATE SET
    total_sessions                     = student_learning_profiles.total_sessions + 1,
    total_questions_asked              = student_learning_profiles.total_questions_asked + p_total,
    total_questions_answered_correctly = student_learning_profiles.total_questions_answered_correctly + p_correct,
    total_time_minutes                 = student_learning_profiles.total_time_minutes + v_time_minutes,
    last_session_at                    = NOW(),
    -- Level uses the already-updated xp column (Step 3 incremented it before
    -- this upsert runs). FLOOR division by 500 matches the original formula.
    level = GREATEST(1, FLOOR(student_learning_profiles.xp / 500.0) + 1);

  -- ── Step 5: Update streak_days on students ────────────────────────────────
  -- award_xp/direct UPDATE above set last_active = NOW() but do not compute
  -- streaks. We read the pre-NOW() last_active via a CASE on last_active::date.
  -- This UPDATE also sets last_active so it is always refreshed.
  UPDATE students SET
    last_active = NOW(),
    streak_days = CASE
      WHEN last_active::date = CURRENT_DATE     THEN COALESCE(streak_days, 1)
      WHEN last_active::date = CURRENT_DATE - 1 THEN COALESCE(streak_days, 0) + 1
      ELSE 1
    END
  WHERE id = p_student_id;

END;
$$;
COMMENT ON FUNCTION "public"."atomic_quiz_profile_update"("p_student_id" "uuid", "p_subject" "text", "p_xp" integer, "p_total" integer, "p_correct" integer, "p_time_seconds" integer, "p_session_id" "uuid") IS 'Atomically records a quiz session: enforces the P2 daily 200 XP quiz cap (200 XP/day from daily_category=''quiz'' in xp_transactions), writes the ledger row, updates students.xp_total, upserts session counters in student_learning_profiles, and updates streak_days. The optional 7th parameter p_session_id (DEFAULT NULL) supplies a dedup key (reference_id = ''quiz_'' || session_id); ON CONFLICT DO NOTHING prevents double-award on re-submission. When p_session_id is NULL (legacy callers), delegates ledger write to award_xp(). SECURITY DEFINER: writes to xp_transactions (no client INSERT policy), students, and student_learning_profiles across RLS boundaries. Ledger wiring + daily cap added in migration 20260408000004.';




CREATE OR REPLACE FUNCTION "public"."atomic_subscription_activation"("p_student_id" "uuid", "p_plan_code" "text", "p_billing_cycle" "text" DEFAULT 'monthly'::"text", "p_razorpay_payment_id" "text" DEFAULT NULL::"text", "p_razorpay_subscription_id" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_plan_id uuid;
  v_period_end timestamptz;
  v_next_billing timestamptz;
BEGIN
  SELECT id INTO v_plan_id FROM subscription_plans WHERE plan_code = p_plan_code LIMIT 1;
  IF v_plan_id IS NULL THEN
    RAISE EXCEPTION 'Plan not found: %', p_plan_code;
  END IF;

  v_period_end := CASE
    WHEN p_billing_cycle = 'yearly' THEN NOW() + INTERVAL '1 year'
    ELSE NOW() + INTERVAL '1 month'
  END;

  v_next_billing := CASE
    WHEN p_billing_cycle = 'yearly' THEN NOW() + INTERVAL '1 year'
    WHEN p_billing_cycle = 'monthly' AND p_razorpay_subscription_id IS NOT NULL THEN NOW() + INTERVAL '1 month'
    ELSE NULL
  END;

  INSERT INTO student_subscriptions (
    student_id, plan_id, plan_code, status, billing_cycle,
    current_period_start, current_period_end, next_billing_at,
    razorpay_payment_id, razorpay_subscription_id,
    auto_renew, renewal_attempts, grace_period_end, ended_at,
    updated_at
  ) VALUES (
    p_student_id, v_plan_id, p_plan_code, 'active', p_billing_cycle,
    NOW(), v_period_end, v_next_billing,
    p_razorpay_payment_id, p_razorpay_subscription_id,
    CASE WHEN p_razorpay_subscription_id IS NOT NULL THEN true ELSE false END,
    0, NULL, NULL, NOW()
  )
  ON CONFLICT (student_id) DO UPDATE SET
    plan_id = v_plan_id,
    plan_code = p_plan_code,
    status = 'active',
    billing_cycle = p_billing_cycle,
    current_period_start = NOW(),
    current_period_end = v_period_end,
    next_billing_at = v_next_billing,
    razorpay_payment_id = COALESCE(p_razorpay_payment_id, student_subscriptions.razorpay_payment_id),
    razorpay_subscription_id = COALESCE(p_razorpay_subscription_id, student_subscriptions.razorpay_subscription_id),
    auto_renew = CASE WHEN p_razorpay_subscription_id IS NOT NULL THEN true ELSE false END,
    renewal_attempts = 0,
    grace_period_end = NULL,
    ended_at = NULL,
    cancelled_at = NULL,
    cancel_reason = NULL,
    updated_at = NOW();

  UPDATE students SET
    subscription_plan = p_plan_code,
    updated_at = NOW()
  WHERE id = p_student_id;
END;
$$;
COMMENT ON FUNCTION "public"."atomic_subscription_activation"("p_student_id" "uuid", "p_plan_code" "text", "p_billing_cycle" "text", "p_razorpay_payment_id" "text", "p_razorpay_subscription_id" "text") IS 'P11 split-brain fallback. Atomically activates a subscription by upserting student_subscriptions and updating students.subscription_plan in a single transaction. Used by the payment webhook when the primary activate_subscription RPC fails.';




CREATE OR REPLACE FUNCTION "public"."atomic_subscription_activation_locked"("p_student_id" "uuid", "p_plan_code" "text", "p_billing_cycle" "text" DEFAULT 'monthly'::"text", "p_razorpay_payment_id" "text" DEFAULT NULL::"text", "p_razorpay_subscription_id" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  PERFORM pg_advisory_xact_lock(hashtextextended('subscription:' || p_student_id::text, 0));

  PERFORM atomic_subscription_activation(
    p_student_id,
    p_plan_code,
    p_billing_cycle,
    p_razorpay_payment_id,
    p_razorpay_subscription_id
  );
END;
$$;


CREATE OR REPLACE FUNCTION "public"."audit_student_changes"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'DELETE' OR (TG_OP = 'UPDATE' AND OLD.is_active = true AND NEW.is_active = false) THEN
    INSERT INTO admin_audit_log (action, entity_type, entity_id, details)
    VALUES (
      CASE WHEN TG_OP='DELETE' THEN 'student_deleted' ELSE 'student_deactivated' END,
      'student',
      COALESCE(OLD.id::text, NEW.id::text),
      jsonb_build_object('email', OLD.email, 'name', OLD.name, 'by', current_user)
    );
  END IF;
  IF TG_OP = 'DELETE' THEN RETURN OLD; ELSE RETURN NEW; END IF;
EXCEPTION WHEN OTHERS THEN
  IF TG_OP = 'DELETE' THEN RETURN OLD; ELSE RETURN NEW; END IF;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."auto_assign_free_plan"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO student_subscriptions (student_id, plan_id, plan_code, status, billing_cycle, current_period_end)
  SELECT NEW.id, sp.id, 'free', 'active', 'free', '2099-12-31'::timestamptz
  FROM subscription_plans sp WHERE sp.plan_code = 'free'
  ON CONFLICT (student_id) DO NOTHING;
  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."auto_create_learning_profile"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  INSERT INTO student_learning_profiles (student_id, subject, xp, streak_days, total_sessions)
  VALUES (NEW.id, COALESCE((SELECT code FROM subjects WHERE name = NEW.preferred_subject LIMIT 1), 'math'), 0, 0, 0)
  ON CONFLICT DO NOTHING;
  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."auto_setup_student"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Create learning profiles for core subjects
  INSERT INTO public.student_learning_profiles (student_id, subject, xp, level, streak_days, longest_streak, total_sessions, total_questions_asked, total_questions_answered_correctly, total_time_minutes)
  VALUES 
    (NEW.id, 'math', 0, 1, 0, 0, 0, 0, 0, 0),
    (NEW.id, 'science', 0, 1, 0, 0, 0, 0, 0, 0),
    (NEW.id, 'english', 0, 1, 0, 0, 0, 0, 0, 0),
    (NEW.id, 'hindi', 0, 1, 0, 0, 0, 0, 0, 0),
    (NEW.id, 'physics', 0, 1, 0, 0, 0, 0, 0, 0),
    (NEW.id, 'chemistry', 0, 1, 0, 0, 0, 0, 0, 0),
    (NEW.id, 'biology', 0, 1, 0, 0, 0, 0, 0, 0)
  ON CONFLICT (student_id, subject) DO NOTHING;

  -- Assign free plan using correct column names
  INSERT INTO public.student_subscriptions (student_id, plan_id, plan_code, status, current_period_start)
  SELECT NEW.id, sp.id, sp.plan_code, 'active', now()
  FROM public.subscription_plans sp WHERE sp.plan_code = 'free'
  ON CONFLICT (student_id) DO NOTHING;

  RETURN NEW;
EXCEPTION WHEN OTHERS THEN
  RAISE LOG 'auto_setup_student error for student %: %', NEW.id, SQLERRM;
  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."available_chapters_for_student_subject"("p_student_id" "uuid", "p_subject_code" "text") RETURNS TABLE("chapter_number" integer, "title" "text", "title_hi" "text", "ncert_page_start" integer, "ncert_page_end" integer, "total_questions" integer, "has_concepts" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_student_id UUID;
  v_grade      TEXT;
  v_allowed    BOOLEAN;
BEGIN
  SELECT id, grade INTO v_student_id, v_grade
    FROM students
   WHERE id = p_student_id OR auth_user_id = p_student_id
   LIMIT 1;

  IF v_student_id IS NULL THEN RETURN; END IF;

  SELECT EXISTS (
    SELECT 1 FROM get_available_subjects(v_student_id) gas
     WHERE gas.code = p_subject_code AND NOT gas.is_locked
  ) INTO v_allowed;

  IF NOT v_allowed THEN RETURN; END IF;

  RETURN QUERY
  SELECT
    c.chapter_number,
    c.title,
    c.title_hi,
    c.ncert_page_start,
    c.ncert_page_end,
    COALESCE(c.total_questions, 0)::INT,
    EXISTS (SELECT 1 FROM chapter_concepts cc WHERE cc.chapter_id = c.id AND cc.is_active)
  FROM chapters c
  WHERE c.subject_code = p_subject_code
    AND c.grade = v_grade
    AND c.is_active
  ORDER BY c.display_order NULLS LAST, c.chapter_number;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."available_chapters_for_student_subject_v2"("p_student_id" "uuid", "p_subject_code" "text") RETURNS TABLE("chapter_number" integer, "chapter_title" "text", "chapter_title_hi" "text", "verified_question_count" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_student_id UUID;
  v_grade      TEXT;
BEGIN
  IF p_subject_code IS NULL OR LENGTH(p_subject_code) = 0 THEN
    RETURN;
  END IF;

  SELECT id, grade INTO v_student_id, v_grade
    FROM students
   WHERE id = p_student_id OR auth_user_id = p_student_id
   LIMIT 1;

  IF v_student_id IS NULL OR v_grade IS NULL THEN
    RETURN;
  END IF;

  RETURN QUERY
  SELECT
    cs.chapter_number,
    cs.chapter_title,
    cs.chapter_title_hi,
    COALESCE(cs.verified_question_count, 0)::INTEGER AS verified_question_count
  FROM cbse_syllabus cs
  WHERE cs.board         = 'CBSE'
    AND cs.grade         = v_grade
    AND cs.subject_code  = p_subject_code
    AND cs.rag_status    IN ('partial', 'ready')
    AND cs.is_in_scope   = TRUE
  ORDER BY cs.chapter_number;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."award_coins"("p_student_id" "uuid", "p_amount" integer, "p_source" "text", "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_current_balance INTEGER; v_new_balance INTEGER;
BEGIN
  IF p_source NOT IN ('quiz_complete','first_quiz_of_day','streak_3_day','streak_7_day','streak_30_day','revise_decaying_topic','study_task_complete','study_plan_week','score_milestone','redemption','xp_migration','admin_adjustment','daily_challenge') THEN
    RAISE EXCEPTION 'Invalid coin source: %', p_source;
  END IF;
  IF p_amount < 0 THEN
    SELECT COALESCE(balance,0) INTO v_current_balance FROM coin_balances WHERE student_id=p_student_id FOR UPDATE;
    IF v_current_balance IS NULL THEN v_current_balance:=0; END IF;
    IF v_current_balance+p_amount<0 THEN RAISE EXCEPTION 'Insufficient coin balance'; END IF;
  END IF;
  INSERT INTO coin_transactions (student_id,amount,source,metadata) VALUES (p_student_id,p_amount,p_source,p_metadata);
  INSERT INTO coin_balances (student_id,balance,updated_at) VALUES (p_student_id,GREATEST(p_amount,0),now()) ON CONFLICT (student_id) DO UPDATE SET balance=coin_balances.balance+p_amount, updated_at=now();
  SELECT balance INTO v_new_balance FROM coin_balances WHERE student_id=p_student_id;
  RETURN v_new_balance;
END; $$;


CREATE OR REPLACE FUNCTION "public"."award_xp"("p_student_id" "uuid", "p_subject" "text", "p_xp" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_new_xp INTEGER;
  v_new_level INTEGER;
BEGIN
  INSERT INTO public.student_learning_profiles (student_id, subject, xp, level)
  VALUES (p_student_id, p_subject, 0, 1)
  ON CONFLICT (student_id, subject) DO NOTHING;
  UPDATE public.student_learning_profiles
  SET xp = xp + p_xp, level = GREATEST(1, (xp + p_xp) / 500 + 1), total_sessions = total_sessions + 1, last_session_at = NOW()
  WHERE student_id = p_student_id AND subject = p_subject
  RETURNING xp, level INTO v_new_xp, v_new_level;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."award_xp"("p_student_id" "uuid", "p_amount" integer, "p_source" "text", "p_subject" "text" DEFAULT NULL::"text", "p_daily_category" "text" DEFAULT NULL::"text", "p_daily_cap" integer DEFAULT NULL::integer, "p_metadata" "jsonb" DEFAULT '{}'::"jsonb") RETURNS TABLE("awarded" integer, "new_total" integer, "capped" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_today_total  INTEGER := 0;
  v_actual_award INTEGER;
  v_new_total    INTEGER;
BEGIN
  -- Validate amount is positive (use 'redemption' source for negative)
  IF p_source <> 'redemption' AND p_source <> 'admin_adjustment' AND p_amount < 0 THEN
    RAISE EXCEPTION 'Negative amount only allowed for redemption or admin_adjustment source';
  END IF;

  -- Check daily cap if applicable
  IF p_daily_category IS NOT NULL AND p_daily_cap IS NOT NULL THEN
    SELECT COALESCE(SUM(xt.amount), 0) INTO v_today_total
    FROM xp_transactions xt
    WHERE xt.student_id = p_student_id
      AND xt.daily_category = p_daily_category
      AND xt.created_at >= (CURRENT_DATE AT TIME ZONE 'Asia/Kolkata');

    IF v_today_total >= p_daily_cap THEN
      -- Cap reached, award nothing
      SELECT COALESCE(s.xp_total, 0) INTO v_new_total
      FROM students s WHERE s.id = p_student_id;
      RETURN QUERY SELECT 0, COALESCE(v_new_total, 0), TRUE;
      RETURN;
    END IF;

    -- Partial award if near cap
    v_actual_award := LEAST(p_amount, p_daily_cap - v_today_total);
  ELSE
    v_actual_award := p_amount;
  END IF;

  -- Skip if nothing to award
  IF v_actual_award = 0 THEN
    SELECT COALESCE(s.xp_total, 0) INTO v_new_total
    FROM students s WHERE s.id = p_student_id;
    RETURN QUERY SELECT 0, COALESCE(v_new_total, 0), FALSE;
    RETURN;
  END IF;

  -- Insert transaction record
  INSERT INTO xp_transactions (student_id, amount, source, subject, daily_category, metadata)
  VALUES (p_student_id, v_actual_award, p_source, p_subject, p_daily_category, p_metadata);

  -- Update running total on students table (for fast reads / leaderboard)
  UPDATE students
  SET xp_total = COALESCE(xp_total, 0) + v_actual_award,
      last_active = now()
  WHERE id = p_student_id
  RETURNING xp_total INTO v_new_total;

  -- Also update subject-specific XP if subject provided
  IF p_subject IS NOT NULL THEN
    UPDATE student_learning_profiles
    SET xp = COALESCE(xp, 0) + v_actual_award
    WHERE student_id = p_student_id AND subject = p_subject;
  END IF;

  RETURN QUERY SELECT v_actual_award, COALESCE(v_new_total, 0), (v_actual_award < p_amount);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."bkt_update"("p_student_id" "uuid", "p_node_code" "text", "p_is_correct" boolean, "p_response_time_ms" integer DEFAULT NULL::integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_rec RECORD;
  v_p_correct float;
  v_p_know_given_obs float;
  v_p_know_after float;
  v_old_level text;
  v_new_level text;
  v_regressed boolean := false;
  v_quality int;
  v_new_ef float;
  v_new_interval int;
  v_new_rep int;
BEGIN
  SELECT * INTO v_rec FROM public.adaptive_mastery WHERE student_id = p_student_id AND node_code = p_node_code;
  IF NOT FOUND THEN
    INSERT INTO public.adaptive_mastery (student_id, node_code, first_attempted_at) VALUES (p_student_id, p_node_code, now()) RETURNING * INTO v_rec;
  END IF;
  v_old_level := v_rec.mastery_level;
  IF p_is_correct THEN
    v_p_correct := v_rec.p_know * (1.0 - v_rec.p_slip) + (1.0 - v_rec.p_know) * v_rec.p_guess;
    v_p_know_given_obs := (v_rec.p_know * (1.0 - v_rec.p_slip)) / GREATEST(v_p_correct, 0.001);
  ELSE
    v_p_correct := v_rec.p_know * v_rec.p_slip + (1.0 - v_rec.p_know) * (1.0 - v_rec.p_guess);
    v_p_know_given_obs := (v_rec.p_know * v_rec.p_slip) / GREATEST(v_p_correct, 0.001);
  END IF;
  v_p_know_after := v_p_know_given_obs + (1.0 - v_p_know_given_obs) * v_rec.p_learn;
  v_p_know_after := GREATEST(0.01, LEAST(0.99, v_p_know_after));
  IF v_p_know_after >= 0.95 THEN v_new_level := 'mastered';
  ELSIF v_p_know_after >= 0.80 THEN v_new_level := 'proficient';
  ELSIF v_p_know_after >= 0.60 THEN v_new_level := 'familiar';
  ELSIF v_p_know_after >= 0.20 THEN v_new_level := 'attempted';
  ELSE v_new_level := 'not_started'; END IF;
  IF NOT p_is_correct AND v_old_level IN ('proficient','mastered') THEN
    IF v_new_level IN ('proficient','mastered') AND v_rec.consecutive_wrong >= 1 THEN
      v_new_level := 'familiar'; v_regressed := true;
    END IF;
  END IF;
  IF p_is_correct THEN
    IF p_response_time_ms IS NOT NULL AND p_response_time_ms < 10000 THEN v_quality := 5;
    ELSIF p_response_time_ms IS NOT NULL AND p_response_time_ms < 30000 THEN v_quality := 4;
    ELSE v_quality := 3; END IF;
  ELSE
    IF v_rec.consecutive_wrong >= 2 THEN v_quality := 0; ELSE v_quality := 1; END IF;
  END IF;
  v_new_ef := GREATEST(1.3, v_rec.ease_factor + (0.1 - (5 - v_quality) * (0.08 + (5 - v_quality) * 0.02)));
  IF v_quality >= 3 THEN
    v_new_rep := v_rec.repetition_count + 1;
    IF v_new_rep = 1 THEN v_new_interval := 1;
    ELSIF v_new_rep = 2 THEN v_new_interval := 3;
    ELSIF v_new_rep = 3 THEN v_new_interval := 7;
    ELSE v_new_interval := LEAST(180, CEIL(v_rec.interval_days * v_new_ef)); END IF;
  ELSE v_new_rep := 0; v_new_interval := 1; END IF;
  UPDATE public.adaptive_mastery SET
    p_know = v_p_know_after, mastery_prob = v_p_know_after, mastery_level = v_new_level,
    total_attempts = total_attempts + 1,
    correct_attempts = correct_attempts + CASE WHEN p_is_correct THEN 1 ELSE 0 END,
    consecutive_correct = CASE WHEN p_is_correct THEN consecutive_correct + 1 ELSE 0 END,
    consecutive_wrong = CASE WHEN p_is_correct THEN 0 ELSE consecutive_wrong + 1 END,
    ease_factor = v_new_ef, interval_days = v_new_interval, repetition_count = v_new_rep,
    next_review_at = now() + (v_new_interval || ' days')::interval,
    last_reviewed_at = now(), last_attempted_at = now(),
    eligible_for_interleave = (v_new_level IN ('familiar','proficient','mastered')),
    can_regress = true, updated_at = now()
  WHERE id = v_rec.id;
  RETURN jsonb_build_object('node_code', p_node_code, 'p_know', round(v_p_know_after::numeric, 4),
    'mastery_level', v_new_level, 'previous_level', v_old_level, 'regressed', v_regressed,
    'sm2', jsonb_build_object('quality', v_quality, 'ease_factor', round(v_new_ef::numeric, 2),
      'interval_days', v_new_interval, 'next_review', (now() + (v_new_interval || ' days')::interval)),
    'streak', CASE WHEN p_is_correct THEN v_rec.consecutive_correct + 1 ELSE 0 END,
    'eligible_for_interleave', (v_new_level IN ('familiar','proficient','mastered')));
END;
$$;


CREATE OR REPLACE FUNCTION "public"."bkt_update_personalized"("p_student_id" "uuid", "p_concept_id" "uuid", "p_is_correct" boolean) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_p_know DOUBLE PRECISION;
  v_p_learn DOUBLE PRECISION;
  v_p_guess DOUBLE PRECISION;
  v_p_slip DOUBLE PRECISION;
  v_posterior DOUBLE PRECISION;
  v_new_p_know DOUBLE PRECISION;
  v_predicted DOUBLE PRECISION;
BEGIN
  -- Read per-concept BKT parameters
  SELECT COALESCE(p_know, 0.3), COALESCE(p_learn, 0.2), COALESCE(p_guess, 0.25), COALESCE(p_slip, 0.1)
  INTO v_p_know, v_p_learn, v_p_guess, v_p_slip
  FROM concept_mastery WHERE student_id = p_student_id AND topic_id = p_concept_id;
  
  IF NOT FOUND THEN
    v_p_know := 0.3; v_p_learn := 0.2; v_p_guess := 0.25; v_p_slip := 0.1;
  END IF;
  
  -- Predict probability of correct answer
  v_predicted := v_p_know * (1.0 - v_p_slip) + (1.0 - v_p_know) * v_p_guess;
  
  -- Bayesian update
  IF p_is_correct THEN
    v_posterior := (v_p_know * (1.0 - v_p_slip)) / NULLIF(v_predicted, 0);
  ELSE
    v_posterior := (v_p_know * v_p_slip) / NULLIF(1.0 - v_predicted, 0);
  END IF;
  
  -- Learning transition
  v_new_p_know := v_posterior + (1.0 - v_posterior) * v_p_learn;
  
  -- Adapt per-concept parameters based on history
  UPDATE concept_mastery SET
    p_know = v_new_p_know,
    mastery_probability = v_new_p_know,
    p_learn = CASE 
      WHEN p_is_correct AND v_p_know > 0.7 THEN LEAST(0.4, v_p_learn + 0.01)
      WHEN NOT p_is_correct AND v_p_know < 0.3 THEN GREATEST(0.05, v_p_learn - 0.01)
      ELSE v_p_learn END,
    p_slip = CASE
      WHEN NOT p_is_correct AND v_p_know > 0.8 THEN LEAST(0.3, v_p_slip + 0.02)
      WHEN p_is_correct THEN GREATEST(0.02, v_p_slip - 0.005)
      ELSE v_p_slip END,
    mastery_level = CASE
      WHEN v_new_p_know >= 0.95 THEN 'mastered'
      WHEN v_new_p_know >= 0.7 THEN 'proficient'
      WHEN v_new_p_know >= 0.4 THEN 'developing'
      ELSE 'beginner' END,
    attempts = attempts + 1,
    correct_attempts = correct_attempts + CASE WHEN p_is_correct THEN 1 ELSE 0 END,
    last_attempted_at = now(),
    updated_at = now()
  WHERE student_id = p_student_id AND topic_id = p_concept_id;
  
  RETURN jsonb_build_object(
    'p_know', v_new_p_know,
    'predicted', v_predicted,
    'mastery_level', CASE WHEN v_new_p_know >= 0.95 THEN 'mastered' WHEN v_new_p_know >= 0.7 THEN 'proficient' WHEN v_new_p_know >= 0.4 THEN 'developing' ELSE 'beginner' END
  );
END;
$$;


CREATE OR REPLACE FUNCTION "public"."bootstrap_user_profile"("p_auth_user_id" "uuid", "p_role" "text", "p_name" "text", "p_email" "text", "p_grade" "text" DEFAULT NULL::"text", "p_board" "text" DEFAULT NULL::"text", "p_school_name" "text" DEFAULT NULL::"text", "p_subjects_taught" "text"[] DEFAULT NULL::"text"[], "p_grades_taught" "text"[] DEFAULT NULL::"text"[], "p_phone" "text" DEFAULT NULL::"text", "p_link_code" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_profile_id UUID;
  v_onboarding_id UUID;
  v_existing_step TEXT;
BEGIN
  SELECT step, profile_id INTO v_existing_step, v_profile_id
    FROM onboarding_state
    WHERE auth_user_id = p_auth_user_id;

  IF v_existing_step = 'completed' THEN
    RETURN jsonb_build_object('status', 'already_completed', 'profile_id', v_profile_id);
  END IF;

  INSERT INTO onboarding_state (auth_user_id, intended_role, step)
  VALUES (p_auth_user_id, p_role, 'identity_created')
  ON CONFLICT (auth_user_id) DO UPDATE SET
    step = 'identity_created',
    error_message = NULL,
    error_step = NULL,
    retry_count = onboarding_state.retry_count + 1,
    updated_at = now()
  RETURNING id INTO v_onboarding_id;

  BEGIN
    IF p_role = 'student' THEN
      INSERT INTO students (auth_user_id, name, email, grade, board, preferred_language, account_status)
      VALUES (
        p_auth_user_id, p_name, p_email,
        COALESCE(p_grade, '9'), COALESCE(p_board, 'CBSE'), 'en', 'active'
      )
      ON CONFLICT ON CONSTRAINT students_auth_user_id_unique DO UPDATE SET
        name = EXCLUDED.name, updated_at = now()
      RETURNING id INTO v_profile_id;

    ELSIF p_role = 'teacher' THEN
      INSERT INTO teachers (auth_user_id, name, email, school_name, subjects_taught, grades_taught)
      VALUES (
        p_auth_user_id, p_name, p_email, p_school_name,
        COALESCE(p_subjects_taught, '{}'), COALESCE(p_grades_taught, '{}')
      )
      ON CONFLICT ON CONSTRAINT teachers_auth_user_id_unique DO UPDATE SET
        name = EXCLUDED.name, updated_at = now()
      RETURNING id INTO v_profile_id;

    ELSIF p_role = 'parent' THEN
      INSERT INTO guardians (auth_user_id, name, email, phone)
      VALUES (p_auth_user_id, p_name, p_email, p_phone)
      ON CONFLICT ON CONSTRAINT guardians_auth_user_id_unique DO UPDATE SET
        name = EXCLUDED.name, updated_at = now()
      RETURNING id INTO v_profile_id;

    ELSE
      UPDATE onboarding_state SET
        step = 'failed', error_message = 'Invalid role: ' || p_role,
        error_step = 'profile_created', updated_at = now()
      WHERE id = v_onboarding_id;
      RETURN jsonb_build_object('status', 'error', 'error', 'Invalid role');
    END IF;

  EXCEPTION WHEN OTHERS THEN
    UPDATE onboarding_state SET
      step = 'failed', error_message = SQLERRM,
      error_step = 'profile_created', updated_at = now()
    WHERE id = v_onboarding_id;
    RETURN jsonb_build_object('status', 'error', 'error', SQLERRM);
  END;

  UPDATE onboarding_state SET
    step = 'completed', profile_id = v_profile_id,
    completed_at = now(), updated_at = now()
  WHERE id = v_onboarding_id;

  INSERT INTO auth_audit_log (auth_user_id, event_type, metadata)
  VALUES (p_auth_user_id, 'bootstrap_success',
    jsonb_build_object('role', p_role, 'profile_id', v_profile_id));

  RETURN jsonb_build_object('status', 'success', 'profile_id', v_profile_id, 'role', p_role);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."build_interleave_queue"("p_student_id" "uuid", "p_subject" "text", "p_session_size" integer DEFAULT 10) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_grade text;
  v_config record;
  v_interleave_count int;
  v_new_count int;
  v_result jsonb := '[]'::jsonb;
  v_used_codes text[] := '{}';
  rec record;
BEGIN
  SELECT public.normalize_grade(grade) INTO v_grade FROM public.students WHERE id = p_student_id;

  SELECT * INTO v_config FROM public.interleave_config WHERE subject_code = p_subject AND grade = v_grade;
  IF NOT FOUND THEN
    v_config.interleave_ratio := 0.30;
    v_config.min_mastery_for_interleave := 0.60;
    v_config.min_attempts_for_interleave := 3;
    v_config.cooldown_hours := 4;
    v_config.difficulty_boost := 0.10;
  END IF;

  v_interleave_count := GREATEST(1, round(p_session_size * v_config.interleave_ratio));
  v_new_count := p_session_size - v_interleave_count;

  FOR rec IN
    SELECT am.node_code, lg.title, lg.chapter_number, lg.bloom_level, am.mastery_prob
    FROM public.adaptive_mastery am
    JOIN public.learning_graph lg ON lg.node_code = am.node_code
    WHERE am.student_id = p_student_id AND lg.subject_code = p_subject AND lg.grade = v_grade
      AND am.mastery_level NOT IN ('mastered') AND am.total_attempts > 0
    ORDER BY am.mastery_prob ASC LIMIT v_new_count
  LOOP
    v_result := v_result || jsonb_build_object('node_code', rec.node_code, 'title', rec.title, 'chapter', rec.chapter_number, 'bloom', rec.bloom_level, 'mastery', round(rec.mastery_prob::numeric, 2), 'source', 'new_concept', 'queue_source', 'new_concept');
    v_used_codes := array_append(v_used_codes, rec.node_code);
  END LOOP;

  FOR rec IN
    SELECT am.node_code, lg.title, lg.chapter_number, lg.bloom_level, am.mastery_prob
    FROM public.adaptive_mastery am
    JOIN public.learning_graph lg ON lg.node_code = am.node_code
    WHERE am.student_id = p_student_id AND lg.subject_code = p_subject AND lg.grade = v_grade
      AND am.mastery_prob >= v_config.min_mastery_for_interleave
      AND am.total_attempts >= v_config.min_attempts_for_interleave
      AND am.eligible_for_interleave = true
      AND am.node_code != ALL(v_used_codes)
      AND (am.last_interleaved_at IS NULL OR am.last_interleaved_at < now() - (v_config.cooldown_hours || ' hours')::interval)
    ORDER BY random() LIMIT v_interleave_count
  LOOP
    v_result := v_result || jsonb_build_object('node_code', rec.node_code, 'title', rec.title, 'chapter', rec.chapter_number, 'bloom', rec.bloom_level, 'mastery', round(rec.mastery_prob::numeric, 2), 'source', 'interleaved', 'queue_source', 'interleave');
    v_used_codes := array_append(v_used_codes, rec.node_code);
  END LOOP;

  IF jsonb_array_length(v_result) < p_session_size THEN
    FOR rec IN
      SELECT am.node_code, lg.title, lg.chapter_number, lg.bloom_level, am.mastery_prob
      FROM public.adaptive_mastery am
      JOIN public.learning_graph lg ON lg.node_code = am.node_code
      WHERE am.student_id = p_student_id AND lg.subject_code = p_subject AND lg.grade = v_grade
        AND am.next_review_at IS NOT NULL AND am.next_review_at <= now() + interval '24 hours'
        AND am.node_code != ALL(v_used_codes)
      ORDER BY am.next_review_at ASC LIMIT (p_session_size - jsonb_array_length(v_result))
    LOOP
      v_result := v_result || jsonb_build_object('node_code', rec.node_code, 'title', rec.title, 'chapter', rec.chapter_number, 'bloom', rec.bloom_level, 'mastery', round(rec.mastery_prob::numeric, 2), 'source', 'srs_review', 'queue_source', 'srs_due');
    END LOOP;
  END IF;

  SELECT COALESCE(jsonb_agg(item ORDER BY random()), '[]'::jsonb) INTO v_result FROM jsonb_array_elements(v_result) item;

  DELETE FROM public.interleave_queue WHERE student_id = p_student_id AND completed_at IS NULL;
  INSERT INTO public.interleave_queue (student_id, node_code, subject_code, grade, source, priority, difficulty_level, target_layer, scheduled_for)
  SELECT p_student_id, item->>'node_code', p_subject, v_grade, item->>'queue_source',
    row_number() OVER (),
    CASE WHEN (item->>'queue_source') = 'interleave' THEN 3 ELSE 2 END,
    1, now()
  FROM jsonb_array_elements(v_result) item;

  RETURN jsonb_build_object(
    'student_id', p_student_id, 'subject', p_subject, 'grade', v_grade,
    'session_size', jsonb_array_length(v_result),
    'interleaved_count', (SELECT count(*) FROM jsonb_array_elements(v_result) r WHERE r->>'source' = 'interleaved'),
    'focused_count', (SELECT count(*) FROM jsonb_array_elements(v_result) r WHERE r->>'source' = 'new_concept'),
    'srs_count', (SELECT count(*) FROM jsonb_array_elements(v_result) r WHERE r->>'source' = 'srs_review'),
    'config', jsonb_build_object('ratio', v_config.interleave_ratio, 'min_mastery', v_config.min_mastery_for_interleave),
    'queue', v_result
  );
END;
$$;


CREATE OR REPLACE FUNCTION "public"."bulk_generate_hpc"("p_class_id" "uuid", "p_academic_year" "text" DEFAULT '2025-26'::"text", "p_term" "text" DEFAULT 'Term 1'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_count int := 0;
  v_student_id uuid;
BEGIN
  FOR v_student_id IN
    SELECT cs.student_id FROM public.class_students cs
    WHERE cs.class_id = p_class_id AND cs.is_active = true
  LOOP
    PERFORM public.generate_hpc(v_student_id, p_academic_year, p_term);
    v_count := v_count + 1;
  END LOOP;

  RETURN jsonb_build_object(
    'class_id', p_class_id,
    'hpcs_generated', v_count,
    'academic_year', p_academic_year,
    'term', p_term
  );
END;
$$;


CREATE OR REPLACE FUNCTION "public"."bulk_transition_status"("p_table" "text", "p_ids" "uuid"[], "p_new_status" "text", "p_actor_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count INTEGER := 0;
  v_id UUID;
BEGIN
  FOREACH v_id IN ARRAY p_ids LOOP
    BEGIN
      PERFORM transition_content_status(p_table, v_id, p_new_status, p_actor_id);
      v_count := v_count + 1;
    EXCEPTION WHEN OTHERS THEN
      -- Skip invalid transitions, continue with rest
      NULL;
    END;
  END LOOP;
  RETURN v_count;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."calculate_rl_reward"("p_student_id" "uuid", "p_action_id" "uuid", "p_is_correct" boolean, "p_response_time" integer, "p_engagement_score" double precision DEFAULT NULL::double precision) RETURNS double precision
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_reward DOUBLE PRECISION := 0;
  v_mastery_delta DOUBLE PRECISION := 0;
  v_retention DOUBLE PRECISION := 0;
  v_engagement DOUBLE PRECISION := COALESCE(p_engagement_score, 0.5);
  v_time_factor DOUBLE PRECISION;
  v_difficulty INTEGER;
  v_zpd_match DOUBLE PRECISION;
BEGIN
  SELECT difficulty_served INTO v_difficulty FROM rl_learning_actions WHERE id = p_action_id;
  
  v_time_factor := CASE
    WHEN p_response_time < 5 AND p_is_correct THEN 0.2
    WHEN p_response_time BETWEEN 5 AND 30 AND p_is_correct THEN 1.0
    WHEN p_response_time BETWEEN 30 AND 60 THEN 0.6
    ELSE 0.3 END;
  
  SELECT COALESCE(mastery_probability, 0) INTO v_mastery_delta
  FROM concept_mastery WHERE student_id = p_student_id
  ORDER BY updated_at DESC LIMIT 1;
  
  v_reward := 
    0.35 * (CASE WHEN p_is_correct THEN 1.0 ELSE -0.3 END) +
    0.25 * v_time_factor +
    0.20 * v_engagement +
    0.20 * LEAST(1.0, v_mastery_delta);
  
  IF p_is_correct AND v_difficulty >= 2 THEN
    v_reward := v_reward + 0.15;
  END IF;
  
  IF p_is_correct AND v_difficulty = 1 AND p_response_time < 5 THEN
    v_reward := v_reward - 0.1;
  END IF;
  
  UPDATE rl_learning_actions SET reward = v_reward WHERE id = p_action_id;
  
  RETURN v_reward;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."calibrate_irt_parameters"() RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  q RECORD;
  total_responses INT;
  correct_count INT;
  avg_time DOUBLE PRECISION;
  difficulty DOUBLE PRECISION;
  discrimination DOUBLE PRECISION;
  guessing DOUBLE PRECISION;
BEGIN
  FOR q IN SELECT id FROM question_bank WHERE is_active = true AND irt_response_count < (
    SELECT count(*) FROM quiz_responses WHERE question_id = question_bank.id
  ) OR NOT irt_calibrated
  LOOP
    SELECT count(*), count(*) FILTER (WHERE is_correct), avg(time_spent_seconds)
    INTO total_responses, correct_count, avg_time
    FROM quiz_responses WHERE question_id = q.id;
    
    IF total_responses >= 5 THEN
      -- 3PL approximation from response data
      difficulty := -2.0 + 4.0 * (1.0 - correct_count::float / total_responses);
      discrimination := GREATEST(0.3, LEAST(3.0, 1.0 / NULLIF(GREATEST(avg_time / 30.0, 0.1), 0)));
      guessing := GREATEST(0.1, LEAST(0.35, 
        CASE WHEN total_responses >= 20 THEN
          (SELECT count(*) FILTER (WHERE is_correct AND time_spent_seconds < 3)::float / NULLIF(total_responses, 0))
        ELSE 0.25 END
      ));
      
      UPDATE question_bank SET 
        irt_difficulty = difficulty,
        irt_discrimination = discrimination,
        irt_guessing = guessing,
        irt_calibrated = true,
        irt_response_count = total_responses
      WHERE id = q.id;
    END IF;
  END LOOP;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."cbse_syllabus_normalize_display"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_subject_name     TEXT;
  v_subject_name_hi  TEXT;
  v_chapter_title    TEXT;
  v_chapter_title_hi TEXT;
BEGIN
  -- Subject display: fill from subjects master when missing or echoing the code.
  IF NEW.subject_display IS NULL
     OR NEW.subject_display = NEW.subject_code
     OR NEW.subject_display_hi IS NULL
  THEN
    SELECT name, name_hi INTO v_subject_name, v_subject_name_hi
      FROM subjects
     WHERE code = NEW.subject_code
     LIMIT 1;

    IF v_subject_name IS NOT NULL THEN
      IF NEW.subject_display IS NULL OR NEW.subject_display = NEW.subject_code THEN
        NEW.subject_display := v_subject_name;
      END IF;
      IF NEW.subject_display_hi IS NULL THEN
        NEW.subject_display_hi := v_subject_name_hi;
      END IF;
    END IF;
  END IF;

  -- Chapter title: fill from chapters catalog when missing or placeholder.
  IF NEW.chapter_title IS NULL
     OR NEW.chapter_title ~ '^Chapter [0-9]+$'
     OR NEW.chapter_title_hi IS NULL
  THEN
    SELECT title, title_hi INTO v_chapter_title, v_chapter_title_hi
      FROM chapters
     WHERE grade = NEW.grade
       AND subject_code = NEW.subject_code
       AND chapter_number = NEW.chapter_number
       AND title IS NOT NULL
       AND title !~ '^Chapter [0-9]+$'
     LIMIT 1;

    IF v_chapter_title IS NOT NULL THEN
      IF NEW.chapter_title IS NULL OR NEW.chapter_title ~ '^Chapter [0-9]+$' THEN
        NEW.chapter_title := v_chapter_title;
      END IF;
      IF NEW.chapter_title_hi IS NULL THEN
        NEW.chapter_title_hi := v_chapter_title_hi;
      END IF;
    END IF;
  END IF;

  RETURN NEW;
END;
$_$;
COMMENT ON FUNCTION "public"."cbse_syllabus_normalize_display"() IS 'Study-path integrity trigger: ensures cbse_syllabus.subject_display and chapter_title always reflect Title Case names from the subjects master + chapters catalog, never bare codes or "Chapter N" placeholders when real data exists. See migration 20260418_display_integrity for history.';




CREATE OR REPLACE FUNCTION "public"."cbse_syllabus_rag_ready"("p_grade" "text", "p_subject_code" "text", "p_chapter_number" integer) RETURNS boolean
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_chunks int;
BEGIN
  SELECT count(*) INTO v_chunks
    FROM rag_content_chunks
    WHERE grade_short = p_grade
      AND subject_code = p_subject_code
      AND chapter_number = p_chapter_number
      AND is_active = true;
  RETURN v_chunks >= 50;
END $$;
COMMENT ON FUNCTION "public"."cbse_syllabus_rag_ready"("p_grade" "text", "p_subject_code" "text", "p_chapter_number" integer) IS 'Returns TRUE when the chapter has >= 50 active NCERT chunks. Distinct from cbse_syllabus.rag_status which also requires verified questions for full ready state. Use this for Foxy chat readiness checks.';




CREATE OR REPLACE FUNCTION "public"."check_and_award_achievements"("p_student_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_awarded jsonb := '[]'::jsonb;
  v_student record;
  v_mastered int;
  v_sessions int;
  rec record;
BEGIN
  SELECT xp_total, streak_days INTO v_student FROM public.students WHERE id = p_student_id;
  SELECT count(*) INTO v_mastered FROM public.adaptive_mastery WHERE student_id = p_student_id AND mastery_level = 'mastered';
  SELECT count(*) INTO v_sessions FROM public.practice_session_log WHERE student_id = p_student_id;

  FOR rec IN
    SELECT a.id, a.code, a.title, a.xp_reward, a.condition_type, a.condition_value
    FROM public.achievements a
    WHERE a.is_active = true
      AND NOT EXISTS (SELECT 1 FROM public.student_achievements sa WHERE sa.achievement_id = a.id AND sa.student_id = p_student_id)
  LOOP
    IF (rec.condition_type = 'xp_total' AND COALESCE(v_student.xp_total, 0) >= rec.condition_value)
    OR (rec.condition_type = 'streak_days' AND COALESCE(v_student.streak_days, 0) >= rec.condition_value)
    OR (rec.condition_type = 'concepts_mastered' AND v_mastered >= rec.condition_value)
    OR (rec.condition_type = 'sessions_count' AND v_sessions >= rec.condition_value)
    THEN
      INSERT INTO public.student_achievements (student_id, achievement_id) VALUES (p_student_id, rec.id) ON CONFLICT DO NOTHING;
      UPDATE public.students SET xp_total = COALESCE(xp_total, 0) + rec.xp_reward WHERE id = p_student_id;
      INSERT INTO public.student_moments (student_id, moment_type, title, description, xp_awarded)
      VALUES (p_student_id, 'achievement', rec.title, 'Achievement unlocked: ' || rec.title, rec.xp_reward);
      v_awarded := v_awarded || jsonb_build_object('code', rec.code, 'title', rec.title, 'xp', rec.xp_reward);
    END IF;
  END LOOP;

  RETURN jsonb_build_object('awarded', v_awarded, 'count', jsonb_array_length(v_awarded));
END;
$$;


CREATE OR REPLACE FUNCTION "public"."check_and_record_usage"("p_student_id" "uuid", "p_feature" "text", "p_usage_date" "date", "p_limit" integer DEFAULT NULL::integer) RETURNS TABLE("allowed" boolean, "used_count" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_limit integer;
  v_count integer;
BEGIN
  -- Always derive limit from the actual subscription plan
  v_limit := get_plan_limit(p_student_id, p_feature);

  -- Ensure the row exists before locking
  INSERT INTO public.student_daily_usage (student_id, feature, usage_date, usage_count)
  VALUES (p_student_id, p_feature, p_usage_date, 0)
  ON CONFLICT (student_id, feature, usage_date) DO NOTHING;

  -- Lock the row for this (student, feature, date) — atomic check+increment
  SELECT usage_count INTO v_count
  FROM   public.student_daily_usage
  WHERE  student_id  = p_student_id
    AND  feature     = p_feature
    AND  usage_date  = p_usage_date
  FOR UPDATE;

  IF v_count < v_limit THEN
    UPDATE public.student_daily_usage
    SET    usage_count = v_count + 1,
           updated_at  = NOW()
    WHERE  student_id  = p_student_id
      AND  feature     = p_feature
      AND  usage_date  = p_usage_date;

    RETURN QUERY SELECT true::boolean, (v_count + 1)::integer;
  ELSE
    RETURN QUERY SELECT false::boolean, v_count::integer;
  END IF;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."check_entitlement"("p_student_id" "uuid") RETURNS TABLE("has_access" boolean, "plan_code" "text", "status" "text", "grace_remaining" interval, "period_end" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY SELECT
    CASE
      WHEN ss.status = 'active' THEN true
      WHEN ss.status = 'past_due' AND ss.grace_period_end IS NOT NULL AND NOW() < ss.grace_period_end THEN true
      WHEN ss.status = 'cancelled' AND ss.current_period_end IS NOT NULL AND NOW() < ss.current_period_end THEN true
      ELSE false
    END,
    ss.plan_code, ss.status,
    CASE WHEN ss.grace_period_end IS NOT NULL AND NOW() < ss.grace_period_end THEN ss.grace_period_end - NOW() ELSE NULL END,
    ss.current_period_end
  FROM student_subscriptions ss WHERE ss.student_id = p_student_id;
END; $$;


CREATE OR REPLACE FUNCTION "public"."check_expired_subscriptions"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  expired_count integer;
BEGIN
  WITH expired AS (
    UPDATE student_subscriptions
    SET status = 'expired', cancelled_at = now(), updated_at = now()
    WHERE status = 'active' AND current_period_end < now() AND plan_code != 'free'
    RETURNING student_id
  )
  UPDATE students SET subscription_plan = 'free'
  WHERE id IN (SELECT student_id FROM expired);
  GET DIAGNOSTICS expired_count = ROW_COUNT;
  RETURN expired_count;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."check_permission"("p_auth_user_id" "uuid", "p_permission_code" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN EXISTS (SELECT 1 FROM user_roles ur JOIN role_permissions rp ON rp.role_id = ur.role_id JOIN permissions p ON p.id = rp.permission_id WHERE ur.auth_user_id = p_auth_user_id AND ur.is_active = true AND (ur.expires_at IS NULL OR ur.expires_at > now()) AND p.code = p_permission_code AND p.is_active = true);
END; $$;


CREATE OR REPLACE FUNCTION "public"."check_plan_limits"("p_student_id" "uuid", "p_usage_type" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_plan      text    := 'free';
  v_limit     integer;
  v_current   integer := 0;
  v_allowed   boolean;
  v_remaining integer;
  v_reason    text;
BEGIN
  -- Look up plan
  SELECT sp.plan_code INTO v_plan
  FROM   student_subscriptions ss
  JOIN   subscription_plans sp ON sp.plan_code = ss.plan_code
  WHERE  ss.student_id = p_student_id
    AND  ss.status IN ('active', 'trial')
  ORDER BY sp.sort_order DESC
  LIMIT 1;

  IF v_plan IS NULL THEN v_plan := 'free'; END IF;

  -- Resolve limit using the helper
  v_limit := get_plan_limit(p_student_id, p_usage_type);

  -- Read actual usage from new schema
  SELECT COALESCE(usage_count, 0) INTO v_current
  FROM   public.student_daily_usage
  WHERE  student_id  = p_student_id
    AND  feature     = p_usage_type
    AND  usage_date  = CURRENT_DATE;

  -- If row doesn't exist yet, current = 0
  IF NOT FOUND THEN v_current := 0; END IF;

  v_allowed   := v_current < v_limit;
  v_remaining := GREATEST(0, v_limit - v_current);
  v_reason    := CASE WHEN v_allowed THEN 'OK'
                      ELSE 'Daily ' || p_usage_type || ' limit reached (' || v_limit
                           || '). Upgrade plan for more.'
                 END;

  -- Increment via check_and_record_usage if allowed (atomic)
  IF v_allowed THEN
    PERFORM check_and_record_usage(p_student_id, p_usage_type, CURRENT_DATE);
  END IF;

  RETURN jsonb_build_object(
    'allowed',    v_allowed,
    'reason',     v_reason,
    'remaining',  CASE WHEN v_allowed THEN v_remaining - 1 ELSE 0 END,
    'plan',       v_plan,
    'used_today', CASE WHEN v_allowed THEN v_current + 1 ELSE v_current END,
    'limit',      v_limit
  );
END;
$$;


CREATE OR REPLACE FUNCTION "public"."check_rate_limit"("p_key" "text", "p_max" integer DEFAULT 20, "p_window" integer DEFAULT 60) RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
DECLARE v RECORD;
BEGIN
  SELECT * INTO v FROM api_rate_limits WHERE key = p_key FOR UPDATE;
  IF NOT FOUND THEN
    INSERT INTO api_rate_limits (key, request_count, max_requests, window_seconds) VALUES (p_key, 1, p_max, p_window) ON CONFLICT (key) DO UPDATE SET request_count = 1, window_start = now();
    RETURN true;
  END IF;
  IF v.window_start + (v.window_seconds || ' seconds')::interval < now() THEN
    UPDATE api_rate_limits SET request_count = 1, window_start = now() WHERE key = p_key; RETURN true;
  END IF;
  IF v.request_count < v.max_requests THEN
    UPDATE api_rate_limits SET request_count = request_count + 1 WHERE key = p_key; RETURN true;
  END IF;
  RETURN false;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."check_rate_limit"("p_identifier" "text", "p_endpoint" "text", "p_max_per_minute" integer DEFAULT 60) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$
DECLARE
  v_window timestamptz;
  v_count int;
BEGIN
  v_window := date_trunc('minute', now());
  INSERT INTO public.api_rate_limits_v2 (identifier, endpoint, window_start, request_count, max_requests)
  VALUES (p_identifier, p_endpoint, v_window, 1, p_max_per_minute)
  ON CONFLICT (identifier, endpoint, window_start)
  DO UPDATE SET request_count = public.api_rate_limits_v2.request_count + 1
  RETURNING request_count INTO v_count;
  DELETE FROM public.api_rate_limits_v2 WHERE window_start < now() - interval '5 minutes';
  RETURN v_count <= p_max_per_minute;
END;
$$;


CREATE TABLE IF NOT EXISTS "public"."ncert_book_catalog" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "storage_path" "text" NOT NULL,
    "grade" "text" NOT NULL,
    "subject" "text" NOT NULL,
    "book_name" "text",
    "chapter_code" "text",
    "file_size_bytes" bigint,
    "processing_status" "text" DEFAULT 'pending'::"text",
    "chunk_count" integer DEFAULT 0,
    "error_message" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "processed_at" timestamp with time zone
);


CREATE OR REPLACE FUNCTION "public"."claim_ncert_batch"("p_batch_size" integer DEFAULT 5, "p_max_file_size" bigint DEFAULT 104857600) RETURNS SETOF "public"."ncert_book_catalog"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  UPDATE public.ncert_book_catalog c
  SET processing_status = 'processing',
      processed_at = NULL,
      error_message = NULL
  WHERE c.id IN (
    SELECT id FROM public.ncert_book_catalog
    WHERE processing_status = 'pending'
      AND file_size_bytes < p_max_file_size
    ORDER BY file_size_bytes ASC
    LIMIT p_batch_size
    FOR UPDATE SKIP LOCKED
  )
  RETURNING c.*;
END
$$;


