    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$ DECLARE v_role TEXT := 'student'; v_name TEXT; v_email TEXT; v_grade TEXT := ''; v_board TEXT := ''; v_school TEXT := ''; v_payload JSONB; v_supabase_url TEXT := 'https://shktyoxqhundlvkiwguu.supabase.co'; v_anon_key TEXT; v_service_key TEXT; BEGIN IF OLD.email_confirmed_at IS NOT NULL OR NEW.email_confirmed_at IS NULL THEN RETURN NEW; END IF; v_email := NEW.email; v_name := COALESCE(NEW.raw_user_meta_data->>'name', split_part(v_email, '@', 1)); IF EXISTS (SELECT 1 FROM students WHERE auth_user_id = NEW.id) THEN v_role := 'student'; SELECT COALESCE(grade, ''), COALESCE(board, '') INTO v_grade, v_board FROM students WHERE auth_user_id = NEW.id LIMIT 1; v_grade := REPLACE(v_grade, 'Grade ', ''); ELSIF EXISTS (SELECT 1 FROM teachers WHERE auth_user_id = NEW.id) THEN v_role := 'teacher'; SELECT COALESCE(school_name, '') INTO v_school FROM teachers WHERE auth_user_id = NEW.id LIMIT 1; ELSIF EXISTS (SELECT 1 FROM guardians WHERE auth_user_id = NEW.id) THEN v_role := 'parent'; END IF; v_payload := jsonb_build_object('role', v_role, 'name', v_name, 'email', v_email, 'grade', v_grade, 'board', v_board, 'school_name', v_school); v_service_key := current_setting('app.settings.service_role_key', true); PERFORM net.http_post(url := v_supabase_url || '/functions/v1/send-welcome-email', body := v_payload, headers := jsonb_build_object('Content-Type', 'application/json', 'Authorization', 'Bearer ' || COALESCE(v_service_key, ''), 'apikey', COALESCE(v_service_key, ''))); RETURN NEW; EXCEPTION WHEN OTHERS THEN RAISE WARNING 'Welcome email trigger failed: %', SQLERRM; RETURN NEW; END; $$;


