CREATE OR REPLACE FUNCTION "public"."set_student_subjects"("p_student_id" "uuid", "p_subjects" "text"[], "p_preferred" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_student_id UUID;
  v_auth_user_id UUID;
  v_allowed TEXT[];
  v_invalid TEXT[];
  v_max INT;
  v_count INT;
BEGIN
  -- Resolve input (may be students.id or auth_user_id) to the canonical students.id
  SELECT id, auth_user_id INTO v_student_id, v_auth_user_id FROM students
   WHERE id = p_student_id OR auth_user_id = p_student_id
   LIMIT 1;

  IF v_student_id IS NULL THEN
    RAISE EXCEPTION 'student_not_found';
  END IF;

  -- authz: caller must match the auth_user_id on the target student row
  IF auth.uid() IS NOT NULL AND auth.uid() <> v_auth_user_id THEN
    RAISE EXCEPTION 'not_authorized';
  END IF;

  IF p_subjects IS NULL OR array_length(p_subjects, 1) IS NULL THEN
    p_subjects := ARRAY[]::TEXT[];
  END IF;

  SELECT ARRAY_AGG(code) INTO v_allowed
    FROM get_available_subjects(v_student_id) WHERE NOT is_locked;

  v_invalid := ARRAY(SELECT UNNEST(p_subjects) EXCEPT SELECT UNNEST(COALESCE(v_allowed, ARRAY[]::TEXT[])));
  IF array_length(v_invalid, 1) > 0 THEN
    RAISE EXCEPTION 'subject_not_allowed'
      USING DETAIL = jsonb_build_object('invalid', v_invalid, 'allowed', v_allowed)::text;
  END IF;

  SELECT max_subjects INTO v_max
    FROM subscription_plans sp
    JOIN student_subscriptions ss ON ss.plan_id = sp.id
   WHERE ss.student_id = v_student_id
     AND ss.status IN ('active','trialing','grace')
   ORDER BY ss.current_period_end DESC NULLS LAST LIMIT 1;

  v_count := COALESCE(array_length(p_subjects, 1), 0);
  IF v_max IS NOT NULL AND v_count > v_max THEN
    RAISE EXCEPTION 'max_subjects_exceeded'
      USING DETAIL = jsonb_build_object('limit', v_max, 'requested', v_count)::text;
  END IF;

  DELETE FROM student_subject_enrollment WHERE student_id = v_student_id;
  IF v_count > 0 THEN
    INSERT INTO student_subject_enrollment (student_id, subject_code, source)
      SELECT v_student_id, UNNEST(p_subjects), 'student';
  END IF;

  UPDATE students
     SET selected_subjects = p_subjects,
         preferred_subject = COALESCE(
           CASE WHEN p_preferred = ANY(p_subjects) THEN p_preferred ELSE NULL END,
           p_subjects[1],
           preferred_subject
         )
   WHERE id = v_student_id;

  RETURN jsonb_build_object('ok', true, 'subjects', p_subjects, 'student_id', v_student_id);
END;
$$;


