CREATE OR REPLACE FUNCTION "public"."snapshot_connection_health"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ DECLARE v_active int; v_idle int; v_waiting int; v_max int; v_pct numeric; v_alert text DEFAULT NULL; BEGIN SELECT count(*) FILTER (WHERE state = 'active'), count(*) FILTER (WHERE state = 'idle'), count(*) FILTER (WHERE wait_event IS NOT NULL AND state != 'active'), (SELECT setting::int FROM pg_settings WHERE name = 'max_connections') INTO v_active, v_idle, v_waiting, v_max FROM pg_stat_activity WHERE backend_type = 'client backend'; v_pct := ROUND((v_active + v_idle)::numeric / GREATEST(v_max, 1) * 100, 2); IF v_pct > 80 THEN v_alert := 'CRITICAL: Connection utilization above 80%'; ELSIF v_pct > 60 THEN v_alert := 'WARNING: Connection utilization above 60%'; ELSIF v_waiting > 5 THEN v_alert := 'WARNING: ' || v_waiting || ' connections waiting'; END IF; INSERT INTO connection_health_log (active_connections, idle_connections, waiting_connections, max_connections, pool_utilization_pct) VALUES (v_active, v_idle, v_waiting, v_max, v_pct); DELETE FROM connection_health_log WHERE check_time < now() - interval '7 days'; RETURN jsonb_build_object('active', v_active, 'idle', v_idle, 'waiting', v_waiting, 'max', v_max, 'utilization_pct', v_pct, 'alert', v_alert, 'healthy', v_pct < 80 AND v_waiting < 5); END; $$;


CREATE OR REPLACE FUNCTION "public"."start_quiz_session"("p_student_id" "uuid", "p_question_ids" "uuid"[]) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_session_id UUID := gen_random_uuid();
  v_qid UUID;
  v_options JSONB;
  v_options_arr JSONB;
  v_correct_idx INT;
  v_shuffle INT[];
  v_displayed JSONB;
  v_questions JSONB := '[]'::jsonb;
  v_question_meta RECORD;
  v_temp INT;
  v_swap_idx INT;
  i INT;
BEGIN
  -- Ownership check: caller must own this student.
  -- service_role bypasses RLS but not this guard, so even an admin caller
  -- has to pass p_student_id matching auth.uid()'s student row.
  -- Skip the check when called from the service_role context (auth.uid()
  -- is NULL) so admin / cron / RPC-from-edge-function paths still work.
  IF auth.uid() IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM students
    WHERE id = p_student_id AND auth_user_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'Access denied: caller does not own student %', p_student_id;
  END IF;

  IF p_question_ids IS NULL OR array_length(p_question_ids, 1) IS NULL THEN
    RETURN jsonb_build_object(
      'session_id', v_session_id,
      'questions', '[]'::jsonb
    );
  END IF;

  -- Iterate over input question IDs, generate per-question shuffle, snapshot.
  FOREACH v_qid IN ARRAY p_question_ids LOOP
    SELECT id, question_text, question_hi, options, correct_answer_index,
           explanation, explanation_hi, hint, difficulty, bloom_level,
           chapter_number, question_type
      INTO v_question_meta
      FROM question_bank
      WHERE id = v_qid AND is_active = true;

    -- Skip unknown / inactive questions silently — caller is responsible
    -- for filtering. We never want a bad ID in the input array to abort
    -- the entire session start.
    IF v_question_meta IS NULL THEN
      CONTINUE;
    END IF;

    -- Normalize options to a JSONB array.
    v_options := CASE
      WHEN jsonb_typeof(v_question_meta.options::jsonb) = 'array' THEN v_question_meta.options::jsonb
      ELSE NULL
    END;

    -- For non-MCQ or malformed options, store an identity shuffle and
    -- the snapshot as-is. Scoring still works because v_correct_idx is
    -- preserved verbatim in the snapshot.
    IF v_options IS NULL OR jsonb_array_length(v_options) <> 4 THEN
      v_shuffle := ARRAY[0,1,2,3]::INT[];
      v_options_arr := COALESCE(v_options, '[]'::jsonb);
    ELSE
      -- Fisher-Yates shuffle on [0,1,2,3] using random().
      v_shuffle := ARRAY[0,1,2,3]::INT[];
      FOR i IN REVERSE 4..2 LOOP
        -- random returns [0,1); floor((i) * random) gives 0..i-1.
        v_swap_idx := 1 + floor(random() * i)::INT;  -- 1-based for PL/pgSQL arrays
        v_temp := v_shuffle[i];
        v_shuffle[i] := v_shuffle[v_swap_idx];
        v_shuffle[v_swap_idx] := v_temp;
      END LOOP;
      v_options_arr := v_options;
    END IF;

    v_correct_idx := COALESCE(v_question_meta.correct_answer_index, 0);

    -- Persist snapshot. ON CONFLICT DO NOTHING keeps the RPC idempotent if
    -- the same (session_id, question_id) pair is submitted twice — though
    -- that should never happen because session_id is freshly generated.
    INSERT INTO quiz_session_shuffles (
      session_id, question_id, shuffle_map,
      options_snapshot, correct_answer_index_snapshot, student_id
    ) VALUES (
      v_session_id, v_qid, v_shuffle,
      v_options_arr, v_correct_idx, p_student_id
    )
    ON CONFLICT (session_id, question_id) DO NOTHING;

    -- Build the displayed options array (in shuffled order) for the client.
    -- Client never receives correct_answer_index — that's intentional.
    IF jsonb_array_length(v_options_arr) = 4 THEN
      v_displayed := jsonb_build_array(
        v_options_arr -> v_shuffle[1],
        v_options_arr -> v_shuffle[2],
        v_options_arr -> v_shuffle[3],
        v_options_arr -> v_shuffle[4]
      );
    ELSE
      v_displayed := v_options_arr;
    END IF;

    v_questions := v_questions || jsonb_build_array(
      jsonb_build_object(
        'question_id', v_qid,
        'question_text', v_question_meta.question_text,
        'question_hi', v_question_meta.question_hi,
        'question_type', v_question_meta.question_type,
        'options_displayed', v_displayed,
        'explanation', v_question_meta.explanation,
        'explanation_hi', v_question_meta.explanation_hi,
        'hint', v_question_meta.hint,
        'difficulty', v_question_meta.difficulty,
        'bloom_level', v_question_meta.bloom_level,
        'chapter_number', v_question_meta.chapter_number
        -- DO NOT include correct_answer_index here. That's the bug class
        -- this migration closes.
      )
    );
  END LOOP;

  RETURN jsonb_build_object(
    'session_id', v_session_id,
    'questions', v_questions
  );
END;
$$;
COMMENT ON FUNCTION "public"."start_quiz_session"("p_student_id" "uuid", "p_question_ids" "uuid"[]) IS 'P0 fix (migration 20260428160000): server-owned shuffle authority for quiz sessions. Generates a per-question Fisher-Yates shuffle, snapshots options + correct_answer_index into quiz_session_shuffles, and returns the SHUFFLED options to the client WITHOUT correct_answer_index. Pair with submit_quiz_results_v2 — client sends only {question_id, selected_displayed_index} per response; server re-derives is_correct against the snapshot. Closes the P1+P6 drift bug where a mid-session question_bank.options edit corrupted the client''s stable shuffle map. Backwards compatible: legacy submit_quiz_results (v1) is preserved for in-flight clients.';




CREATE OR REPLACE FUNCTION "public"."student_join_class"("p_student_id" "uuid", "p_class_code" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ DECLARE v_class RECORD; BEGIN SELECT id, name, grade INTO v_class FROM classes WHERE class_code = upper(trim(p_class_code)) AND is_active = true; IF v_class.id IS NULL THEN RETURN jsonb_build_object('error', 'Invalid class code.'); END IF; IF EXISTS (SELECT 1 FROM class_students WHERE class_id = v_class.id AND student_id = p_student_id) THEN RETURN jsonb_build_object('error', 'You are already in this class'); END IF; INSERT INTO class_students (class_id, student_id, joined_at) VALUES (v_class.id, p_student_id, now()); RETURN jsonb_build_object('success', true, 'class_name', v_class.name, 'class_grade', v_class.grade, 'message', 'Joined class: ' || v_class.name); END; $$;


CREATE OR REPLACE FUNCTION "public"."student_respond_to_link_request"("p_student_auth_id" "uuid", "p_link_id" "uuid", "p_action" "text", "p_reason" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ DECLARE v_student_id UUID; BEGIN IF p_action NOT IN ('approved', 'rejected') THEN RETURN jsonb_build_object('success', false, 'error', 'Action must be approved or rejected'); END IF; SELECT id INTO v_student_id FROM public.students WHERE auth_user_id = p_student_auth_id; IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'Student profile not found'); END IF; UPDATE public.guardian_student_links SET status = p_action, is_verified = (p_action = 'approved'), approved_by = CASE WHEN p_action = 'approved' THEN p_student_auth_id ELSE NULL END, approved_at = CASE WHEN p_action = 'approved' THEN now() ELSE NULL END, rejected_reason = CASE WHEN p_action = 'rejected' THEN COALESCE(p_reason, 'Declined by student') ELSE NULL END, updated_at = now() WHERE id = p_link_id AND student_id = v_student_id AND status = 'pending'; IF NOT FOUND THEN RETURN jsonb_build_object('success', false, 'error', 'No pending request found'); END IF; INSERT INTO public.admin_audit_log (action, entity_type, entity_id, details) VALUES ('guardian_link_' || p_action, 'guardian_student_link', p_link_id::TEXT, jsonb_build_object('student_auth_id', p_student_auth_id, 'action', p_action)); RETURN jsonb_build_object('success', true, 'status', p_action); END; $$;


CREATE OR REPLACE FUNCTION "public"."submit_challenge_attempt"("p_student_id" "uuid", "p_challenge_id" "uuid", "p_solved" boolean, "p_moves" integer, "p_hints_used" integer, "p_distractors_excluded" integer, "p_time_spent" integer, "p_coins_earned" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_attempt_id UUID; v_new_streak INTEGER; v_new_balance INTEGER;
BEGIN
  INSERT INTO challenge_attempts (student_id, challenge_id, solved, moves, hints_used, distractors_excluded, time_spent_seconds, coins_earned)
  VALUES (p_student_id, p_challenge_id, p_solved, p_moves, p_hints_used, p_distractors_excluded, p_time_spent, p_coins_earned)
  ON CONFLICT (student_id, challenge_id) DO UPDATE SET solved=EXCLUDED.solved, moves=EXCLUDED.moves, hints_used=EXCLUDED.hints_used, distractors_excluded=EXCLUDED.distractors_excluded, time_spent_seconds=EXCLUDED.time_spent_seconds, coins_earned=EXCLUDED.coins_earned, attempted_at=now()
  RETURNING id INTO v_attempt_id;

  IF p_solved THEN
    INSERT INTO challenge_streaks (student_id, current_streak, best_streak, last_challenge_date)
    VALUES (p_student_id, 1, 1, CURRENT_DATE)
    ON CONFLICT (student_id) DO UPDATE SET
      current_streak = CASE
        WHEN challenge_streaks.last_challenge_date = CURRENT_DATE THEN challenge_streaks.current_streak
        WHEN challenge_streaks.last_challenge_date = CURRENT_DATE - 1 THEN challenge_streaks.current_streak + 1
        ELSE 1
      END,
      best_streak = GREATEST(challenge_streaks.best_streak, CASE
        WHEN challenge_streaks.last_challenge_date = CURRENT_DATE - 1 THEN challenge_streaks.current_streak + 1
        ELSE 1
      END),
      last_challenge_date = CURRENT_DATE;

    SELECT current_streak INTO v_new_streak FROM challenge_streaks WHERE student_id = p_student_id;

    IF p_coins_earned > 0 THEN
      SELECT award_coins(p_student_id, p_coins_earned, 'daily_challenge', jsonb_build_object('challenge_id', p_challenge_id)) INTO v_new_balance;
    END IF;
  END IF;

  RETURN jsonb_build_object('attempt_id', v_attempt_id, 'solved', p_solved, 'streak', COALESCE(v_new_streak, 0), 'coin_balance', COALESCE(v_new_balance, 0));
END; $$;


CREATE OR REPLACE FUNCTION "public"."submit_poll_response"("p_poll_id" "uuid", "p_student_id" "uuid", "p_answer_index" integer DEFAULT NULL::integer, "p_answer_text" "text" DEFAULT NULL::"text", "p_response_time_ms" integer DEFAULT NULL::integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$ DECLARE v_poll RECORD; v_correct boolean; BEGIN SELECT * INTO v_poll FROM public.classroom_polls WHERE id = p_poll_id; IF NOT FOUND THEN RETURN jsonb_build_object('error', 'Poll not found'); END IF; IF v_poll.status != 'live' THEN RETURN jsonb_build_object('error', 'Poll is not live'); END IF; v_correct := CASE WHEN v_poll.correct_index IS NOT NULL THEN p_answer_index = v_poll.correct_index ELSE NULL END; INSERT INTO public.classroom_poll_responses (poll_id, student_id, answer_index, answer_text, is_correct, response_time_ms) VALUES (p_poll_id, p_student_id, p_answer_index, p_answer_text, v_correct, p_response_time_ms) ON CONFLICT (poll_id, student_id) DO UPDATE SET answer_index = p_answer_index, answer_text = p_answer_text, is_correct = v_correct, response_time_ms = p_response_time_ms, submitted_at = now(); RETURN jsonb_build_object('submitted', true, 'is_correct', v_correct); END; $$;


CREATE OR REPLACE FUNCTION "public"."submit_quiz_results"("p_student_id" "uuid", "p_subject" "text", "p_grade" "text", "p_topic" "text" DEFAULT NULL::"text", "p_chapter" integer DEFAULT NULL::integer, "p_responses" "jsonb" DEFAULT '[]'::"jsonb", "p_time" integer DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    AS $$
DECLARE
  v_total INTEGER := 0;
  v_correct INTEGER := 0;
  v_score_percent NUMERIC;
  v_xp INTEGER := 0;
  v_session_id UUID;
  v_flagged BOOLEAN := false;
  v_avg_time NUMERIC;
  r JSONB;
  v_question_id UUID;
  v_selected INTEGER;
  v_shuffle JSONB;
  v_shuffle_arr INTEGER[];
  v_shuffle_ok BOOLEAN;
  v_shuffle_valid BOOLEAN;
  v_selected_orig INTEGER;
  v_actual_correct INTEGER;
  v_is_correct BOOLEAN;
  v_client_is_correct BOOLEAN;
  v_q_text TEXT;
  v_q_type TEXT;
  v_q_topic_id UUID;
  v_q_number INTEGER := 0;
  v_q_bloom TEXT;
  v_q_difficulty INT;
  v_answer_counts    INT[]   := ARRAY[0,0,0,0];
  v_max_same_answer  INT     := 0;
  v_cme_action TEXT;
  v_cme_concept_id UUID;
  v_cme_reason TEXT;
BEGIN
  FOR r IN SELECT * FROM jsonb_array_elements(p_responses)
  LOOP
    v_total := v_total + 1;
    v_question_id := (r->>'question_id')::UUID;
    v_selected := (r->>'selected_option')::INTEGER;
    v_shuffle := r->'shuffle_map';

    v_shuffle_valid := (
      v_shuffle IS NOT NULL
      AND jsonb_typeof(v_shuffle) = 'array'
      AND jsonb_array_length(v_shuffle) = 4
      AND v_selected IS NOT NULL
      AND v_selected BETWEEN 0 AND 3
    );
    IF v_shuffle_valid THEN
      v_shuffle_ok := true;
      v_shuffle_arr := NULL;
      BEGIN
        SELECT array_agg(elem ORDER BY ord)
          INTO v_shuffle_arr
          FROM (
            SELECT (e)::INTEGER AS elem, ord
            FROM jsonb_array_elements_text(v_shuffle) WITH ORDINALITY AS t(e, ord)
          ) s;
      EXCEPTION WHEN OTHERS THEN
        v_shuffle_ok := false;
      END;
      IF v_shuffle_ok AND v_shuffle_arr IS NOT NULL AND array_length(v_shuffle_arr, 1) = 4 THEN
        FOR i IN 1..4 LOOP
          IF v_shuffle_arr[i] IS NULL OR v_shuffle_arr[i] < 0 OR v_shuffle_arr[i] > 3 THEN
            v_shuffle_ok := false;
            EXIT;
          END IF;
        END LOOP;
      ELSE
        v_shuffle_ok := false;
      END IF;

      IF v_shuffle_ok THEN
        v_selected_orig := v_shuffle_arr[v_selected + 1];
      ELSE
        v_selected_orig := v_selected;
      END IF;
    ELSE
      v_selected_orig := v_selected;
    END IF;

    SELECT correct_answer_index INTO v_actual_correct
    FROM question_bank WHERE id = v_question_id;

    v_is_correct := (
      v_selected_orig IS NOT NULL
      AND v_actual_correct IS NOT NULL
      AND v_selected_orig = v_actual_correct
    );

    IF v_is_correct THEN
      v_correct := v_correct + 1;
    END IF;

    IF v_selected IS NOT NULL AND v_selected >= 0 AND v_selected <= 3 THEN
      v_answer_counts[v_selected + 1] := v_answer_counts[v_selected + 1] + 1;
    END IF;
  END LOOP;

  IF v_total = 0 THEN
    RETURN jsonb_build_object(
      'total', 0, 'correct', 0, 'score_percent', 0,
      'xp_earned', 0, 'session_id', NULL, 'flagged', false
    );
  END IF;

  v_avg_time := CASE WHEN v_total > 0 THEN p_time::NUMERIC / v_total ELSE 0 END;
  IF v_avg_time < 3.0 AND v_total > 0 THEN
    v_flagged := true;
  END IF;

  IF v_total > 3 THEN
    v_max_same_answer := GREATEST(
      v_answer_counts[1], v_answer_counts[2],
      v_answer_counts[3], v_answer_counts[4]
    );
    IF v_max_same_answer = v_total THEN
      v_flagged := true;
    END IF;
  END IF;

  IF jsonb_array_length(p_responses) != v_total THEN
    v_flagged := true;
  END IF;

  v_score_percent := ROUND((v_correct::NUMERIC / v_total) * 100);

  IF v_flagged THEN
    v_xp := 0;
  ELSE
    v_xp := v_correct * 10;
    IF v_score_percent >= 80 THEN v_xp := v_xp + 20; END IF;
    IF v_score_percent = 100 THEN v_xp := v_xp + 50; END IF;
  END IF;

  INSERT INTO quiz_sessions (
    student_id, subject, grade, topic_title, chapter_number,
    total_questions, correct_answers, score_percent,
    time_taken_seconds, score, is_completed, completed_at
  ) VALUES (
    p_student_id, p_subject, p_grade, p_topic, p_chapter,
    v_total, v_correct, v_score_percent,
    p_time, v_xp, true, NOW()
  ) RETURNING id INTO v_session_id;

  v_q_number := 0;
  FOR r IN SELECT * FROM jsonb_array_elements(p_responses)
  LOOP
    v_q_number := v_q_number + 1;
    v_question_id := (r->>'question_id')::UUID;
    v_selected := (r->>'selected_option')::INTEGER;
    v_shuffle := r->'shuffle_map';

    v_shuffle_arr := NULL;
    v_shuffle_valid := (
      v_shuffle IS NOT NULL
      AND jsonb_typeof(v_shuffle) = 'array'
      AND jsonb_array_length(v_shuffle) = 4
      AND v_selected IS NOT NULL
      AND v_selected BETWEEN 0 AND 3
    );
    IF v_shuffle_valid THEN
      v_shuffle_ok := true;
      v_shuffle_arr := NULL;
      BEGIN
        SELECT array_agg(elem ORDER BY ord)
          INTO v_shuffle_arr
          FROM (
            SELECT (e)::INTEGER AS elem, ord
            FROM jsonb_array_elements_text(v_shuffle) WITH ORDINALITY AS t(e, ord)
          ) s;
      EXCEPTION WHEN OTHERS THEN
        v_shuffle_ok := false;
      END;
      IF v_shuffle_ok AND v_shuffle_arr IS NOT NULL AND array_length(v_shuffle_arr, 1) = 4 THEN
        FOR i IN 1..4 LOOP
          IF v_shuffle_arr[i] IS NULL OR v_shuffle_arr[i] < 0 OR v_shuffle_arr[i] > 3 THEN
            v_shuffle_ok := false;
            EXIT;
          END IF;
        END LOOP;
      ELSE
        v_shuffle_ok := false;
      END IF;

      IF v_shuffle_ok THEN
        v_selected_orig := v_shuffle_arr[v_selected + 1];
      ELSE
        v_selected_orig := v_selected;
        v_shuffle_arr := NULL;
      END IF;
    ELSE
      v_selected_orig := v_selected;
      v_shuffle_arr := NULL;
    END IF;

    SELECT correct_answer_index, question_text, question_type, topic_id, bloom_level, difficulty
    INTO v_actual_correct, v_q_text, v_q_type, v_q_topic_id, v_q_bloom, v_q_difficulty
    FROM question_bank WHERE id = v_question_id;

    v_is_correct := (
      v_selected_orig IS NOT NULL
      AND v_actual_correct IS NOT NULL
      AND v_selected_orig = v_actual_correct
    );

    IF (r ? 'is_correct') AND jsonb_typeof(r->'is_correct') = 'boolean' THEN
      v_client_is_correct := (r->>'is_correct')::BOOLEAN;
      IF v_client_is_correct IS DISTINCT FROM v_is_correct THEN
        BEGIN
          INSERT INTO ops_events (
            occurred_at, category, source, severity,
            subject_type, subject_id, message, context, environment
          ) VALUES (
            NOW(),
            'grounding.scoring',
            'submit_quiz_results',
            'warning',
            'student', p_student_id::text,
            'Client/server is_correct disagreement on quiz_response',
            jsonb_build_object(
              'student_id', p_student_id,
              'session_id', v_session_id,
              'question_id', v_question_id,
              'client_flag', v_client_is_correct,
              'server_flag', v_is_correct,
              'selected_option', v_selected,
              'selected_orig', v_selected_orig,
              'actual_correct', v_actual_correct,
              'shuffle_map', v_shuffle
            ),
            COALESCE(current_setting('app.environment', true), 'production')
          );
        EXCEPTION WHEN OTHERS THEN
          NULL;
        END;
      END IF;
    END IF;

    INSERT INTO quiz_responses (
      quiz_session_id, student_id, question_id, selected_option,
      is_correct, time_spent_seconds,
      question_number, question_text, question_type,
      shuffle_map
    ) VALUES (
      v_session_id, p_student_id, v_question_id, v_selected,
      v_is_correct, COALESCE((r->>'time_spent')::INTEGER, 0),
      v_q_number, v_q_text, v_q_type,
      v_shuffle_arr
    ) ON CONFLICT DO NOTHING;

    IF v_q_topic_id IS NOT NULL THEN
      PERFORM update_learner_state_post_quiz(
        p_student_id,
        v_q_topic_id,
        v_is_correct,
        v_q_bloom,
        (r->>'error_type')::TEXT,
        COALESCE((r->>'time_spent')::INT, 0) * 1000,
        v_q_difficulty
      );
    END IF;

    INSERT INTO user_question_history (
      student_id, question_id, subject, grade, chapter_number,
      first_shown_at, last_shown_at, times_shown, last_result
    ) VALUES (
      p_student_id, v_question_id, p_subject, p_grade, p_chapter,
      NOW(), NOW(), 1, v_is_correct
    ) ON CONFLICT (student_id, question_id) DO UPDATE SET
      last_shown_at = NOW(),
      times_shown = user_question_history.times_shown + 1,
      last_result = v_is_correct;
  END LOOP;

  PERFORM atomic_quiz_profile_update(
    p_student_id, p_subject, v_xp, v_total, v_correct, p_time, v_session_id
  );

  BEGIN
    SELECT ca.action_type, ca.concept_id, ca.reason
    INTO v_cme_action, v_cme_concept_id, v_cme_reason
    FROM compute_post_quiz_action(p_student_id, p_subject, p_grade) ca;

    UPDATE quiz_sessions
    SET cme_next_action = v_cme_action,
        cme_next_concept_id = v_cme_concept_id,
        cme_reason = v_cme_reason
    WHERE id = v_session_id;
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN jsonb_build_object(
    'total', v_total,
    'correct', v_correct,
    'score_percent', v_score_percent,
    'xp_earned', v_xp,
    'session_id', v_session_id,
    'flagged', v_flagged,
    'cme_next_action', v_cme_action,
    'cme_next_concept_id', v_cme_concept_id,
    'cme_reason', v_cme_reason
  );
END;
$$;


CREATE OR REPLACE FUNCTION "public"."submit_quiz_results_rpc"("p_student_id" "uuid", "p_started_at" timestamp with time zone, "p_finished_at" timestamp with time zone, "p_items" "jsonb", "p_subject" "text" DEFAULT NULL::"text", "p_grade" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ DECLARE v_result jsonb; BEGIN BEGIN v_result := (SELECT row_to_json(t) FROM (SELECT * FROM public.submit_quiz_results(p_student_id, p_started_at, p_finished_at, p_items, COALESCE(p_subject,'unknown')::text, COALESCE(p_grade,'N/A')::text)) t); RETURN COALESCE(v_result, jsonb_build_object('success', true)); EXCEPTION WHEN undefined_function THEN BEGIN v_result := (SELECT row_to_json(t) FROM (SELECT * FROM public.submit_quiz_results(p_student_id, p_started_at, p_finished_at, p_items, COALESCE(p_subject,'unknown')::text)) t); RETURN COALESCE(v_result, jsonb_build_object('success', true)); EXCEPTION WHEN undefined_function THEN BEGIN v_result := (SELECT row_to_json(t) FROM (SELECT * FROM public.submit_quiz_results(p_student_id, p_started_at, p_finished_at, p_items)) t); RETURN COALESCE(v_result, jsonb_build_object('success', true)); EXCEPTION WHEN OTHERS THEN RETURN jsonb_build_object('success', false, 'error', SQLERRM); END; END; END; END; $$;


CREATE OR REPLACE FUNCTION "public"."submit_quiz_results_safe"("p_student_id" "uuid", "p_items" "jsonb", "p_subject" "text" DEFAULT 'unknown'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ DECLARE v_started timestamptz := now() - interval '1 minute'; v_finished timestamptz := now(); v_resp jsonb; BEGIN v_resp := public.submit_quiz_results_rpc(p_student_id, v_started, v_finished, p_items, p_subject, NULL); RETURN jsonb_build_object('ok', COALESCE((v_resp->>'success')::boolean, true), 'detail', v_resp); EXCEPTION WHEN OTHERS THEN RETURN jsonb_build_object('ok', false, 'error', SQLERRM); END; $$;


CREATE OR REPLACE FUNCTION "public"."submit_quiz_results_v2"("p_session_id" "uuid", "p_student_id" "uuid", "p_subject" "text", "p_grade" "text", "p_topic" "text" DEFAULT NULL::"text", "p_chapter" integer DEFAULT NULL::integer, "p_responses" "jsonb" DEFAULT '[]'::"jsonb", "p_time" integer DEFAULT 0) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_total INTEGER := 0;
  v_correct INTEGER := 0;
  v_score_percent NUMERIC;
  v_xp INTEGER := 0;
  v_quiz_session_id UUID;
  v_flagged BOOLEAN := false;
  v_avg_time NUMERIC;
  r JSONB;
  v_question_id UUID;
  v_selected_displayed INTEGER;
  v_selected_orig INTEGER;
  v_shuffle INT[];
  v_correct_idx_snapshot INT;
  v_options_snapshot JSONB;
  v_is_correct BOOLEAN;
  v_q_text TEXT;
  v_q_type TEXT;
  v_q_topic_id UUID;
  v_q_number INTEGER := 0;
  v_q_bloom TEXT;
  v_q_difficulty INT;
  v_answer_counts INT[] := ARRAY[0,0,0,0];
  v_max_same_answer INT := 0;
  v_review_questions JSONB := '[]'::jsonb;
  v_correct_option_text TEXT;
  v_cme_action TEXT;
  v_cme_concept_id UUID;
  v_cme_reason TEXT;
BEGIN
  -- Ownership check (same pattern as start_quiz_session).
  IF auth.uid() IS NOT NULL AND NOT EXISTS (
    SELECT 1 FROM students
    WHERE id = p_student_id AND auth_user_id = auth.uid()
  ) THEN
    RAISE EXCEPTION 'Access denied: caller does not own student %', p_student_id;
  END IF;

  -- Validate session ownership: every shuffle row for this session must
  -- belong to the caller's student. If the session has zero shuffle rows,
  -- the caller may have submitted a v2 payload without first calling
  -- start_quiz_session — fall through to scoring with NULL shuffles, which
  -- treats selected_displayed_index as already in original space.
  IF EXISTS (
    SELECT 1 FROM quiz_session_shuffles
    WHERE session_id = p_session_id AND student_id <> p_student_id
  ) THEN
    RAISE EXCEPTION 'Access denied: session % does not belong to student %',
      p_session_id, p_student_id;
  END IF;

  -- ─── First pass: count + score in original-index space ───────────────
  FOR r IN SELECT * FROM jsonb_array_elements(p_responses)
  LOOP
    v_total := v_total + 1;
    v_question_id := (r->>'question_id')::UUID;
    -- v2 contract: client sends `selected_displayed_index`, NOT
    -- `selected_option`. Accept both keys for resilience while the
    -- web client transitions; mobile + legacy paths still call v1.
    v_selected_displayed := COALESCE(
      (r->>'selected_displayed_index')::INTEGER,
      (r->>'selected_option')::INTEGER
    );

    -- Look up snapshot. service_role-context calls bypass RLS, so this
    -- read works inside the SECURITY DEFINER function.
    SELECT shuffle_map, correct_answer_index_snapshot
      INTO v_shuffle, v_correct_idx_snapshot
      FROM quiz_session_shuffles
     WHERE session_id = p_session_id AND question_id = v_question_id;

    IF v_shuffle IS NOT NULL
       AND array_length(v_shuffle, 1) = 4
       AND v_selected_displayed IS NOT NULL
       AND v_selected_displayed BETWEEN 0 AND 3 THEN
      -- 1-based PL/pgSQL array indexing.
      v_selected_orig := v_shuffle[v_selected_displayed + 1];
    ELSE
      -- No snapshot OR malformed shuffle OR out-of-range index. Treat
      -- selected as already-original (matches v1 fallback semantics).
      v_selected_orig := v_selected_displayed;
    END IF;

    v_is_correct := (
      v_selected_orig IS NOT NULL
      AND v_correct_idx_snapshot IS NOT NULL
      AND v_selected_orig = v_correct_idx_snapshot
    );

    IF v_is_correct THEN
      v_correct := v_correct + 1;
    END IF;

    -- P3 Check 2: distribution tracked on the SHUFFLED click (matches v1).
    IF v_selected_displayed IS NOT NULL
       AND v_selected_displayed >= 0
       AND v_selected_displayed <= 3 THEN
      v_answer_counts[v_selected_displayed + 1] := v_answer_counts[v_selected_displayed + 1] + 1;
    END IF;
  END LOOP;

  IF v_total = 0 THEN
    RETURN jsonb_build_object(
      'total', 0, 'correct', 0, 'score_percent', 0,
      'xp_earned', 0, 'session_id', NULL, 'flagged', false,
      'questions', '[]'::jsonb
    );
  END IF;

  -- P3 Check 1: avg time < 3s -> flag, xp = 0.
  v_avg_time := CASE WHEN v_total > 0 THEN p_time::NUMERIC / v_total ELSE 0 END;
  IF v_avg_time < 3.0 AND v_total > 0 THEN
    v_flagged := true;
  END IF;

  -- P3 Check 2: not all same answer if >3 questions.
  IF v_total > 3 THEN
    v_max_same_answer := GREATEST(
      v_answer_counts[1], v_answer_counts[2],
      v_answer_counts[3], v_answer_counts[4]
    );
    IF v_max_same_answer = v_total THEN
      v_flagged := true;
    END IF;
  END IF;

  -- P3 Check 3: response count matches jsonb_array_length.
  IF jsonb_array_length(p_responses) <> v_total THEN
    v_flagged := true;
  END IF;

  -- P1: score_percent = ROUND((v_correct / v_total) * 100). Identical to v1.
  v_score_percent := ROUND((v_correct::NUMERIC / v_total) * 100);

  -- P2: base + high_score_bonus + perfect_bonus, gated by P3 flag.
  IF v_flagged THEN
    v_xp := 0;
  ELSE
    v_xp := v_correct * 10;
    IF v_score_percent >= 80 THEN v_xp := v_xp + 20; END IF;
    IF v_score_percent = 100 THEN v_xp := v_xp + 50; END IF;
  END IF;

  -- Insert quiz_sessions row.
  INSERT INTO quiz_sessions (
    student_id, subject, grade, topic_title, chapter_number,
    total_questions, correct_answers, score_percent,
    time_taken_seconds, score, is_completed, completed_at
  ) VALUES (
    p_student_id, p_subject, p_grade, p_topic, p_chapter,
    v_total, v_correct, v_score_percent,
    p_time, v_xp, true, NOW()
  ) RETURNING id INTO v_quiz_session_id;

  -- ─── Second pass: write quiz_responses + history + per-question state ─
  v_q_number := 0;
  FOR r IN SELECT * FROM jsonb_array_elements(p_responses)
  LOOP
    v_q_number := v_q_number + 1;
    v_question_id := (r->>'question_id')::UUID;
    v_selected_displayed := COALESCE(
      (r->>'selected_displayed_index')::INTEGER,
      (r->>'selected_option')::INTEGER
    );

    SELECT shuffle_map, correct_answer_index_snapshot, options_snapshot
      INTO v_shuffle, v_correct_idx_snapshot, v_options_snapshot
      FROM quiz_session_shuffles
     WHERE session_id = p_session_id AND question_id = v_question_id;

    IF v_shuffle IS NOT NULL
       AND array_length(v_shuffle, 1) = 4
       AND v_selected_displayed IS NOT NULL
       AND v_selected_displayed BETWEEN 0 AND 3 THEN
      v_selected_orig := v_shuffle[v_selected_displayed + 1];
    ELSE
      v_selected_orig := v_selected_displayed;
    END IF;

    SELECT question_text, question_type, topic_id, bloom_level, difficulty
      INTO v_q_text, v_q_type, v_q_topic_id, v_q_bloom, v_q_difficulty
      FROM question_bank WHERE id = v_question_id;

    v_is_correct := (
      v_selected_orig IS NOT NULL
      AND v_correct_idx_snapshot IS NOT NULL
      AND v_selected_orig = v_correct_idx_snapshot
    );

    -- Resolve correct_option_text from the SNAPSHOT (not live question_bank).
    IF v_options_snapshot IS NOT NULL
       AND jsonb_typeof(v_options_snapshot) = 'array'
       AND v_correct_idx_snapshot IS NOT NULL
       AND jsonb_array_length(v_options_snapshot) > v_correct_idx_snapshot THEN
      v_correct_option_text := v_options_snapshot ->> v_correct_idx_snapshot;
    ELSE
      v_correct_option_text := NULL;
    END IF;

    INSERT INTO quiz_responses (
      quiz_session_id, student_id, question_id, selected_option,
      is_correct, time_spent_seconds,
      question_number, question_text, question_type,
      shuffle_map
    ) VALUES (
      v_quiz_session_id, p_student_id, v_question_id, v_selected_displayed,
      v_is_correct, COALESCE((r->>'time_spent')::INTEGER, 0),
      v_q_number, v_q_text, v_q_type,
      v_shuffle
    ) ON CONFLICT DO NOTHING;

    -- Unified learner state update (matches v1).
    IF v_q_topic_id IS NOT NULL THEN
      PERFORM update_learner_state_post_quiz(
        p_student_id,
        v_q_topic_id,
        v_is_correct,
        v_q_bloom,
        (r->>'error_type')::TEXT,
        COALESCE((r->>'time_spent')::INT, 0) * 1000,
        v_q_difficulty
      );
    END IF;

    INSERT INTO user_question_history (
      student_id, question_id, subject, grade, chapter_number,
      first_shown_at, last_shown_at, times_shown, last_result
    ) VALUES (
      p_student_id, v_question_id, p_subject, p_grade, p_chapter,
      NOW(), NOW(), 1, v_is_correct
    ) ON CONFLICT (student_id, question_id) DO UPDATE SET
      last_shown_at = NOW(),
      times_shown = user_question_history.times_shown + 1,
      last_result = v_is_correct;

    -- Append to review payload — the v2 contract returns per-question
    -- review data so the client review screen never derives correct
    -- answer text from its own (potentially-stale) options array.
    v_review_questions := v_review_questions || jsonb_build_array(
      jsonb_build_object(
        'question_id', v_question_id,
        'is_correct', v_is_correct,
        'selected_displayed_index', v_selected_displayed,
        'selected_original_index', v_selected_orig,
        'correct_original_index', v_correct_idx_snapshot,
        'correct_option_text', v_correct_option_text,
        'shuffle_map', to_jsonb(v_shuffle)
      )
    );
  END LOOP;

  -- P4: atomic XP + profile update via the same RPC v1 uses.
  PERFORM atomic_quiz_profile_update(
    p_student_id, p_subject, v_xp, v_total, v_correct, p_time, v_quiz_session_id
  );

  -- CME: best-effort post-quiz action (error-isolated, matches v1).
  BEGIN
    SELECT ca.action_type, ca.concept_id, ca.reason
      INTO v_cme_action, v_cme_concept_id, v_cme_reason
      FROM compute_post_quiz_action(p_student_id, p_subject, p_grade) ca;

    UPDATE quiz_sessions
       SET cme_next_action = v_cme_action,
           cme_next_concept_id = v_cme_concept_id,
           cme_reason = v_cme_reason
     WHERE id = v_quiz_session_id;
  EXCEPTION WHEN OTHERS THEN
    NULL;
  END;

  RETURN jsonb_build_object(
    'total', v_total,
    'correct', v_correct,
    'score_percent', v_score_percent,
    'xp_earned', v_xp,
    'session_id', v_quiz_session_id,
    'flagged', v_flagged,
    'cme_next_action', v_cme_action,
    'cme_next_concept_id', v_cme_concept_id,
    'cme_reason', v_cme_reason,
    -- Per-question review payload — server is the single source of truth
    -- for correct_option_text. QuizResults.tsx must consume this, not
    -- derive from its own options array.
    'questions', v_review_questions
  );
END;
$$;
COMMENT ON FUNCTION "public"."submit_quiz_results_v2"("p_session_id" "uuid", "p_student_id" "uuid", "p_subject" "text", "p_grade" "text", "p_topic" "text", "p_chapter" integer, "p_responses" "jsonb", "p_time" integer) IS 'P0 fix (migration 20260428160000): the v2 quiz submission path. Reads shuffle + options + correct_answer_index from the per-session snapshot in quiz_session_shuffles, NOT from live question_bank. Mid-session content edits to question_bank.options can no longer corrupt scoring. Client sends only { question_id, selected_displayed_index, time_spent }; server re-derives is_correct, returns canonical correct_option_text per question for the review screen. P1/P2/P3/P4 invariants preserved verbatim from v1. Backwards compatible: v1 submit_quiz_results is untouched and still serves legacy + mobile clients.';




CREATE OR REPLACE FUNCTION "public"."sync_onboarding_completed"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  IF NEW.step = 'completed' AND (OLD.step IS NULL OR OLD.step != 'completed') THEN
    UPDATE students 
    SET onboarding_completed = true, updated_at = now()
    WHERE auth_user_id = NEW.auth_user_id;
  END IF;
  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."sync_rag_chunk_normalized_fields"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Sync subject_code from subjects table
  SELECT code INTO NEW.subject_code
  FROM public.subjects
  WHERE name = NEW.subject
  LIMIT 1;

  -- Sync grade_short
  NEW.grade_short := regexp_replace(NEW.grade, '^Grade\s+', '', 'i');

  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."sync_school_admin_role"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Add institution_admin role when school_admin is created
  INSERT INTO user_roles (auth_user_id, role_name)
  VALUES (NEW.auth_user_id, 'institution_admin')
  ON CONFLICT (auth_user_id, role_name) DO NOTHING;
  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."sync_user_roles_for_user"("p_auth_user_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_role_id UUID;
BEGIN
  IF EXISTS (SELECT 1 FROM students WHERE auth_user_id = p_auth_user_id AND is_active = true) THEN
    SELECT id INTO v_role_id FROM roles WHERE name = 'student' AND is_active = true;
    IF v_role_id IS NOT NULL THEN
      INSERT INTO user_roles (auth_user_id, role_id, is_active)
      VALUES (p_auth_user_id, v_role_id, true)
      ON CONFLICT (auth_user_id, role_id) DO NOTHING;
    END IF;
  END IF;

  IF EXISTS (SELECT 1 FROM teachers WHERE auth_user_id = p_auth_user_id) THEN
    SELECT id INTO v_role_id FROM roles WHERE name = 'teacher' AND is_active = true;
    IF v_role_id IS NOT NULL THEN
      INSERT INTO user_roles (auth_user_id, role_id, is_active)
      VALUES (p_auth_user_id, v_role_id, true)
      ON CONFLICT (auth_user_id, role_id) DO NOTHING;
    END IF;
  END IF;

  IF EXISTS (SELECT 1 FROM guardians WHERE auth_user_id = p_auth_user_id) THEN
    SELECT id INTO v_role_id FROM roles WHERE name = 'parent' AND is_active = true;
    IF v_role_id IS NOT NULL THEN
      INSERT INTO user_roles (auth_user_id, role_id, is_active)
      VALUES (p_auth_user_id, v_role_id, true)
      ON CONFLICT (auth_user_id, role_id) DO NOTHING;
    END IF;
  END IF;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."sync_user_roles_on_insert"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_role_name TEXT;
  v_auth_id UUID;
BEGIN
  v_auth_id := NEW.auth_user_id;
  IF v_auth_id IS NULL THEN RETURN NEW; END IF;

  IF TG_TABLE_NAME = 'students' THEN
    v_role_name := 'student';
  ELSIF TG_TABLE_NAME = 'teachers' THEN
    v_role_name := 'teacher';
  ELSIF TG_TABLE_NAME = 'guardians' THEN
    v_role_name := 'guardian';
  END IF;

  IF v_role_name IS NOT NULL THEN
    INSERT INTO user_roles (auth_user_id, role_id)
    SELECT v_auth_id, id FROM roles WHERE name = v_role_name
    ON CONFLICT DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."teacher_create_adaptive_assignment"("p_teacher_id" "uuid", "p_class_id" "uuid", "p_title" "text", "p_node_codes" "text"[], "p_due_date" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_question_count" integer DEFAULT 10, "p_bloom_level" "text" DEFAULT NULL::"text", "p_assignment_type" "text" DEFAULT 'practice'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$ DECLARE v_id uuid; v_grade text; v_subject text; BEGIN SELECT grade, subject INTO v_grade, v_subject FROM public.classes WHERE id = p_class_id; INSERT INTO public.assignments (class_id, teacher_id, title, assignment_type, subject, grade, due_date, question_count, bloom_level, status) VALUES (p_class_id, p_teacher_id, p_title, p_assignment_type, v_subject, v_grade, COALESCE(p_due_date, now() + interval '7 days'), p_question_count, p_bloom_level, 'active') RETURNING id INTO v_id; INSERT INTO public.assignment_submissions (assignment_id, student_id, status) SELECT v_id, cs.student_id, 'not_started' FROM public.class_students cs WHERE cs.class_id = p_class_id AND cs.is_active; INSERT INTO public.notifications (recipient_type, recipient_id, sender_type, sender_id, type, notification_type, title, message, body, data) SELECT 'student', cs.student_id, 'teacher', p_teacher_id, 'assignment_new', 'assignment_new', 'New: ' || p_title, 'New assignment', 'New assignment from teacher', jsonb_build_object('assignment_id', v_id, 'concepts', p_node_codes) FROM public.class_students cs WHERE cs.class_id = p_class_id AND cs.is_active; IF p_due_date IS NOT NULL THEN INSERT INTO public.assessment_schedule (student_id, assessment_type, subject, grade, concept_codes, scheduled_for, priority, reason) SELECT cs.student_id, 'mixed_recall', v_subject, v_grade, p_node_codes, p_due_date + interval '3 days', 'medium', 'Post-assignment review: ' || p_title FROM public.class_students cs WHERE cs.class_id = p_class_id AND cs.is_active ON CONFLICT DO NOTHING; END IF; RETURN jsonb_build_object('assignment_id', v_id, 'concepts', p_node_codes, 'students_assigned', (SELECT count(*) FROM public.class_students WHERE class_id = p_class_id AND is_active), 'due_date', COALESCE(p_due_date, now() + interval '7 days')); END; $$;


CREATE OR REPLACE FUNCTION "public"."teacher_create_assignment"("p_teacher_id" "uuid", "p_class_id" "uuid", "p_title" "text", "p_type" "text" DEFAULT 'practice'::"text", "p_topic_id" "uuid" DEFAULT NULL::"uuid", "p_subject" "text" DEFAULT NULL::"text", "p_due_date" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_question_count" integer DEFAULT 10) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$ DECLARE v_id uuid; v_grade text; BEGIN SELECT grade INTO v_grade FROM classes WHERE id = p_class_id; INSERT INTO assignments (class_id, teacher_id, title, assignment_type, topic_id, subject, grade, due_date, question_count) VALUES (p_class_id, p_teacher_id, p_title, p_type, p_topic_id, p_subject, v_grade, p_due_date, p_question_count) RETURNING id INTO v_id; INSERT INTO assignment_submissions (assignment_id, student_id, status) SELECT v_id, cs.student_id, 'not_started' FROM class_students cs WHERE cs.class_id = p_class_id AND cs.is_active; INSERT INTO notifications (recipient_type, recipient_id, sender_type, sender_id, type, notification_type, title, message, body, data) SELECT 'student', cs.student_id, 'teacher', p_teacher_id, 'assignment_new', 'assignment_new', 'New: ' || p_title, 'New assignment from your teacher', 'New assignment from your teacher', jsonb_build_object('assignment_id', v_id) FROM class_students cs WHERE cs.class_id = p_class_id AND cs.is_active; RETURN jsonb_build_object('assignment_id', v_id); END; $$;


CREATE OR REPLACE FUNCTION "public"."teacher_create_class"("p_teacher_id" "uuid", "p_name" "text", "p_grade" "text", "p_section" "text" DEFAULT NULL::"text", "p_subject" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$ DECLARE v_class_id uuid; v_code text; v_school_id uuid; BEGIN SELECT school_id INTO v_school_id FROM teachers WHERE id = p_teacher_id; INSERT INTO classes (school_id, name, grade, section, subject, created_by) VALUES (v_school_id, p_name, p_grade, p_section, p_subject, p_teacher_id) RETURNING id, class_code INTO v_class_id, v_code; INSERT INTO class_teachers (class_id, teacher_id, role) VALUES (v_class_id, p_teacher_id, 'teacher'); RETURN jsonb_build_object('class_id', v_class_id, 'class_code', v_code); END; $$;


CREATE OR REPLACE FUNCTION "public"."track_ai_quality"("p_subject" "text", "p_is_thumbs_up" boolean DEFAULT NULL::boolean, "p_is_report" boolean DEFAULT false) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ BEGIN INSERT INTO ai_quality_metrics (date, subject, total_responses, thumbs_up, thumbs_down, reported_errors) VALUES (CURRENT_DATE, p_subject, 1, CASE WHEN p_is_thumbs_up = true THEN 1 ELSE 0 END, CASE WHEN p_is_thumbs_up = false THEN 1 ELSE 0 END, CASE WHEN p_is_report = true THEN 1 ELSE 0 END) ON CONFLICT (date, subject) DO UPDATE SET total_responses = ai_quality_metrics.total_responses + 1, thumbs_up = ai_quality_metrics.thumbs_up + CASE WHEN p_is_thumbs_up = true THEN 1 ELSE 0 END, thumbs_down = ai_quality_metrics.thumbs_down + CASE WHEN p_is_thumbs_up = false THEN 1 ELSE 0 END, reported_errors = ai_quality_metrics.reported_errors + CASE WHEN p_is_report = true THEN 1 ELSE 0 END; END; $$;


CREATE OR REPLACE FUNCTION "public"."transition_content_status"("p_table" "text", "p_id" "uuid", "p_new_status" "text", "p_actor_id" "uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_status TEXT;
  v_valid BOOLEAN := false;
BEGIN
  -- Get current status
  IF p_table = 'curriculum_topics' THEN
    SELECT content_status INTO v_current_status FROM curriculum_topics WHERE id = p_id;
  ELSIF p_table = 'question_bank' THEN
    SELECT content_status INTO v_current_status FROM question_bank WHERE id = p_id;
  ELSE
    RAISE EXCEPTION 'Invalid table: %', p_table;
  END IF;

  IF v_current_status IS NULL THEN
    RAISE EXCEPTION 'Record not found: % %', p_table, p_id;
  END IF;

  -- Validate transition
  v_valid := CASE
    WHEN v_current_status = 'draft' AND p_new_status IN ('review', 'archived') THEN true
    WHEN v_current_status = 'review' AND p_new_status IN ('published', 'draft', 'archived') THEN true
    WHEN v_current_status = 'published' AND p_new_status IN ('archived', 'draft') THEN true
    WHEN v_current_status = 'archived' AND p_new_status = 'draft' THEN true
    ELSE false
  END;

  IF NOT v_valid THEN
    RAISE EXCEPTION 'Invalid transition: % -> %', v_current_status, p_new_status;
  END IF;

  -- Apply transition
  IF p_table = 'curriculum_topics' THEN
    UPDATE curriculum_topics SET
      content_status = p_new_status,
      updated_by = p_actor_id,
      updated_at = now(),
      reviewed_by = CASE WHEN p_new_status IN ('published','draft') AND v_current_status = 'review' THEN p_actor_id ELSE reviewed_by END,
      published_by = CASE WHEN p_new_status = 'published' THEN p_actor_id ELSE published_by END,
      published_at = CASE WHEN p_new_status = 'published' THEN now() ELSE published_at END,
      review_notes = COALESCE(p_notes, review_notes)
    WHERE id = p_id;
  ELSIF p_table = 'question_bank' THEN
    UPDATE question_bank SET
      content_status = p_new_status,
      updated_by = p_actor_id,
      updated_at = now(),
      reviewed_by = CASE WHEN p_new_status IN ('published','draft') AND v_current_status = 'review' THEN p_actor_id ELSE reviewed_by END,
      published_by = CASE WHEN p_new_status = 'published' THEN p_actor_id ELSE published_by END,
      published_at = CASE WHEN p_new_status = 'published' THEN now() ELSE published_at END,
      review_notes = COALESCE(p_notes, review_notes)
    WHERE id = p_id;
  END IF;

  RETURN true;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."trg_fn_quiz_session_affective_state"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only fire when session transitions to completed
  IF NEW.is_completed = true AND (OLD.is_completed = false OR OLD.is_completed IS NULL) THEN
    -- Per-session cognitive metrics
    PERFORM public.compute_session_cognitive_metrics(NEW.student_id, NEW.id);
    -- Student-level affective profile (boredom/frustration bands)
    PERFORM public.compute_student_affective_profile(NEW.student_id);
  END IF;
  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."trg_fn_update_irt_theta"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only run when we have the necessary columns populated
  IF NEW.student_id IS NOT NULL AND NEW.subject IS NOT NULL THEN
    PERFORM public.update_irt_theta(NEW.student_id, NEW.subject);
  END IF;
  RETURN NEW;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."trg_question_bank_recompute"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF TG_OP = 'UPDATE' AND
     OLD.verified_against_ncert IS NOT DISTINCT FROM NEW.verified_against_ncert AND
     OLD.deleted_at IS NOT DISTINCT FROM NEW.deleted_at THEN
    RETURN NEW;
  END IF;
  PERFORM recompute_syllabus_status(NEW.grade, NEW.subject, NEW.chapter_number);
  RETURN NEW;
END $$;


CREATE OR REPLACE FUNCTION "public"."trg_rag_chunks_recompute"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF TG_OP = 'DELETE' THEN
    PERFORM recompute_syllabus_status(OLD.grade_short, OLD.subject_code, OLD.chapter_number);
    RETURN OLD;
  ELSE
    PERFORM recompute_syllabus_status(NEW.grade_short, NEW.subject_code, NEW.chapter_number);
    IF TG_OP = 'UPDATE' AND (
      OLD.grade_short IS DISTINCT FROM NEW.grade_short OR
      OLD.subject_code IS DISTINCT FROM NEW.subject_code OR
      OLD.chapter_number IS DISTINCT FROM NEW.chapter_number
    ) THEN
      PERFORM recompute_syllabus_status(OLD.grade_short, OLD.subject_code, OLD.chapter_number);
    END IF;
    RETURN NEW;
  END IF;
END $$;


CREATE OR REPLACE FUNCTION "public"."update_bloom_progression_trigger"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$ DECLARE question_concept_id UUID; question_subject TEXT; question_bloom_level TEXT; BEGIN SELECT qb.concept_id, qb.subject, qb.bloom_level INTO question_concept_id, question_subject, question_bloom_level FROM question_bank qb WHERE qb.id = NEW.question_id; INSERT INTO bloom_progression (student_id, concept_id, subject) VALUES (NEW.student_id, question_concept_id, question_subject) ON CONFLICT (student_id, concept_id) DO NOTHING; UPDATE bloom_progression SET remember_mastery = CASE WHEN question_bloom_level = 'remember' THEN LEAST(1.0, remember_mastery + CASE WHEN NEW.is_correct THEN 0.1 ELSE -0.05 END) ELSE remember_mastery END, understand_mastery = CASE WHEN question_bloom_level = 'understand' THEN LEAST(1.0, understand_mastery + CASE WHEN NEW.is_correct THEN 0.1 ELSE -0.05 END) ELSE understand_mastery END, apply_mastery = CASE WHEN question_bloom_level = 'apply' THEN LEAST(1.0, apply_mastery + CASE WHEN NEW.is_correct THEN 0.1 ELSE -0.05 END) ELSE apply_mastery END, analyze_mastery = CASE WHEN question_bloom_level = 'analyze' THEN LEAST(1.0, analyze_mastery + CASE WHEN NEW.is_correct THEN 0.1 ELSE -0.05 END) ELSE analyze_mastery END, evaluate_mastery = CASE WHEN question_bloom_level = 'evaluate' THEN LEAST(1.0, evaluate_mastery + CASE WHEN NEW.is_correct THEN 0.1 ELSE -0.05 END) ELSE evaluate_mastery END, create_mastery = CASE WHEN question_bloom_level = 'create' THEN LEAST(1.0, create_mastery + CASE WHEN NEW.is_correct THEN 0.1 ELSE -0.05 END) ELSE create_mastery END, last_practiced_at = NEW.created_at, updated_at = NOW() WHERE student_id = NEW.student_id AND concept_id = question_concept_id; RETURN NEW; END; $$;


CREATE OR REPLACE FUNCTION "public"."update_burst_progress"("p_student_id" "uuid", "p_action_type" "text", "p_value" integer DEFAULT 1) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$ DECLARE v_completions jsonb := '[]'::jsonb; rec record; BEGIN FOR rec IN SELECT b.id, b.burst_type, b.goal_type, b.goal_value, b.reward_xp, b.reward_title, b.xp_multiplier, b.narrative_context, sp.id as progress_id, sp.current_value, sp.is_completed FROM public.gamification_bursts b LEFT JOIN public.student_burst_progress sp ON sp.burst_id = b.id AND sp.student_id = p_student_id WHERE b.status = 'active' LOOP IF rec.progress_id IS NULL THEN INSERT INTO public.student_burst_progress (student_id, burst_id, goal_value) VALUES (p_student_id, rec.id, rec.goal_value); UPDATE public.gamification_bursts SET participants_count = participants_count + 1 WHERE id = rec.id; rec.current_value := 0; rec.is_completed := false; END IF; IF rec.is_completed THEN CONTINUE; END IF; IF (rec.goal_type = 'questions' AND p_action_type = 'question_correct') OR (rec.goal_type = 'concepts' AND p_action_type = 'concept_mastered') OR (rec.goal_type = 'xp' AND p_action_type = 'xp_earned') OR (rec.goal_type = 'streak' AND p_action_type = 'session_complete') THEN UPDATE public.student_burst_progress SET current_value = current_value + p_value, xp_earned_during_burst = xp_earned_during_burst + CASE WHEN p_action_type = 'xp_earned' THEN p_value ELSE 0 END, last_activity_at = now(), is_completed = (current_value + p_value >= rec.goal_value), completed_at = CASE WHEN current_value + p_value >= rec.goal_value THEN now() ELSE NULL END WHERE student_id = p_student_id AND burst_id = rec.id; IF rec.current_value + p_value >= rec.goal_value THEN UPDATE public.students SET xp_total = COALESCE(xp_total, 0) + rec.reward_xp WHERE id = p_student_id; UPDATE public.gamification_bursts SET completions_count = completions_count + 1 WHERE id = rec.id; IF rec.reward_title IS NOT NULL THEN INSERT INTO public.student_titles (student_id, title, icon, tier, source, source_id) VALUES (p_student_id, rec.reward_title, '🏆', 'gold', 'burst', rec.id::text) ON CONFLICT DO NOTHING; END IF; INSERT INTO public.student_moments (student_id, moment_type, title, description, xp_awarded) VALUES (p_student_id, 'burst_complete', 'Burst Complete: ' || rec.reward_title, 'Completed the ' || rec.burst_type || ' challenge!', rec.reward_xp); v_completions := v_completions || jsonb_build_object('burst_id', rec.id, 'type', rec.burst_type, 'reward_title', rec.reward_title, 'reward_xp', rec.reward_xp); END IF; IF rec.burst_type IN ('mystery_solve','boss_battle','exploration') THEN INSERT INTO public.narrative_progress (student_id, burst_id, total_chapters) VALUES (p_student_id, rec.id, COALESCE((rec.narrative_context->>'total_chapters')::int, 5)) ON CONFLICT (student_id, burst_id) DO NOTHING; IF rec.burst_type = 'mystery_solve' THEN UPDATE public.narrative_progress SET clues_found = clues_found + 1, current_chapter = LEAST(total_chapters, 1 + (clues_found + 1) / 3), chapters_unlocked = LEAST(total_chapters, 1 + (clues_found + 1) / 3), updated_at = now() WHERE student_id = p_student_id AND burst_id = rec.id; ELSIF rec.burst_type = 'boss_battle' THEN UPDATE public.narrative_progress SET boss_hp_remaining = GREATEST(0, COALESCE(boss_hp_remaining, rec.goal_value) - p_value), updated_at = now() WHERE student_id = p_student_id AND burst_id = rec.id; ELSIF rec.burst_type = 'exploration' THEN UPDATE public.narrative_progress SET areas_explored = areas_explored + 1, current_chapter = LEAST(total_chapters, 1 + areas_explored / 2), chapters_unlocked = LEAST(total_chapters, 1 + areas_explored / 2), updated_at = now() WHERE student_id = p_student_id AND burst_id = rec.id; END IF; END IF; END IF; END LOOP; PERFORM public.check_and_award_achievements(p_student_id); RETURN jsonb_build_object('burst_completions', v_completions, 'count', jsonb_array_length(v_completions)); END; $$;


