CREATE OR REPLACE FUNCTION "public"."update_chapter_progress"("p_student_id" "uuid", "p_subject" "text", "p_grade" "text", "p_chapter_number" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_chapter_id UUID; v_unique_seen INTEGER := 0; v_total_in_chapter INTEGER := 0; v_attempted INTEGER := 0; v_correct INTEGER := 0; v_pool_coverage REAL := 0; v_accuracy REAL := 0; v_is_completed BOOLEAN := false; v_test_mode_unlocked BOOLEAN := false;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM students WHERE id = p_student_id AND auth_user_id = auth.uid()) THEN RAISE EXCEPTION 'Access denied'; END IF;
  SELECT c.id INTO v_chapter_id FROM chapters c JOIN subjects s ON s.id = c.subject_id WHERE s.code = p_subject AND c.grade = p_grade AND c.chapter_number = p_chapter_number AND c.is_active = true LIMIT 1;
  IF v_chapter_id IS NULL THEN RETURN; END IF;
  SELECT COUNT(DISTINCT h.question_id) INTO v_unique_seen FROM user_question_history h WHERE h.student_id = p_student_id AND h.subject = p_subject AND h.grade = p_grade AND h.chapter_number = p_chapter_number;
  SELECT COUNT(*) INTO v_total_in_chapter FROM question_bank qb WHERE qb.subject = p_subject AND qb.grade = p_grade AND qb.chapter_number = p_chapter_number AND qb.is_active = true;
  SELECT COUNT(*), COALESCE(SUM(CASE WHEN qr.is_correct THEN 1 ELSE 0 END), 0) INTO v_attempted, v_correct FROM quiz_responses qr JOIN question_bank qb ON qb.id = qr.question_id WHERE qr.student_id = p_student_id AND qb.subject = p_subject AND qb.grade = p_grade AND qb.chapter_number = p_chapter_number;
  IF v_total_in_chapter > 0 THEN v_pool_coverage := ROUND((v_unique_seen::REAL / v_total_in_chapter) * 100, 1); END IF;
  IF v_attempted > 0 THEN v_accuracy := ROUND((v_correct::REAL / v_attempted) * 100, 1); END IF;
  v_is_completed := (v_pool_coverage >= 80 AND v_accuracy >= 60);
  v_test_mode_unlocked := v_is_completed;
  INSERT INTO chapter_progress (student_id, chapter_id, subject, grade, chapter_number, questions_attempted, questions_correct, unique_questions_seen, total_questions_in_chapter, pool_coverage_percent, accuracy_percent, is_completed, test_mode_unlocked, completed_at, last_activity_at)
  VALUES (p_student_id, v_chapter_id, p_subject, p_grade, p_chapter_number, v_attempted, v_correct, v_unique_seen, v_total_in_chapter, v_pool_coverage, v_accuracy, v_is_completed, v_test_mode_unlocked, CASE WHEN v_is_completed THEN now() ELSE NULL END, now())
  ON CONFLICT (student_id, chapter_id) DO UPDATE SET questions_attempted = EXCLUDED.questions_attempted, questions_correct = EXCLUDED.questions_correct, unique_questions_seen = EXCLUDED.unique_questions_seen, total_questions_in_chapter = EXCLUDED.total_questions_in_chapter, pool_coverage_percent = EXCLUDED.pool_coverage_percent, accuracy_percent = EXCLUDED.accuracy_percent, is_completed = EXCLUDED.is_completed, test_mode_unlocked = EXCLUDED.test_mode_unlocked, completed_at = CASE WHEN EXCLUDED.is_completed AND chapter_progress.completed_at IS NULL THEN now() ELSE chapter_progress.completed_at END, last_activity_at = now();
END; $$;


