CREATE OR REPLACE FUNCTION "public"."update_concept_mastery"("p_student_id" "uuid", "p_topic_id" "uuid", "p_is_correct" boolean, "p_used_hint" boolean DEFAULT false) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$ DECLARE v_current_prob FLOAT; v_slip FLOAT := 0.1; v_guess FLOAT := 0.25; v_learn FLOAT := 0.1; v_new_prob FLOAT; v_new_level TEXT; BEGIN INSERT INTO public.concept_mastery (student_id, topic_id, first_attempted_at) VALUES (p_student_id, p_topic_id, NOW()) ON CONFLICT (student_id, topic_id) DO NOTHING; SELECT mastery_probability INTO v_current_prob FROM public.concept_mastery WHERE student_id = p_student_id AND topic_id = p_topic_id; IF p_is_correct THEN v_new_prob := (v_current_prob * (1 - v_slip)) / (v_current_prob * (1 - v_slip) + (1 - v_current_prob) * v_guess); ELSE v_new_prob := (v_current_prob * v_slip) / (v_current_prob * v_slip + (1 - v_current_prob) * (1 - v_guess)); END IF; v_new_prob := v_new_prob + (1 - v_new_prob) * v_learn; IF p_used_hint THEN v_new_prob := v_new_prob * 0.95; END IF; v_new_prob := GREATEST(0.01, LEAST(0.99, v_new_prob)); v_new_level := CASE WHEN v_new_prob >= 0.9 THEN 'mastered' WHEN v_new_prob >= 0.7 THEN 'proficient' WHEN v_new_prob >= 0.4 THEN 'developing' WHEN v_new_prob >= 0.15 THEN 'beginner' ELSE 'not_started' END; UPDATE public.concept_mastery SET mastery_probability = v_new_prob, mastery_level = v_new_level, attempts = attempts + 1, correct_attempts = correct_attempts + (CASE WHEN p_is_correct THEN 1 ELSE 0 END), hints_used = hints_used + (CASE WHEN p_used_hint THEN 1 ELSE 0 END), last_attempted_at = NOW(), mastered_at = CASE WHEN v_new_level = 'mastered' AND mastered_at IS NULL THEN NOW() ELSE mastered_at END WHERE student_id = p_student_id AND topic_id = p_topic_id; END; $$;


CREATE OR REPLACE FUNCTION "public"."update_concept_mastery_bkt"("p_student_id" "uuid", "p_topic_id" "uuid", "p_is_correct" boolean, "p_p_learn" double precision DEFAULT 0.2, "p_p_slip" double precision DEFAULT 0.1, "p_p_guess" double precision DEFAULT 0.25) RETURNS TABLE("new_mastery" double precision, "new_ease_factor" double precision, "new_review_interval" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_current_mastery FLOAT;
  v_ease_factor FLOAT;
  v_review_interval INT;
  v_total_attempts INT;
  v_correct_attempts INT;
  v_p_evidence FLOAT;
  v_p_know_given_evidence FLOAT;
  v_new_mastery FLOAT;
  v_new_ease FLOAT;
  v_new_interval INT;
  v_row_id UUID;
BEGIN
  SELECT cm.id, cm.mastery_level, cm.ease_factor, cm.review_interval,
         cm.total_attempts, cm.correct_attempts
  INTO v_row_id, v_current_mastery, v_ease_factor, v_review_interval,
       v_total_attempts, v_correct_attempts
  FROM concept_mastery cm
  WHERE cm.student_id = p_student_id AND cm.topic_id = p_topic_id
  FOR UPDATE;

  IF NOT FOUND THEN
    v_current_mastery := 0.1;
    v_ease_factor := 2.5;
    v_review_interval := 0;
    v_total_attempts := 0;
    v_correct_attempts := 0;
  END IF;

  IF p_is_correct THEN
    v_p_evidence := v_current_mastery * (1.0 - p_p_slip) + (1.0 - v_current_mastery) * p_p_guess;
    v_p_know_given_evidence := (v_current_mastery * (1.0 - p_p_slip)) / v_p_evidence;
  ELSE
    v_p_evidence := v_current_mastery * p_p_slip + (1.0 - v_current_mastery) * (1.0 - p_p_guess);
    v_p_know_given_evidence := (v_current_mastery * p_p_slip) / v_p_evidence;
  END IF;

  v_new_mastery := LEAST(1.0, GREATEST(0.0,
    v_p_know_given_evidence + (1.0 - v_p_know_given_evidence) * p_p_learn
  ));

  IF p_is_correct THEN
    v_new_ease := LEAST(3.0, v_ease_factor + 0.1);
  ELSE
    v_new_ease := GREATEST(1.3, v_ease_factor - 0.2);
  END IF;

  IF NOT p_is_correct THEN
    v_new_interval := 1;
  ELSIF v_review_interval = 0 THEN
    v_new_interval := 1;
  ELSIF v_review_interval = 1 THEN
    v_new_interval := 6;
  ELSE
    v_new_interval := ROUND(v_review_interval * v_new_ease)::INT;
  END IF;

  INSERT INTO concept_mastery (
    student_id, topic_id, mastery_level, ease_factor, review_interval,
    last_reviewed_at, next_review_at, total_attempts, correct_attempts, updated_at
  ) VALUES (
    p_student_id, p_topic_id, v_new_mastery, v_new_ease, v_new_interval,
    now(), now() + (v_new_interval || ' days')::INTERVAL,
    v_total_attempts + 1,
    v_correct_attempts + CASE WHEN p_is_correct THEN 1 ELSE 0 END,
    now()
  )
  ON CONFLICT (student_id, topic_id) DO UPDATE SET
    mastery_level = EXCLUDED.mastery_level,
    ease_factor = EXCLUDED.ease_factor,
    review_interval = EXCLUDED.review_interval,
    last_reviewed_at = EXCLUDED.last_reviewed_at,
    next_review_at = EXCLUDED.next_review_at,
    total_attempts = EXCLUDED.total_attempts,
    correct_attempts = EXCLUDED.correct_attempts,
    updated_at = EXCLUDED.updated_at;

  new_mastery := v_new_mastery;
  new_ease_factor := v_new_ease;
  new_review_interval := v_new_interval;
  RETURN NEXT;
END;
$$;


