CREATE OR REPLACE FUNCTION "public"."update_irt_theta"("p_student_id" "uuid", "p_subject" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_theta        double precision := 0.0;
  v_theta_prev   double precision;
  v_fisher_info  double precision := 0.0;
  v_l_prime      double precision;
  v_l_double     double precision;
  v_p            double precision;
  v_se           double precision;
  v_opt_diff     integer;
  v_iter         integer;
  v_n            integer;
  v_existing_slp uuid;
  v_existing_ap  uuid;

  -- Single-pass aggregate from JOIN
  v_responses RECORD;
BEGIN

  -- ── Collect responses ──────────────────────────────────────────────────────
  -- Count valid responses (need b-parameter from question_bank)
  SELECT COUNT(*)::integer INTO v_n
  FROM quiz_responses qr
  JOIN question_bank qb ON qb.id = qr.question_id
  WHERE qr.student_id = p_student_id
    AND qr.subject    = p_subject
    AND qb.irt_difficulty IS NOT NULL;

  -- Not enough data — need at least 2 responses for stable estimation
  IF v_n < 2 THEN
    RETURN;
  END IF;

  -- ── Newton-Raphson: 5 iterations ──────────────────────────────────────────
  FOR v_iter IN 1..5 LOOP
    v_l_prime  := 0.0;
    v_l_double := 0.0;

    FOR v_responses IN
      SELECT qb.irt_difficulty AS b,
             (CASE WHEN qr.is_correct THEN 1.0 ELSE 0.0 END) AS x
      FROM quiz_responses qr
      JOIN question_bank qb ON qb.id = qr.question_id
      WHERE qr.student_id = p_student_id
        AND qr.subject    = p_subject
        AND qb.irt_difficulty IS NOT NULL
    LOOP
      -- Rasch ICC: P(theta, b) = 1/(1+exp(-(theta-b)))
      v_p := 1.0 / (1.0 + exp(-(v_theta - v_responses.b)));

      -- Clamp P away from 0/1 to prevent divide-by-zero in L''
      v_p := GREATEST(0.0001, LEAST(0.9999, v_p));

      v_l_prime  := v_l_prime  + (v_responses.x - v_p);
      v_l_double := v_l_double - (v_p * (1.0 - v_p));       -- always negative
    END LOOP;

    -- Guard: if L'' is near zero, stop iterating
    IF ABS(v_l_double) < 1e-8 THEN
      EXIT;
    END IF;

    v_theta_prev := v_theta;
    v_theta := v_theta - (v_l_prime / v_l_double);

    -- Clamp theta to valid IRT range
    v_theta := GREATEST(-4.0, LEAST(4.0, v_theta));

    -- Convergence check (< 0.001 change)
    IF ABS(v_theta - v_theta_prev) < 0.001 THEN
      EXIT;
    END IF;
  END LOOP;

  -- ── Compute SE = 1/sqrt(Fisher information = Σ P_i*(1-P_i)) ──────────────
  v_fisher_info := 0.0;
  FOR v_responses IN
    SELECT qb.irt_difficulty AS b
    FROM quiz_responses qr
    JOIN question_bank qb ON qb.id = qr.question_id
    WHERE qr.student_id = p_student_id
      AND qr.subject    = p_subject
      AND qb.irt_difficulty IS NOT NULL
  LOOP
    v_p := 1.0 / (1.0 + exp(-(v_theta - v_responses.b)));
    v_p := GREATEST(0.0001, LEAST(0.9999, v_p));
    v_fisher_info := v_fisher_info + (v_p * (1.0 - v_p));
  END LOOP;

  v_se := CASE WHEN v_fisher_info > 0 THEN 1.0 / sqrt(v_fisher_info) ELSE 9.99 END;
  -- Cap SE at 9.99 (unreliable estimate indicator)
  v_se := LEAST(9.99, v_se);

  -- ── Upsert student_learning_profiles ──────────────────────────────────────
  -- Check for existing unique constraint on (student_id, subject)
  SELECT id INTO v_existing_slp
  FROM student_learning_profiles
  WHERE student_id = p_student_id AND subject = p_subject
  LIMIT 1;

  IF v_existing_slp IS NOT NULL THEN
    UPDATE student_learning_profiles
    SET irt_theta    = v_theta,
        irt_theta_se = v_se,
        updated_at   = now()
    WHERE student_id = p_student_id AND subject = p_subject;
  ELSE
    INSERT INTO student_learning_profiles (id, student_id, subject, irt_theta, irt_theta_se, updated_at)
    VALUES (gen_random_uuid(), p_student_id, p_subject, v_theta, v_se, now());
  END IF;

  -- ── Update adaptive_profile.optimal_difficulty ─────────────────────────────
  -- Map theta range → difficulty integer (1=easy, 2=medium, 3=hard)
  v_opt_diff := CASE
    WHEN v_theta < -1.0 THEN 1
    WHEN v_theta < 1.0  THEN 2
    ELSE                     3
  END;

  -- adaptive_profile is per-student (no subject), update only if row exists
  SELECT id INTO v_existing_ap
  FROM adaptive_profile
  WHERE student_id = p_student_id
  LIMIT 1;

  IF v_existing_ap IS NOT NULL THEN
    UPDATE adaptive_profile
    SET optimal_difficulty = v_opt_diff,
        updated_at         = now()
    WHERE student_id = p_student_id;
  ELSE
    INSERT INTO adaptive_profile (id, student_id, optimal_difficulty, updated_at)
    VALUES (gen_random_uuid(), p_student_id, v_opt_diff, now());
  END IF;

END;
$$;


