CREATE OR REPLACE FUNCTION "public"."update_mastery_bkt"("p_student_id" "uuid", "p_topic_id" "uuid", "p_is_correct" boolean) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$ DECLARE v_rec RECORD; v_p_know double precision; v_p_correct double precision; v_new_mastery text; BEGIN SELECT * INTO v_rec FROM concept_mastery WHERE student_id = p_student_id AND topic_id = p_topic_id; IF NOT FOUND THEN INSERT INTO concept_mastery (student_id, topic_id, mastery_level, mastery_probability, p_know, p_learn, p_guess, p_slip, attempts, correct_attempts, consecutive_correct, ease_factor, review_interval_days, first_attempted_at, last_attempted_at, next_review_at) VALUES (p_student_id, p_topic_id, 'developing', 0.1, 0.1, 0.2, 0.25, 0.1, 0, 0, 0, 2.5, 1, now(), now(), now() + interval '1 day') RETURNING * INTO v_rec; END IF; IF p_is_correct THEN v_p_correct := (1 - v_rec.p_slip) * v_rec.p_know + v_rec.p_guess * (1 - v_rec.p_know); v_p_know := ((1 - v_rec.p_slip) * v_rec.p_know) / v_p_correct; ELSE v_p_correct := v_rec.p_slip * v_rec.p_know + (1 - v_rec.p_guess) * (1 - v_rec.p_know); v_p_know := (v_rec.p_slip * v_rec.p_know) / v_p_correct; END IF; v_p_know := v_p_know + (1 - v_p_know) * v_rec.p_learn; IF v_p_know >= 0.95 THEN v_new_mastery := 'mastered'; ELSIF v_p_know >= 0.75 THEN v_new_mastery := 'proficient'; ELSIF v_p_know >= 0.50 THEN v_new_mastery := 'familiar'; ELSIF v_p_know >= 0.20 THEN v_new_mastery := 'developing'; ELSE v_new_mastery := 'not_started'; END IF; UPDATE concept_mastery SET mastery_probability = v_p_know, p_know = v_p_know, mastery_level = v_new_mastery, attempts = attempts + 1, correct_attempts = correct_attempts + CASE WHEN p_is_correct THEN 1 ELSE 0 END, consecutive_correct = CASE WHEN p_is_correct THEN consecutive_correct + 1 ELSE 0 END, last_attempted_at = now(), mastered_at = CASE WHEN v_new_mastery = 'mastered' AND mastered_at IS NULL THEN now() ELSE mastered_at END, ease_factor = GREATEST(1.3, ease_factor + CASE WHEN p_is_correct THEN 0.1 ELSE -0.3 END), review_interval_days = CASE WHEN p_is_correct AND consecutive_correct = 0 THEN 1 WHEN p_is_correct AND consecutive_correct = 1 THEN 3 WHEN p_is_correct THEN LEAST(180, ROUND(review_interval_days * ease_factor)) ELSE 1 END, next_review_at = now() + (CASE WHEN p_is_correct AND consecutive_correct >= 2 THEN LEAST(180, ROUND(review_interval_days * ease_factor)) WHEN p_is_correct THEN 3 ELSE 1 END || ' days')::interval, updated_at = now() WHERE id = v_rec.id; RETURN jsonb_build_object('mastery_level', v_new_mastery, 'mastery_probability', ROUND(v_p_know::numeric, 3), 'next_review', (now() + (CASE WHEN p_is_correct THEN 3 ELSE 1 END || ' days')::interval)); END; $$;


CREATE OR REPLACE FUNCTION "public"."update_ncert_chapter_progress"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO student_ncert_chapter_progress
    (student_id, subject, grade, chapter_number, attempted, correct, total_marks, earned_marks, last_attempted)
  VALUES (
    NEW.student_id, NEW.subject, NEW.grade, NEW.chapter_number,
    1, CASE WHEN NEW.is_correct THEN 1 ELSE 0 END,
    COALESCE(NEW.marks_possible,1), COALESCE(NEW.marks_awarded,0), NEW.created_at
  )
  ON CONFLICT (student_id, subject, grade, chapter_number) DO UPDATE SET
    attempted     = student_ncert_chapter_progress.attempted + 1,
    correct       = student_ncert_chapter_progress.correct + CASE WHEN NEW.is_correct THEN 1 ELSE 0 END,
    total_marks   = student_ncert_chapter_progress.total_marks + COALESCE(NEW.marks_possible,1),
    earned_marks  = student_ncert_chapter_progress.earned_marks + COALESCE(NEW.marks_awarded,0),
    last_attempted = NEW.created_at;
  RETURN NEW;
END;
$$;


