CREATE OR REPLACE FUNCTION "public"."update_sm2_parameters"("current_ease_factor" numeric, "current_interval" integer, "current_repetitions" integer, "quality" integer) RETURNS TABLE("new_ease_factor" numeric, "new_interval" integer, "new_repetitions" integer)
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$ DECLARE new_ef NUMERIC; new_int INTEGER; new_rep INTEGER; BEGIN IF quality >= 3 THEN IF current_repetitions = 0 THEN new_int := 1; ELSIF current_repetitions = 1 THEN new_int := 6; ELSE new_int := ROUND(current_interval * current_ease_factor); END IF; new_rep := current_repetitions + 1; new_ef := current_ease_factor + (0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02)); IF new_ef < 1.3 THEN new_ef := 1.3; END IF; ELSE new_rep := 0; new_int := 1; new_ef := current_ease_factor; END IF; RETURN QUERY SELECT new_ef, new_int, new_rep; END; $$;


CREATE OR REPLACE FUNCTION "public"."update_streak"("p_student_id" "uuid", "p_subject" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO ''
    AS $$ DECLARE v_last_session TIMESTAMPTZ; v_streak INTEGER; BEGIN SELECT last_session_at, streak_days INTO v_last_session, v_streak FROM public.student_learning_profiles WHERE student_id = p_student_id AND subject = p_subject; IF v_last_session IS NULL OR v_last_session < NOW() - INTERVAL '2 days' THEN UPDATE public.student_learning_profiles SET streak_days = 1 WHERE student_id = p_student_id AND subject = p_subject; ELSIF v_last_session < NOW() - INTERVAL '1 day' THEN UPDATE public.student_learning_profiles SET streak_days = streak_days + 1, longest_streak = GREATEST(longest_streak, streak_days + 1) WHERE student_id = p_student_id AND subject = p_subject; END IF; END; $$;


