CREATE OR REPLACE FUNCTION "public"."upsert_content_gap"("p_subject" "text", "p_grade" "text", "p_query" "text", "p_topic_title" "text" DEFAULT 'unknown'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO content_gaps (subject, grade, query, topic_title)
  VALUES (p_subject, p_grade, left(p_query, 200), p_topic_title)
  ON CONFLICT (subject, grade, query)
  DO UPDATE SET
    hit_count = content_gaps.hit_count + 1,
    last_seen_at = now(),
    topic_title = COALESCE(NULLIF(p_topic_title, 'unknown'), content_gaps.topic_title);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."validate_academic_scope"("p_student_id" "uuid", "p_grade" "text", "p_subject" "text", "p_chapter_number" integer DEFAULT NULL::integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_student_id    UUID;
  v_student_grade TEXT;
  v_subject_ok    BOOLEAN;
  v_chapter_ok    BOOLEAN;
BEGIN
  SELECT id, grade INTO v_student_id, v_student_grade
    FROM students
   WHERE id = p_student_id OR auth_user_id = p_student_id
   LIMIT 1;

  IF v_student_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'student_not_found');
  END IF;

  IF v_student_grade <> p_grade THEN
    RETURN jsonb_build_object(
      'ok', false, 'reason', 'grade_mismatch',
      'student_grade', v_student_grade, 'requested_grade', p_grade
    );
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM get_available_subjects(v_student_id) gas
     WHERE gas.code = p_subject AND NOT gas.is_locked
  ) INTO v_subject_ok;

  IF NOT v_subject_ok THEN
    RETURN jsonb_build_object(
      'ok', false, 'reason', 'subject_not_allowed', 'subject', p_subject
    );
  END IF;

  IF p_chapter_number IS NOT NULL THEN
    SELECT EXISTS (
      SELECT 1 FROM chapters c
       WHERE c.subject_code = p_subject
         AND c.grade = p_grade
         AND c.chapter_number = p_chapter_number
         AND c.is_active
    ) INTO v_chapter_ok;

    IF NOT v_chapter_ok THEN
      RETURN jsonb_build_object(
        'ok', false, 'reason', 'chapter_not_in_subject',
        'subject', p_subject, 'grade', p_grade, 'chapter_number', p_chapter_number
      );
    END IF;
  END IF;

  RETURN jsonb_build_object('ok', true);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."write_foxy_cache"("p_q" "text", "p_resp" "text", "p_grade" "text", "p_subject" "text", "p_ch" integer DEFAULT NULL::integer, "p_topic" "text" DEFAULT NULL::"text", "p_model" "text" DEFAULT 'claude-sonnet-4-20250514'::"text", "p_lang" "text" DEFAULT 'en'::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ BEGIN INSERT INTO foxy_response_cache (cache_key,grade,subject,chapter_number,topic,question_pattern,response_text,model_used,language,expires_at) VALUES (md5(lower(trim(regexp_replace(p_q,'[^a-zA-Z0-9\s]','','g')))),p_grade,p_subject,p_ch,p_topic,p_q,p_resp,p_model,p_lang,now()+interval '30 days') ON CONFLICT (cache_key) DO UPDATE SET response_text=EXCLUDED.response_text,expires_at=now()+interval '30 days',is_active=true; END; $$;


CREATE OR REPLACE FUNCTION "public"."check_foxy_quota"("p_student_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN (SELECT check_plan_limits(p_student_id, 'foxy_chat'));
END;
