CREATE OR REPLACE FUNCTION "public"."claim_verification_batch"("p_batch_size" integer, "p_claimed_by" "text", "p_claim_ttl_seconds" integer) RETURNS SETOF "public"."question_bank"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY WITH "_dml" AS (UPDATE question_bank
  SET verification_state = 'pending',
      verification_claimed_by = p_claimed_by,
      verification_claim_expires_at = now() + (p_claim_ttl_seconds || ' seconds')::interval
  WHERE id IN (
    SELECT id FROM question_bank
    WHERE verification_state = 'legacy_unverified'
       OR (verification_state = 'pending'
           AND verification_claim_expires_at < now())
    ORDER BY created_at ASC
    LIMIT p_batch_size
    FOR UPDATE SKIP LOCKED
  )
  RETURNING *) SELECT * FROM "_dml";
END;
$$;


