CREATE OR REPLACE FUNCTION "public"."distinct_chapter_tuples_from_bank"() RETURNS TABLE("grade" "text", "subject_code" "text", "chapter_number" integer, "chapter_title" "text", "subject_display" "text")
    LANGUAGE "plpgsql" STABLE
    AS $$
BEGIN
  RETURN QUERY SELECT DISTINCT
    grade,
    subject AS subject_code,
    chapter_number,
    NULL::text AS chapter_title,
    subject AS subject_display
  FROM question_bank
  WHERE grade IS NOT NULL
    AND subject IS NOT NULL
    AND chapter_number IS NOT NULL;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."distinct_chapter_tuples_from_chunks"() RETURNS TABLE("grade" "text", "subject_code" "text", "chapter_number" integer, "chapter_title" "text", "subject_display" "text")
    LANGUAGE "plpgsql" STABLE
    AS $$
BEGIN
  RETURN QUERY SELECT DISTINCT
    grade_short AS grade,
    subject_code,
    chapter_number,
    NULL::text AS chapter_title,
    subject_code AS subject_display
  FROM rag_content_chunks
  WHERE grade_short IS NOT NULL
    AND subject_code IS NOT NULL
    AND chapter_number IS NOT NULL;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."fast_rag_search_v2"("query_text" "text", "p_subject" "text", "p_grade" "text", "match_count" integer DEFAULT 5, "p_chapter" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "content" "text", "chapter_title" "text", "topic" "text", "concept" "text", "similarity" double precision)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
BEGIN
  RETURN QUERY WITH normalized AS (
    SELECT
      CASE lower(trim(p_subject))
        WHEN 'math' THEN 'Mathematics' WHEN 'mathematics' THEN 'Mathematics' WHEN 'maths' THEN 'Mathematics'
        WHEN 'science' THEN 'Science' WHEN 'physics' THEN 'Physics' WHEN 'chemistry' THEN 'Chemistry'
        WHEN 'biology' THEN 'Biology' WHEN 'english' THEN 'English' WHEN 'hindi' THEN 'Hindi'
        WHEN 'sanskrit' THEN 'Sanskrit' WHEN 'social_studies' THEN 'Social Studies'
        WHEN 'social studies' THEN 'Social Studies' WHEN 'computer_science' THEN 'Computer Science'
        WHEN 'computer science' THEN 'Computer Science' WHEN 'coding' THEN 'Computer Science'
        WHEN 'informatics_practices' THEN 'Informatics Practices'
        WHEN 'economics' THEN 'Economics' WHEN 'accountancy' THEN 'Accountancy'
        WHEN 'political_science' THEN 'Political Science' WHEN 'history' THEN 'History'
        WHEN 'geography' THEN 'Geography'
        ELSE initcap(replace(trim(p_subject), '_', ' '))
      END AS subj,
      CASE
        WHEN p_grade ~ '^\d+$' THEN 'Grade ' || p_grade
        WHEN p_grade ILIKE 'grade%' THEN 'Grade ' || regexp_replace(p_grade, '[^0-9]', '', 'g')
        ELSE p_grade
      END AS grd
  ),
  seed AS (
    SELECT c.embedding
    FROM rag_content_chunks c, normalized n
    WHERE c.is_active = true AND c.embedding IS NOT NULL
      AND c.subject = n.subj AND c.grade = n.grd
      AND c.search_vector @@ plainto_tsquery('english', query_text)
      AND (p_chapter IS NULL OR c.chapter_title ILIKE '%' || p_chapter || '%')
    ORDER BY ts_rank(c.search_vector, plainto_tsquery('english', query_text)) DESC
    LIMIT 1
  )
  SELECT c.id, c.chunk_text, c.chapter_title, c.topic, c.concept,
    (1 - (c.embedding <=> s.embedding))::FLOAT AS similarity
  FROM rag_content_chunks c, normalized n, seed s
  WHERE c.is_active = true AND c.embedding IS NOT NULL
    AND c.subject = n.subj AND c.grade = n.grd
    AND (p_chapter IS NULL OR c.chapter_title ILIKE '%' || p_chapter || '%')
  ORDER BY c.embedding <=> s.embedding
  LIMIT match_count;
END;
$_$;


