CREATE OR REPLACE FUNCTION "public"."get_exercise_completion"("p_student_id" "uuid", "p_subject_code" "text", "p_grade" "text") RETURNS TABLE("chapter_number" integer, "exercise_id" "text", "total_exercises" bigint, "attempted" bigint, "best_total_marks" numeric, "max_possible_marks" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY SELECT
    ne.chapter_number,
    ne.exercise_id,
    count(DISTINCT ne.id) AS total_exercises,
    count(DISTINCT sna.exercise_id) AS attempted,
    coalesce(sum(best.best_marks), 0) AS best_total_marks,
    coalesce(sum(ne.marks), 0) AS max_possible_marks
  FROM ncert_exercises ne
  LEFT JOIN (
    SELECT DISTINCT ON (exercise_id)
      exercise_id, marks_awarded AS best_marks
    FROM student_ncert_attempts
    WHERE student_id = p_student_id
    ORDER BY exercise_id, marks_awarded DESC
  ) best ON best.exercise_id = ne.id
  LEFT JOIN student_ncert_attempts sna
    ON sna.exercise_id = ne.id AND sna.student_id = p_student_id
  WHERE ne.subject_code = p_subject_code
    AND ne.grade = p_grade
    AND ne.is_active = true
  GROUP BY ne.chapter_number, ne.exercise_id
  ORDER BY ne.chapter_number, ne.exercise_id;
END;
$$;


