END;
$$;


CREATE OR REPLACE FUNCTION "public"."is_guardian_of"("p_student_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN (SELECT EXISTS (
    SELECT 1 FROM guardian_student_links gsl
    JOIN guardians g ON g.id = gsl.guardian_id
    WHERE gsl.student_id = p_student_id
      AND g.auth_user_id = auth.uid()
      AND gsl.status IN ('active', 'approved')
  ));
END;
$$;


CREATE OR REPLACE FUNCTION "public"."is_school_admin_of"("p_school_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN (SELECT EXISTS (
    SELECT 1 FROM school_admins sa
    WHERE sa.school_id = p_school_id
      AND sa.auth_user_id = auth.uid()
      AND sa.is_active = true
  ));
END;
$$;


CREATE OR REPLACE FUNCTION "public"."is_teacher_of"("p_student_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN (SELECT EXISTS(
    SELECT 1
    FROM class_students cs
    JOIN class_teachers ct ON ct.class_id = cs.class_id
    JOIN teachers t ON t.id = ct.teacher_id
    WHERE cs.student_id = p_student_id
      AND t.auth_user_id = auth.uid()
      AND cs.is_active = true
      AND ct.is_active = true
  ));
END;
$$;


CREATE OR REPLACE FUNCTION "public"."normalize_grade"("p_grade" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $_$
BEGIN
  RETURN (SELECT CASE
    WHEN p_grade ~* '^grade\s*\d+$' THEN 'Grade ' || regexp_replace(p_grade, '[^0-9]', '', 'g')
    WHEN p_grade ~ '^\d+$'          THEN 'Grade ' || p_grade
    ELSE p_grade
  END);
END;
$_$;


CREATE OR REPLACE FUNCTION "public"."purge_old_grounded_traces"() RETURNS "void"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  DELETE FROM grounded_ai_traces
    WHERE grounded = true AND created_at < now() - INTERVAL '90 days';
  DELETE FROM grounded_ai_traces
    WHERE grounded = false AND created_at < now() - INTERVAL '180 days';
END;
$$;


CREATE OR REPLACE FUNCTION "public"."quiz_grounding_check"("p_grade" "text", "p_subject" "text", "p_chapter_num" integer, "p_question_text" "text") RETURNS TABLE("is_safe" boolean, "supporting_chunks" integer, "verdict" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY SELECT
    (COUNT(*) >= 1)::boolean,
    COUNT(*)::integer,
    CASE WHEN COUNT(*) >= 1
      THEN 'VERIFIED: Question has NCERT source support'
      ELSE 'BLOCKED: No NCERT content found for this question'
    END
  FROM rag_content_chunks rc
  WHERE rc.grade          = p_grade
    AND rc.subject        = p_subject
    AND rc.chapter_number = p_chapter_num
    AND rc.is_active      = true
    AND rc.search_vector @@ websearch_to_tsquery('english', p_question_text);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."rag_resolve_chapter"("p_grade" "text", "p_subject" "text", "p_query" "text") RETURNS TABLE("chapter_number" integer, "chapter_title" "text", "match_score" real)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY WITH ranked AS (
    SELECT
      rc.chapter_number,
      rc.chapter_title,
      SUM(ts_rank(rc.search_vector, websearch_to_tsquery('english', p_query))) AS total_score
    FROM rag_content_chunks rc
    WHERE rc.grade   = p_grade
      AND rc.subject = p_subject
      AND rc.is_active = true
      AND rc.search_vector @@ websearch_to_tsquery('english', p_query)
    GROUP BY rc.chapter_number, rc.chapter_title
  )
  SELECT chapter_number, chapter_title, total_score::real AS match_score
  FROM ranked
  ORDER BY total_score DESC
  LIMIT 3;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."reconcile_stuck_payments"() RETURNS TABLE("payment_id" "text", "razorpay_order_id" "text", "student_id" "uuid", "student_name" "text", "student_email" "text", "paid_plan" "text", "current_plan" "text", "sub_plan" "text", "payment_date" timestamp with time zone, "needs_fix" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY SELECT 
    ph.razorpay_payment_id as payment_id,
    ph.razorpay_order_id,
    ph.student_id,
    s.name as student_name,
    s.email as student_email,
    ph.plan_code as paid_plan,
    s.subscription_plan as current_plan,
    ss.plan_code as sub_plan,
    ph.created_at as payment_date,
    (s.subscription_plan IS DISTINCT FROM ph.plan_code) as needs_fix
  FROM payment_history ph
  JOIN students s ON s.id = ph.student_id
  LEFT JOIN student_subscriptions ss ON ss.student_id = ph.student_id
  WHERE ph.status = 'captured'
    AND ph.razorpay_payment_id IS NOT NULL
  ORDER BY ph.created_at DESC;
END;
$$;


CREATE OR REPLACE FUNCTION "public"."severity_rank"("sev" "text") RETURNS integer
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
BEGIN
  RETURN (SELECT CASE sev WHEN 'info' THEN 1 WHEN 'warning' THEN 2 WHEN 'error' THEN 3 WHEN 'critical' THEN 4 ELSE 0 END);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."subject_code_to_rag_name"("p_code" "text") RETURNS "text"
    LANGUAGE "plpgsql" IMMUTABLE
    AS $$
BEGIN
  RETURN (SELECT CASE lower(p_code)
    WHEN 'math'                  THEN 'Mathematics'
    WHEN 'mathematics'           THEN 'Mathematics'
    WHEN 'science'               THEN 'Science'
    WHEN 'physics'               THEN 'Physics'
    WHEN 'chemistry'             THEN 'Chemistry'
    WHEN 'biology'               THEN 'Biology'
    WHEN 'english'               THEN 'English'
    WHEN 'hindi'                 THEN 'Hindi'
    WHEN 'social_studies'        THEN 'Social Studies'
    WHEN 'socialstudies'         THEN 'Social Studies'
    WHEN 'social studies'        THEN 'Social Studies'
    WHEN 'sanskrit'              THEN 'Sanskrit'
    WHEN 'computer_science'      THEN 'Computer Science'
    WHEN 'computerscience'       THEN 'Computer Science'
    WHEN 'computer science'      THEN 'Computer Science'
    WHEN 'informatics_practices' THEN 'Informatics Practices'
    WHEN 'informatics practices' THEN 'Informatics Practices'
    WHEN 'economics'             THEN 'Economics'
    ELSE initcap(replace(p_code,'_',' '))
  END);
END;
$$;


CREATE OR REPLACE FUNCTION "public"."total_questions_in_chapter"("p_grade" "text", "p_subject_code" "text", "p_chapter_number" integer) RETURNS integer
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN (SELECT count(*)::int FROM question_bank
  WHERE grade = p_grade
    AND subject = p_subject_code
    AND chapter_number = p_chapter_number
    AND deleted_at IS NULL);
END;
$$;


