CREATE OR REPLACE VIEW "public"."admin_question_verification_status" WITH ("security_invoker"='true') AS
 WITH "sample_ids" AS (
         SELECT "question_bank"."subject",
            "question_bank"."grade",
            "question_bank"."chapter_number",
            "array_agg"("question_bank"."id" ORDER BY "question_bank"."created_at") AS "all_ids"
           FROM "public"."question_bank"
          WHERE ("question_bank"."is_active" = true)
          GROUP BY "question_bank"."subject", "question_bank"."grade", "question_bank"."chapter_number"
        )
 SELECT "qb"."subject",
    "qb"."grade",
    "qb"."chapter_number",
    "count"(*) AS "total_questions",
    "count"(*) FILTER (WHERE ("qb"."is_verified" = true)) AS "verified_count",
    "count"(*) FILTER (WHERE (("qb"."is_verified" IS NULL) OR ("qb"."is_verified" = false))) AS "unverified_count",
    "round"(((100.0 * ("count"(*) FILTER (WHERE ("qb"."is_verified" = true)))::numeric) / (NULLIF("count"(*), 0))::numeric), 1) AS "verified_pct",
    "round"(("avg"("qb"."irt_difficulty"))::numeric, 3) AS "avg_irt_difficulty",
    "round"("avg"("qb"."difficulty"), 1) AS "avg_difficulty_int",
    "bool_or"(("cg"."concept_code" IS NOT NULL)) AS "has_real_concept_node",
    "si"."all_ids"[1:3] AS "sample_question_ids"
   FROM (("public"."question_bank" "qb"
     LEFT JOIN "public"."concept_graph" "cg" ON ((("cg"."subject" = "qb"."subject") AND ("cg"."grade" = "qb"."grade") AND ("cg"."chapter_number" = "qb"."chapter_number") AND ("cg"."is_active" = true))))
     LEFT JOIN "sample_ids" "si" ON ((("si"."subject" = "qb"."subject") AND ("si"."grade" = "qb"."grade") AND ("si"."chapter_number" = "qb"."chapter_number"))))
  WHERE ("qb"."is_active" = true)
  GROUP BY "qb"."subject", "qb"."grade", "qb"."chapter_number", "si"."all_ids"
  ORDER BY "qb"."subject", "qb"."grade", "qb"."chapter_number";


