);


COMMENT ON TABLE "public"."cbse_syllabus" IS 'Layer 2 SSoT. One row per (board, grade, subject_code, chapter_number). rag_status derived from chunk_count + verified_question_count. See docs/superpowers/specs/2026-04-17-rag-grounding-integrity-design.md §5.1';


