    "created_at" timestamp with time zone DEFAULT "now"()
);


CREATE TABLE IF NOT EXISTS "public"."domain_events" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "event_type" "text" NOT NULL,
    "aggregate_type" "text" NOT NULL,
    "aggregate_id" "uuid",
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "retry_count" integer DEFAULT 0 NOT NULL,
    "last_error" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "processed_at" timestamp with time zone,
    CONSTRAINT "domain_events_event_type_format" CHECK (("event_type" ~ '^[a-z_]+\.[a-z_]+$'::"text")),
    CONSTRAINT "domain_events_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'processing'::"text", 'processed'::"text", 'failed'::"text", 'dead_letter'::"text"])))
);


COMMENT ON TABLE "public"."domain_events" IS 'Outbox table for cross-context domain events. Producers insert via enqueue_event RPC inside the source transaction; a polling worker dispatches to consumers. See docs/architecture/EVENT_CATALOG.md.';


COMMENT ON COLUMN "public"."domain_events"."event_type" IS 'Dotted lower_snake event name, e.g. quiz.completed (matches ^[a-z_]+\.[a-z_]+$).';


COMMENT ON COLUMN "public"."domain_events"."aggregate_type" IS 'The bounded-context aggregate this event belongs to (e.g. quiz_session, content_request).';


COMMENT ON COLUMN "public"."domain_events"."aggregate_id" IS 'Optional aggregate primary key; null for events not tied to a single row.';


COMMENT ON COLUMN "public"."domain_events"."status" IS 'Lifecycle: pending -> processing -> processed | failed -> dead_letter (after max retries).';


