);


COMMENT ON COLUMN "public"."students"."is_demo" IS 'Marks demo/test accounts to exclude from analytics';


CREATE OR REPLACE VIEW "public"."ingestion_gaps" AS
 SELECT "board",
    "grade",
    "subject_code",
    "subject_display",
    "chapter_number",
    "chapter_title",
    "rag_status",
    "chunk_count",
    "verified_question_count",
    "last_verified_at",
        CASE
            WHEN ("rag_status" = 'missing'::"text") THEN 'critical'::"text"
            WHEN (("rag_status" = 'partial'::"text") AND ("chunk_count" < 10)) THEN 'high'::"text"
            WHEN ("rag_status" = 'partial'::"text") THEN 'medium'::"text"
            ELSE NULL::"text"
        END AS "severity",
    ( SELECT "count"(*) AS "count"
           FROM "public"."students"
          WHERE (("students"."grade" = "s"."grade") AND ("students"."account_status" = 'active'::"text"))) AS "potential_affected_students",
    ( SELECT "count"(*) AS "count"
           FROM "public"."content_requests" "cr"
          WHERE (("cr"."grade" = "s"."grade") AND ("cr"."subject_code" = "s"."subject_code") AND ("cr"."chapter_number" = "s"."chapter_number"))) AS "request_count"
   FROM "public"."cbse_syllabus" "s"
  WHERE (("is_in_scope" = true) AND ("rag_status" <> 'ready'::"text"));


