CREATE TABLE IF NOT EXISTS "public"."learning_objectives" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "chapter_id" "uuid" NOT NULL,
    "code" "text" NOT NULL,
    "statement" "text" NOT NULL,
    "statement_hi" "text",
    "bloom_level" smallint NOT NULL,
    "prereq_objective_ids" "uuid"[] DEFAULT '{}'::"uuid"[] NOT NULL,
    "skill_tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "bkt_p_learn" numeric(4,3) DEFAULT 0.20 NOT NULL,
    "bkt_p_slip" numeric(4,3) DEFAULT 0.10 NOT NULL,
    "bkt_p_guess" numeric(4,3) DEFAULT 0.25 NOT NULL,
    "bkt_calibrated_at" timestamp with time zone,
    "bkt_sample_n" integer DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "learning_objectives_bloom_level_check" CHECK ((("bloom_level" >= 1) AND ("bloom_level" <= 6)))
);


COMMENT ON TABLE "public"."learning_objectives" IS 'Fine-grained CBSE learning objectives per chapter. Drives BKT priors, RAG retrieval grounding, and adaptive selection. Phase 3 of Foxy moat plan.';


COMMENT ON COLUMN "public"."learning_objectives"."code" IS 'Stable human-readable code, e.g. "PHY-7-MOTION-LO-01". Used as join key across content pipeline.';


COMMENT ON COLUMN "public"."learning_objectives"."bkt_p_learn" IS 'BKT P(T) — probability of transitioning from unknown to known on a practice opportunity. Default 0.20 (Pardos & Heffernan 2010 high-guess MCQ band); recalibrated nightly when bkt_sample_n >= 200.';


COMMENT ON COLUMN "public"."learning_objectives"."bkt_p_slip" IS 'BKT P(slip) — probability student knows the skill but answers wrong. Default 0.10 per Corbett & Anderson (1995); recalibrated.';


COMMENT ON COLUMN "public"."learning_objectives"."bkt_p_guess" IS 'BKT P(guess) — probability student does not know but answers right. Default 0.25 (4-option MCQ chance floor); recalibrated.';


COMMENT ON COLUMN "public"."learning_objectives"."bkt_calibrated_at" IS 'Set by nightly calibration job (Phase 4) when bkt_sample_n >= 30 across student responses tied to this LO.';


