COMMENT ON COLUMN "public"."quiz_responses"."rubric_feedback" IS 'AI-generated CBSE rubric feedback for written answers. NULL for MCQ.';


CREATE OR REPLACE VIEW "public"."misconception_candidates" AS
 WITH "per_qd" AS (
         SELECT "qr"."question_id",
            "qr"."student_answer_index" AS "distractor_index",
            "count"(*) AS "times_picked",
            "count"(*) FILTER (WHERE ("qr"."is_correct" = false)) AS "times_wrong"
           FROM "public"."quiz_responses" "qr"
          WHERE (("qr"."student_answer_index" IS NOT NULL) AND (("qr"."student_answer_index" >= 0) AND ("qr"."student_answer_index" <= 3)))
          GROUP BY "qr"."question_id", "qr"."student_answer_index"
        ), "totals" AS (
         SELECT "per_qd"."question_id",
            "sum"("per_qd"."times_picked") AS "total_responses"
           FROM "per_qd"
          GROUP BY "per_qd"."question_id"
        )
 SELECT "pq"."question_id",
    "pq"."distractor_index",
    "pq"."times_picked",
    "pq"."times_wrong",
    "t"."total_responses",
    "round"((("pq"."times_wrong")::numeric / NULLIF("t"."total_responses", (0)::numeric)), 4) AS "wrong_rate",
    "qb"."question_text",
    "qb"."options",
    "qb"."correct_answer_index",
    "qb"."subject",
    "qb"."grade",
    "qb"."chapter_number",
    (EXISTS ( SELECT 1
           FROM "public"."question_misconceptions" "qm"
          WHERE (("qm"."question_id" = "pq"."question_id") AND ("qm"."distractor_index" = "pq"."distractor_index")))) AS "has_curated_misconception"
   FROM (("per_qd" "pq"
     JOIN "totals" "t" ON (("t"."question_id" = "pq"."question_id")))
     JOIN "public"."question_bank" "qb" ON (("qb"."id" = "pq"."question_id")))
  WHERE (("qb"."is_active" = true) AND ("pq"."distractor_index" <> "qb"."correct_answer_index") AND ("t"."total_responses" >= (10)::numeric) AND ("pq"."times_wrong" >= 3) AND ((("pq"."times_wrong")::numeric / NULLIF("t"."total_responses", (0)::numeric)) >= 0.10));


COMMENT ON VIEW "public"."misconception_candidates" IS 'Phase 3 editorial input. Surfaces (question_id, distractor_index) pairs where the distractor is picked by >=10% of responders to a question with >=10 total responses. Editors curate question_misconceptions rows by sorting wrong_rate DESC and writing a misconception_code + label. has_curated_misconception flags pairs already done so editors can skip them.';


