CREATE TABLE IF NOT EXISTS "public"."quiz_session_shuffles" (
    "session_id" "uuid" NOT NULL,
    "question_id" "uuid" NOT NULL,
    "shuffle_map" integer[] NOT NULL,
    "options_snapshot" "jsonb" NOT NULL,
    "correct_answer_index_snapshot" integer NOT NULL,
    "student_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "quiz_session_shuffles_correct_idx_range" CHECK ((("correct_answer_index_snapshot" >= 0) AND ("correct_answer_index_snapshot" <= 3))),
    CONSTRAINT "quiz_session_shuffles_map_len4" CHECK (("array_length"("shuffle_map", 1) = 4))
);


COMMENT ON TABLE "public"."quiz_session_shuffles" IS 'Server-owned per-question shuffle snapshot for quiz sessions started via start_quiz_session(). Closes the P1+P6 drift bug where a client-derived stable shuffle could mismatch a later question_bank content edit. submit_quiz_results_v2 reads from here, NEVER from the live question_bank, when re-deriving is_correct. See migration 20260428160000 for full threat model.';


COMMENT ON COLUMN "public"."quiz_session_shuffles"."shuffle_map" IS '4-element permutation. shuffle_map[displayed_index] = original_index in options_snapshot. Mirror semantics of resolveOriginalIndex() in src/lib/quiz-scoring.ts and the v1 submit_quiz_results algorithm.';


COMMENT ON COLUMN "public"."quiz_session_shuffles"."options_snapshot" IS 'JSONB array snapshot of question_bank.options at quiz session start. Mid-session edits to question_bank.options DO NOT affect this row.';


COMMENT ON COLUMN "public"."quiz_session_shuffles"."correct_answer_index_snapshot" IS 'Integer 0..3 snapshot of question_bank.correct_answer_index at quiz session start. submit_quiz_results_v2 compares against THIS, not the live question_bank value.';


