CREATE OR REPLACE VIEW "public"."rag_chapter_coverage" AS
 SELECT "grade",
    "subject",
    "chapter_number",
    "chapter_title",
    "count"(*) AS "chunk_count",
    "round"(("avg"("quality_score"))::numeric, 3) AS "avg_quality",
    "max"("embedded_at") AS "last_embedded_at",
    "sum"(
        CASE
            WHEN ("embedding" IS NULL) THEN 1
            ELSE 0
        END) AS "missing_embeddings",
    (("count"(*) >= 3) AND ("sum"(
        CASE
            WHEN ("embedding" IS NULL) THEN 1
            ELSE 0
        END) = 0) AND ("avg"("quality_score") >= (0.5)::double precision)) AS "is_grounded"
   FROM "public"."rag_content_chunks" "rc"
  WHERE (("is_active" = true) AND ("grade" IS NOT NULL) AND ("subject" IS NOT NULL) AND ("chapter_number" IS NOT NULL))
  GROUP BY "grade", "subject", "chapter_number", "chapter_title";


