CREATE TABLE IF NOT EXISTS "public"."student_skill_state" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "student_id" "uuid" NOT NULL,
    "learning_objective_id" "uuid" NOT NULL,
    "p_know" numeric(5,4) DEFAULT 0.10 NOT NULL,
    "p_learn" numeric(4,3) DEFAULT 0.20 NOT NULL,
    "p_slip" numeric(4,3) DEFAULT 0.10 NOT NULL,
    "p_guess" numeric(4,3) DEFAULT 0.25 NOT NULL,
    "theta" numeric(5,3) DEFAULT 0 NOT NULL,
    "theta_se" numeric(5,3) DEFAULT 1.5 NOT NULL,
    "last_n_responses" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "total_attempts" integer DEFAULT 0 NOT NULL,
    "total_correct" integer DEFAULT 0 NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL
);


COMMENT ON TABLE "public"."student_skill_state" IS 'Per-student, per-LO BKT/IRT state. last_n_responses is a ring buffer of the most recent 20 responses (oldest dropped on the application side). Phase 3 of Foxy moat plan.';


COMMENT ON COLUMN "public"."student_skill_state"."p_know" IS 'BKT prior P(L0) — probability student knows the skill before any practice. Cold-start 0.10 per Corbett & Anderson (1995); calibrated per-skill in Phase 4.';


COMMENT ON COLUMN "public"."student_skill_state"."theta" IS 'IRT theta (ability) on N(0,1) scale. Bounded [-4, 4] in update functions. Cold-start 0.';


COMMENT ON COLUMN "public"."student_skill_state"."theta_se" IS 'IRT ability standard error. Cold-start default 1.5 per Wainer (2000) and van der Linden (2010); tighter values commit early and starve item-information gain. Calibration job updates this from response data.';


