CREATE OR REPLACE VIEW "public"."super_admin_subject_readiness" AS
 SELECT "code" AS "subject_code",
    "name" AS "subject_name",
    "subject_kind",
    "is_active",
    "is_content_ready",
    ( SELECT "count"(*) AS "count"
           FROM "public"."chapters" "c"
          WHERE (("c"."subject_id" = "s"."id") AND "c"."is_active")) AS "active_chapters",
    ( SELECT "count"(*) AS "count"
           FROM "public"."question_bank" "q"
          WHERE ("q"."subject" = "s"."code")) AS "questions",
    ( SELECT "count"(*) AS "count"
           FROM "public"."chapter_concepts" "cc"
          WHERE (("cc"."subject" = "s"."code") AND "cc"."is_active")) AS "active_concepts",
    ( SELECT "count"(*) AS "count"
           FROM "public"."rag_content_chunks" "rc"
          WHERE (("rc"."subject_code" = "s"."code") AND "rc"."is_active" AND ("rc"."source" = 'ncert_2025'::"text"))) AS "ncert_chunks",
    ( SELECT "array_agg"(DISTINCT "psa"."plan_code" ORDER BY "psa"."plan_code") AS "array_agg"
           FROM "public"."plan_subject_access" "psa"
          WHERE ("psa"."subject_code" = "s"."code")) AS "plans_granting_access",
        CASE
            WHEN ((NOT "is_content_ready") AND (EXISTS ( SELECT 1
               FROM "public"."plan_subject_access" "psa"
              WHERE ("psa"."subject_code" = "s"."code")))) THEN 'GATED — plan grants access but content missing'::"text"
            WHEN "is_content_ready" THEN 'OK'::"text"
            ELSE 'inactive'::"text"
        END AS "readiness_state"
   FROM "public"."subjects" "s"
  WHERE "is_active"
  ORDER BY "is_content_ready", "code";


COMMENT ON VIEW "public"."super_admin_subject_readiness" IS 'Per-subject content readiness signals. Triages why a subject is hidden from students.';


