CREATE OR REPLACE VIEW "public"."v_ops_timeline" AS
 SELECT "ops_events"."id",
    "ops_events"."occurred_at",
    "ops_events"."category",
    "ops_events"."source",
    "ops_events"."severity",
    "ops_events"."subject_type",
    "ops_events"."subject_id",
    "ops_events"."message",
    "ops_events"."context",
    "ops_events"."request_id",
    "ops_events"."environment"
   FROM "public"."ops_events"
UNION ALL
 SELECT "admin_audit_log"."id",
    "admin_audit_log"."created_at" AS "occurred_at",
    'admin_action'::"text" AS "category",
    COALESCE(("admin_audit_log"."details" ->> 'admin_email'::"text"), 'unknown'::"text") AS "source",
    'info'::"text" AS "severity",
    "admin_audit_log"."entity_type" AS "subject_type",
    "admin_audit_log"."entity_id" AS "subject_id",
    "admin_audit_log"."action" AS "message",
    COALESCE("admin_audit_log"."details", '{}'::"jsonb") AS "context",
    NULL::"text" AS "request_id",
    'production'::"text" AS "environment"
   FROM "public"."admin_audit_log";


COMMENT ON VIEW "public"."v_ops_timeline" IS 'Unified timeline across ops_events and admin_audit_log.';


