CREATE POLICY "Admin read alert_rules" ON "public"."legacy_alert_rules" FOR SELECT TO "authenticated" USING ((EXISTS ( SELECT 1
   FROM ("public"."user_roles" "ur"
     JOIN "public"."roles" "r" ON (("r"."id" = "ur"."role_id")))
  WHERE (("ur"."auth_user_id" = ( SELECT "auth"."uid"() AS "uid")) AND ("r"."name" = 'admin'::"text") AND ("ur"."is_active" = true)))));


CREATE POLICY "Admin read health snapshots" ON "public"."platform_health_snapshots" FOR SELECT TO "authenticated" USING ((EXISTS ( SELECT 1
   FROM ("public"."user_roles" "ur"
     JOIN "public"."roles" "r" ON (("r"."id" = "ur"."role_id")))
  WHERE (("ur"."auth_user_id" = ( SELECT "auth"."uid"() AS "uid")) AND ("r"."name" = 'admin'::"text") AND ("ur"."is_active" = true)))));


